import type {
  PieBridge,
  RuntimeHostBridge,
  RuntimeHostCapabilityDescriptor,
  RuntimeHostRegistration,
} from "./pie-bridge.js";

type RuntimeHostHandler = (args?: unknown) => unknown;

type RuntimeHostRecord = {
  namespace: string;
  displayName: string;
  capabilities: RuntimeHostCapabilityDescriptor[];
  handlers: Map<string, RuntimeHostHandler>;
};

type RuntimeHostBridgeGlobal = typeof globalThis & {
  __pieRuntimeHostBridge?: {
    invokeCapability(name: string, argsJson: string): string;
    hasRegisteredHostBridge(): boolean;
  };
};

function assertString(value: unknown, label: string): string {
  const text = String(value ?? "").trim();
  if (!text) {
    throw new Error(`${label} is required.`);
  }
  return text;
}

function toDescriptor(namespace: string, displayName: string, capability: RuntimeHostRegistration["capabilities"][number]): RuntimeHostCapabilityDescriptor {
  const kind = String(capability?.kind || "").trim().toLowerCase();
  if (kind !== "tool" && kind !== "rpc") {
    throw new Error(`Runtime host capability kind must be tool or rpc: ${capability?.name || "(unnamed)"}`);
  }

  return {
    kind,
    name: assertString(capability?.name, "capability name"),
    namespace: assertString(capability?.namespace || namespace, "capability namespace"),
    description: assertString(capability?.description, "capability description"),
    parameters: Array.isArray(capability?.parameters) ? capability.parameters : [],
    mode: String(capability?.mode || "runtime"),
    readOnly: capability?.readOnly === true,
    requiresMainThread: capability?.requiresMainThread !== false,
    owner: String(capability?.owner || displayName || namespace),
    writeScope: String(capability?.writeScope || ""),
    returns: String(capability?.returns || ""),
    recommendedWorkflow: String(capability?.recommendedWorkflow || ""),
    examples: Array.isArray(capability?.examples) ? capability.examples.map((item) => String(item || "")) : [],
    errorCodes: Array.isArray(capability?.errorCodes) ? capability.errorCodes.map((item) => String(item || "")) : [],
    destructive: capability?.destructive === true,
    canTriggerDomainReload: capability?.canTriggerDomainReload === true,
  };
}

function parseArgsJson(argsJson: string): unknown {
  if (!argsJson) return {};
  try {
    return JSON.parse(String(argsJson));
  } catch {
    return {};
  }
}

export function installRuntimeHostBridge(bridge: PieBridge): void {
  const hosts = new Map<string, RuntimeHostRecord>();
  const capabilityIndex = new Map<string, { descriptor: RuntimeHostCapabilityDescriptor; handler: RuntimeHostHandler }>();

  function removeLocalHost(namespace: string): void {
    const normalized = String(namespace || "").trim();
    if (!normalized) return;
    hosts.delete(normalized);
    for (const [name, entry] of capabilityIndex.entries()) {
      if (String(entry.descriptor.namespace || "") === normalized) {
        capabilityIndex.delete(name);
      }
    }
  }

  function unregisterHost(namespace: string): void {
    const normalized = String(namespace || "").trim();
    if (!normalized) return;
    removeLocalHost(normalized);
    bridge.callHost?.("pie.host_bridge", {
      action: "unregister_host",
      hostNamespace: normalized,
    });
  }

  function registerHost(host: RuntimeHostRegistration): { namespace: string; capabilityCount: number } {
    const namespace = assertString(host?.namespace, "host namespace");
    const displayName = String(host?.displayName || namespace);
    const capabilities = Array.isArray(host?.capabilities) ? host.capabilities : [];
    if (capabilities.length === 0) {
      throw new Error(`Runtime host ${namespace} registered no capabilities.`);
    }

    const descriptors = capabilities.map((capability) => toDescriptor(namespace, displayName, capability));
    const handlers = new Map<string, RuntimeHostHandler>();
    for (let index = 0; index < descriptors.length; index += 1) {
      const descriptor = descriptors[index];
      const execute = capabilities[index]?.execute;
      if (typeof execute !== "function") {
        throw new Error(`Runtime host capability ${descriptor.name} must provide execute(args).`);
      }
      handlers.set(descriptor.name, execute);
    }

    removeLocalHost(namespace);

    bridge.callHost?.("pie.host_bridge", {
      action: "register_host",
      hostNamespace: namespace,
      hostDisplayName: displayName,
      capabilities: descriptors.map((descriptor) => ({
        kind: descriptor.kind,
        name: descriptor.name,
        namespace: descriptor.namespace,
        description: descriptor.description,
        mode: descriptor.mode,
        readOnly: descriptor.readOnly === true,
        requiresMainThread: descriptor.requiresMainThread !== false,
        owner: descriptor.owner || "",
        writeScope: descriptor.writeScope || "",
        returns: descriptor.returns || "",
        recommendedWorkflow: descriptor.recommendedWorkflow || "",
        examples: descriptor.examples || [],
        errorCodes: descriptor.errorCodes || [],
        destructive: descriptor.destructive === true,
        canTriggerDomainReload: descriptor.canTriggerDomainReload === true,
        parameters: descriptor.parameters || [],
      })),
    });

    const record: RuntimeHostRecord = {
      namespace,
      displayName,
      capabilities: descriptors,
      handlers,
    };
    hosts.set(namespace, record);
    for (const descriptor of descriptors) {
      capabilityIndex.set(descriptor.name, {
        descriptor,
        handler: handlers.get(descriptor.name)!,
      });
    }

    return {
      namespace,
      capabilityCount: descriptors.length,
    };
  }

  function resolveCapabilityName(fullNameOrNamespace: string, nameOrArgs?: string | unknown): string {
    const first = String(fullNameOrNamespace || "").trim();
    if (!first) {
      throw new Error("Runtime host capability name is required.");
    }

    if (typeof nameOrArgs !== "string") {
      return first;
    }

    const second = String(nameOrArgs || "").trim();
    if (!second) {
      throw new Error("Runtime host capability name is required.");
    }
    if (capabilityIndex.has(second)) {
      return second;
    }
    const inferred = `${first}_${second}`;
    if (capabilityIndex.has(inferred)) {
      return inferred;
    }
    return second;
  }

  function callCapability(fullNameOrNamespace: string, nameOrArgs?: string | unknown, maybeArgs?: unknown): unknown {
    if (!bridge.devRpc?.call) {
      throw new Error("pieBridge.devRpc is not available.");
    }
    const name = resolveCapabilityName(fullNameOrNamespace, nameOrArgs);
    const args = typeof nameOrArgs === "string" ? (maybeArgs ?? {}) : (nameOrArgs ?? {});
    return bridge.devRpc.call(name, args);
  }

  bridge.host = {
    registerHost,
    unregisterHost,
    call: callCapability,
    hasCapability(name: string): boolean {
      return capabilityIndex.has(String(name || "").trim());
    },
    listCapabilities(namespace?: string): RuntimeHostCapabilityDescriptor[] {
      const normalized = String(namespace || "").trim();
      const items = Array.from(capabilityIndex.values()).map((entry) => entry.descriptor);
      return normalized
        ? items.filter((descriptor) => String(descriptor.namespace || "") === normalized)
        : items;
    },
  } satisfies RuntimeHostBridge;

  (globalThis as RuntimeHostBridgeGlobal).__pieRuntimeHostBridge = {
    invokeCapability(name: string, argsJson: string): string {
      const entry = capabilityIndex.get(String(name || "").trim());
      if (!entry) {
        throw new Error(`Runtime host capability not found: ${name}`);
      }
      const result = entry.handler(parseArgsJson(argsJson));
      if (result && typeof (result as Promise<unknown>).then === "function") {
        throw new Error(`Runtime host capability ${name} must return synchronously.`);
      }
      return JSON.stringify(result ?? null);
    },
    hasRegisteredHostBridge(): boolean {
      return !!bridge.host;
    },
  };
}
