import { Agent, type AgentTool } from "@pie/agent-core";
import { createSubagentCapability, type SharedSkill } from "@pie/shared-headless-capabilities";
import type { Api, Model } from "@pie/ai";
import type { UnitySessionTraceWriter } from "./session-trace.js";

export interface UnitySubagentToolOptions {
	projectRoot: string;
	getActiveModel(): Model<Api>;
	getActiveApiKey(): string | undefined;
	getSkills(): SharedSkill[];
	getRuntimeTools(): AgentTool[];
	getParentTools(): AgentTool[];
	trace: UnitySessionTraceWriter;
}

export function createUnitySubagentTool(options: UnitySubagentToolOptions): AgentTool {
	const capability = createSubagentCapability({
		get apiKey() {
			return options.getActiveApiKey();
		},
		get model() {
			return options.getActiveModel();
		},
		skills: options.getSkills(),
		yoloMode: false,
		getParentTools: () => options.getParentTools().map((tool) => ({
			name: tool.name,
			description: tool.description,
			parameters: tool.parameters,
		})),
		createRuntimeTools: () => options.getRuntimeTools().filter((tool) => tool.name !== "spawn_subagents_parallel"),
		createAgent: ({ systemPrompt, model, tools, apiKey }) => new Agent({
			initialState: {
				systemPrompt,
				model,
				tools,
				thinkingLevel: "off",
			},
			apiKey,
		}),
		log: (message) => options.trace.noteRuntimeEvent("subagent_log", { message }),
		debugLog: (module, message, data) => options.trace.noteRuntimeEvent("subagent_debug", { module, message, data }),
	});
	return capability.tools[0] as AgentTool;
}

