/**
 * Tool argument validation using TypeBox runtime checks.
 */

import { Value } from "@sinclair/typebox/value";
import type { Tool, ToolCall } from "../types.js";

export function validateToolCall(tools: Tool[], toolCall: ToolCall): any {
	const tool = tools.find((t) => t.name === toolCall.name);
	if (!tool) {
		throw new Error(`Tool "${toolCall.name}" not found`);
	}
	return validateToolArguments(tool, toolCall);
}

export function validateToolArguments(tool: Tool, toolCall: ToolCall): any {
	const args = toolCall.arguments ?? {};

	if (Value.Check(tool.parameters, args)) {
		return args;
	}

	const firstError = Array.from(Value.Errors(tool.parameters, args))[0];
	if (!firstError) {
		throw new Error(`Invalid arguments for tool "${tool.name}"`);
	}

	const path = firstError.path || "/";
	throw new Error(`Invalid arguments for tool "${tool.name}" at ${path}: ${firstError.message}`);
}
