import { FileSystemGateway } from "@pie/platform";

export type DurableFileRole = "main" | "backup" | "previous";

export interface DurableFileParsed<T> {
	data: T;
	content: string;
	updatedAt: number;
}

export interface DurableFileCandidate<T> extends DurableFileParsed<T> {
	role: DurableFileRole;
	path: string;
	rawContent: string;
}

export interface DurableFileOptions<T> {
	gateway: FileSystemGateway;
	filePath: string;
	parse: (content: string, path: string) => DurableFileParsed<T>;
	retryDelaysMs?: number[];
}

export interface DurableFileLoadResult<T> {
	data: T;
	content: string;
	source: DurableFileRole;
	restoredMain: boolean;
	refreshedBackup: boolean;
	repairError?: unknown;
}

export interface DurableFilePaths {
	main: string;
	backup: string;
	previous: string;
}

const DEFAULT_FILE_RETRY_DELAYS_MS = [0, 25, 75, 150];

export function durableFilePaths(filePath: string): DurableFilePaths {
	return {
		main: filePath,
		backup: `${filePath}.bak`,
		previous: `${filePath}.prev`,
	};
}

export function isTransientFileError(error: unknown): boolean {
	const code = typeof error === "object" && error && "code" in error ? String((error as { code?: unknown }).code) : "";
	const message = error instanceof Error ? error.message : String(error);
	return /^(EPERM|EACCES|EBUSY|ENOTEMPTY)$/.test(code) || /\b(EPERM|EACCES|EBUSY|locked|busy)\b/i.test(message);
}

function sleep(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

async function retryFileOperation(operation: () => void, retryDelaysMs: readonly number[]): Promise<void> {
	let lastError: unknown;
	for (const [index, delayMs] of retryDelaysMs.entries()) {
		if (delayMs > 0) {
			await sleep(delayMs);
		}
		try {
			operation();
			return;
		} catch (error) {
			lastError = error;
			if (!isTransientFileError(error) || index === retryDelaysMs.length - 1) {
				throw error;
			}
		}
	}
	throw lastError;
}

function retryDelays<T>(options: DurableFileOptions<T>): readonly number[] {
	return options.retryDelaysMs ?? DEFAULT_FILE_RETRY_DELAYS_MS;
}

function tempPathFor(filePath: string, operation: string): string {
	return `${filePath}.${operation}.${Date.now()}.${Math.random().toString(36).slice(2)}.tmp`;
}

async function replaceFile(gateway: FileSystemGateway, filePath: string, content: string, retryDelaysMs: readonly number[]): Promise<void> {
	const tempPath = tempPathFor(filePath, "durable");
	gateway.writeFile(tempPath, content, "utf-8");
	try {
		try {
			await retryFileOperation(() => gateway.renameFile(tempPath, filePath), retryDelaysMs);
		} catch {
			await retryFileOperation(() => gateway.copyFile(tempPath, filePath), retryDelaysMs);
			try { gateway.deleteFile(tempPath); } catch {}
		}
	} catch (error) {
		try { gateway.deleteFile(tempPath); } catch {}
		throw error;
	}
}

async function copyExistingFile(gateway: FileSystemGateway, sourcePath: string, destinationPath: string, retryDelaysMs: readonly number[]): Promise<boolean> {
	if (!gateway.exists(sourcePath)) {
		return false;
	}
	await retryFileOperation(() => gateway.copyFile(sourcePath, destinationPath), retryDelaysMs);
	return true;
}

function readCandidate<T>(
	options: DurableFileOptions<T>,
	role: DurableFileRole,
	path: string,
): DurableFileCandidate<T> | null {
	if (!options.gateway.exists(path)) {
		return null;
	}
	const rawContent = options.gateway.readFile(path, "utf-8");
	const parsed = options.parse(rawContent, path);
	const updatedAt = Number.isFinite(parsed.updatedAt) ? parsed.updatedAt : 0;
	return {
		...parsed,
		updatedAt,
		role,
		path,
		rawContent,
	};
}

function candidatePriority(role: DurableFileRole): number {
	if (role === "main") return 3;
	if (role === "backup") return 2;
	return 1;
}

function chooseBestCandidate<T>(candidates: DurableFileCandidate<T>[]): DurableFileCandidate<T> {
	return [...candidates].sort((a, b) => {
		const updatedAtDiff = b.updatedAt - a.updatedAt;
		if (updatedAtDiff !== 0) return updatedAtDiff;
		return candidatePriority(b.role) - candidatePriority(a.role);
	})[0];
}

export async function writeDurableFile<T>(options: DurableFileOptions<T>, content: string): Promise<void> {
	const parsed = options.parse(content, options.filePath);
	const durableContent = parsed.content;
	const paths = durableFilePaths(options.filePath);
	const delays = retryDelays(options);

	if (options.gateway.exists(paths.backup)) {
		await copyExistingFile(options.gateway, paths.backup, paths.previous, delays);
	}

	await replaceFile(options.gateway, paths.backup, durableContent, delays);
	await replaceFile(options.gateway, paths.main, durableContent, delays);
}

export async function loadDurableFile<T>(options: DurableFileOptions<T>): Promise<DurableFileLoadResult<T> | null> {
	const paths = durableFilePaths(options.filePath);
	const roles: Array<[DurableFileRole, string]> = [
		["main", paths.main],
		["backup", paths.backup],
		["previous", paths.previous],
	];
	const candidates: DurableFileCandidate<T>[] = [];

	for (const [role, path] of roles) {
		try {
			const candidate = readCandidate(options, role, path);
			if (candidate) {
				candidates.push(candidate);
			}
		} catch {
			// Invalid sidecars are ignored so a good candidate can repair them.
		}
	}

	if (candidates.length === 0) {
		return null;
	}

	const best = chooseBestCandidate(candidates);
	const main = candidates.find((candidate) => candidate.role === "main");
	const backup = candidates.find((candidate) => candidate.role === "backup");
	const needsMainRestore = !main || main.rawContent !== best.content;
	const needsBackupRefresh = !backup || backup.rawContent !== best.content;
	let restoredMain = false;
	let refreshedBackup = false;
	let repairError: unknown;
	const delays = retryDelays(options);

	try {
		if (needsBackupRefresh) {
			if (backup && backup.rawContent !== best.content) {
				await replaceFile(options.gateway, paths.previous, backup.content, delays);
			}
			await replaceFile(options.gateway, paths.backup, best.content, delays);
			refreshedBackup = true;
		}
		if (needsMainRestore) {
			await replaceFile(options.gateway, paths.main, best.content, delays);
			restoredMain = true;
		}
	} catch (error) {
		repairError = error;
	}

	return {
		data: best.data,
		content: best.content,
		source: best.role,
		restoredMain,
		refreshedBackup,
		repairError,
	};
}

export function durableFileExists(gateway: FileSystemGateway, filePath: string): boolean {
	const paths = durableFilePaths(filePath);
	return gateway.exists(paths.main) || gateway.exists(paths.backup) || gateway.exists(paths.previous);
}

export function deleteDurableFile(gateway: FileSystemGateway, filePath: string): boolean {
	const paths = durableFilePaths(filePath);
	let deleted = false;
	for (const path of [paths.main, paths.backup, paths.previous]) {
		if (gateway.exists(path)) {
			gateway.deleteFile(path);
			deleted = true;
		}
	}
	return deleted;
}
