/**
 * FileSystem Gateway
 * Unified file system operations with sandbox safety
 *
 * All file operations go through this gateway, ensuring:
 * 1. All paths are restricted to allowed directories (sandbox)
 * 2. Path traversal attacks are prevented
 * 3. Platform-specific paths are handled correctly
 */

import { getPlatformConfig, PlatformConfig } from "./config.js";
import { detectPlatform } from "./detector.js";
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";

// Create require function for ESM compatibility
// @ts-ignore - import.meta.url is available in ESM
const __filename = fileURLToPath(import.meta.url);
const nodeRequire = createRequire(__filename);

/** Global CS namespace for PuerTS Unity interop */
declare const CS: any;

/**
 * FileSystem Gateway options
 */
export interface FileSystemGatewayOptions {
  /** Allowed root directories (default: dataPath from config) */
  allowedRoots?: string[];
  /** Whether to allow writes (default: true) */
  allowWrites?: boolean;
}

/**
 * FileSystem Gateway
 * Provides safe, unified file system operations
 */
export class FileSystemGateway {
  private config: PlatformConfig;
  private allowedRoots: string[];
  private allowWrites: boolean;
  private sep: string;

  constructor(options: FileSystemGatewayOptions = {}) {
    this.config = getPlatformConfig();
    this.sep = this.config.sep;

    // Default allowed roots to dataPath
    this.allowedRoots = options.allowedRoots || [this.config.dataPath];
    this.allowWrites = options.allowWrites !== false;
  }

  /**
   * Check if a path is within allowed roots
   */
  private isPathAllowed(path: string): boolean {
    const normalized = this.normalizePath(path);
    for (const root of this.allowedRoots) {
      const normalizedRoot = this.normalizePath(root);
      if (normalized === normalizedRoot || normalized.startsWith(this.withTrailingSep(normalizedRoot))) {
        return true;
      }
    }
    return false;
  }

  /**
   * Normalize path for comparison
   */
  private normalizePath(path: string): string {
    const normalized = path.replace(/\\/g, "/").replace(/\/+/g, "/");
    if (normalized === "/") return normalized;
    return normalized.replace(/\/+$/, "").toLowerCase();
  }

  /**
   * Normalize root path for prefix comparison
   */
  private withTrailingSep(path: string): string {
    return path.endsWith("/") ? path : `${path}/`;
  }

  /**
   * Detect actual path traversal segments without rejecting normal file names like a..b.txt
   */
  private hasTraversalSegment(path: string): boolean {
    return path.replace(/\\/g, "/").split("/").some((segment) => segment === "..");
  }

  /**
   * Validate path for security
   * Throws error if path is not allowed
   */
  private validatePath(path: string, operation: string): void {
    // Check for path traversal
    if (this.hasTraversalSegment(path)) {
      throw new Error(`Path traversal detected: ${path}`);
    }

    // Check if path is allowed
    if (!this.isPathAllowed(path)) {
      throw new Error(`Access denied: ${operation} not allowed on ${path}`);
    }
  }

  /**
   * Join path segments
   */
  join(...parts: string[]): string {
    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      let result = parts[0] || "";
      for (let i = 1; i < parts.length; i++) {
        result = CS.System.IO.Path.Combine(result, parts[i]);
      }
      return result;
    }

    // Node.js: use path module
    const path = nodeRequire("path");
    return path.join(...parts);
  }

  /**
   * Get directory name from path
   */
  dirname(path: string): string {
    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      return CS.System.IO.Path.GetDirectoryName(path) || "";
    }

    // Node.js: use path module
    const p = nodeRequire("path");
    return p.dirname(path);
  }

  /**
   * Get file name from path
   */
  basename(path: string, ext?: string): string {
    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      let name = CS.System.IO.Path.GetFileName(path) || "";
      if (ext && name.endsWith(ext)) {
        name = name.slice(0, -ext.length);
      }
      return name;
    }

    // Node.js: use path module
    const p = nodeRequire("path");
    return p.basename(path, ext);
  }

  /**
   * Get file extension
   */
  extname(path: string): string {
    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      return CS.System.IO.Path.GetExtension(path) || "";
    }

    // Node.js: use path module
    const p = nodeRequire("path");
    return p.extname(path);
  }

  /**
   * Check if file exists
   */
  exists(path: string): boolean {
    this.validatePath(path, "exists");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      return CS.System.IO.File.Exists(path) || CS.System.IO.Directory.Exists(path);
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    return fs.existsSync(path);
  }

  /**
   * Read file content
   */
  readFile(path: string, encoding: string = "utf-8"): string {
    this.validatePath(path, "read");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (!CS.System.IO.File.Exists(path)) {
        throw new Error(`File not found: ${path}`);
      }
      return CS.System.IO.File.ReadAllText(path);
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    return fs.readFileSync(path, encoding);
  }

  /**
   * Write file content
   */
  writeFile(path: string, content: string, encoding: string = "utf-8"): void {
    if (!this.allowWrites) {
      throw new Error(`Writes not allowed: ${path}`);
    }
    this.validatePath(path, "write");

    const platform = detectPlatform();

    // Ensure parent directory exists
    const dir = this.dirname(path);
    this.mkdir(dir, { recursive: true });

    if (platform === "puerts" && typeof CS !== "undefined") {
      CS.System.IO.File.WriteAllText(path, content);
      return;
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    fs.writeFileSync(path, content, encoding);
  }

  /**
   * Copy a file.
   */
  copyFile(source: string, destination: string): void {
    if (!this.allowWrites) {
      throw new Error(`Writes not allowed: ${destination}`);
    }
    this.validatePath(source, "copy");
    this.validatePath(destination, "copy");

    const platform = detectPlatform();
    const dir = this.dirname(destination);
    this.mkdir(dir, { recursive: true });

    if (platform === "puerts" && typeof CS !== "undefined") {
      CS.System.IO.File.Copy(source, destination, true);
      return;
    }

    const fs = nodeRequire("fs");
    fs.copyFileSync(source, destination);
  }

  /**
   * Rename or move a file.
   */
  renameFile(source: string, destination: string): void {
    if (!this.allowWrites) {
      throw new Error(`Writes not allowed: ${destination}`);
    }
    this.validatePath(source, "rename");
    this.validatePath(destination, "rename");

    const platform = detectPlatform();
    const dir = this.dirname(destination);
    this.mkdir(dir, { recursive: true });

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (CS.System.IO.File.Exists(destination)) {
        CS.System.IO.File.Delete(destination);
      }
      CS.System.IO.File.Move(source, destination);
      return;
    }

    const fs = nodeRequire("fs");
    fs.renameSync(source, destination);
  }

  /**
   * Delete file
   */
  deleteFile(path: string): void {
    if (!this.allowWrites) {
      throw new Error(`Writes not allowed: ${path}`);
    }
    this.validatePath(path, "delete");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (CS.System.IO.File.Exists(path)) {
        CS.System.IO.File.Delete(path);
      }
      return;
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (fs.existsSync(path)) {
      fs.unlinkSync(path);
    }
  }

  /**
   * Create directory
   */
  mkdir(path: string, options?: { recursive?: boolean }): void {
    if (!this.allowWrites) {
      throw new Error(`Writes not allowed: ${path}`);
    }
    this.validatePath(path, "mkdir");

    const platform = detectPlatform();
    const recursive = options?.recursive ?? true;

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (!CS.System.IO.Directory.Exists(path)) {
        CS.System.IO.Directory.CreateDirectory(path);
      }
      return;
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (!fs.existsSync(path)) {
      fs.mkdirSync(path, { recursive });
    }
  }

  /**
   * List directory contents
   */
  readdir(path: string): string[] {
    this.validatePath(path, "readdir");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (!CS.System.IO.Directory.Exists(path)) {
        return [];
      }
      const files = CS.System.IO.Directory.GetFiles(path);
      const dirs = CS.System.IO.Directory.GetDirectories(path);
      // Convert C# arrays to JS arrays
      const result: string[] = [];
      for (let i = 0; i < files.Length; i++) {
        result.push(this.basename(files[i]));
      }
      for (let i = 0; i < dirs.Length; i++) {
        result.push(this.basename(dirs[i]));
      }
      return result;
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (!fs.existsSync(path)) {
      return [];
    }
    return fs.readdirSync(path);
  }

  /**
   * Check if path is a directory
   */
  isDirectory(path: string): boolean {
    this.validatePath(path, "isDirectory");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      return CS.System.IO.Directory.Exists(path);
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (!fs.existsSync(path)) return false;
    return fs.statSync(path).isDirectory();
  }

  /**
   * Check if path is a file
   */
  isFile(path: string): boolean {
    this.validatePath(path, "isFile");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      return CS.System.IO.File.Exists(path);
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (!fs.existsSync(path)) return false;
    return fs.statSync(path).isFile();
  }

  /**
   * Get file size in bytes
   */
  getFileSize(path: string): number {
    this.validatePath(path, "getFileSize");

    const platform = detectPlatform();

    if (platform === "puerts" && typeof CS !== "undefined") {
      if (!CS.System.IO.File.Exists(path)) return 0;
      const info = CS.System.IO.FileInfo(path);
      return info.Length;
    }

    // Node.js: use fs module
    const fs = nodeRequire("fs");
    if (!fs.existsSync(path)) return 0;
    return fs.statSync(path).size;
  }

  /**
   * Get config
   */
  getConfig(): PlatformConfig {
    return this.config;
  }
}

// Singleton instance
let gatewayInstance: FileSystemGateway | null = null;

/**
 * Get the FileSystemGateway singleton
 */
export function getFileSystemGateway(options?: FileSystemGatewayOptions): FileSystemGateway {
  if (!gatewayInstance) {
    gatewayInstance = new FileSystemGateway(options);
  }
  return gatewayInstance;
}

/**
 * Reset gateway instance (mainly for testing)
 */
export function resetFileSystemGateway(): void {
  gatewayInstance = null;
}
