export type LogLevel = "debug" | "info" | "warn" | "error" | "fatal";

export type RuntimeLogMode =
  | "interactive_tui"
  | "headless_cli"
  | "unity_host"
  | "test";

export interface LogContext {
  module?: string;
  [key: string]: unknown;
}

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  mode: RuntimeLogMode;
  context?: LogContext;
}

export interface LogSink {
  log(entry: LogEntry): void;
}

export interface Logger {
  readonly mode: RuntimeLogMode;
  log(level: LogLevel, message: string, context?: LogContext): void;
  debug(message: string, context?: LogContext): void;
  info(message: string, context?: LogContext): void;
  warn(message: string, context?: LogContext): void;
  error(message: string, context?: LogContext): void;
  fatal(message: string, context?: LogContext): void;
  child(context: LogContext): Logger;
}

const LEVEL_ORDER: Record<LogLevel, number> = {
  debug: 10,
  info: 20,
  warn: 30,
  error: 40,
  fatal: 50,
};

class SinkLogger implements Logger {
  constructor(
    public readonly mode: RuntimeLogMode,
    private readonly sinks: readonly LogSink[],
    private readonly baseContext: LogContext = {},
    private readonly minLevel: LogLevel = "debug",
  ) {}

  log(level: LogLevel, message: string, context: LogContext = {}): void {
    if (LEVEL_ORDER[level] < LEVEL_ORDER[this.minLevel]) {
      return;
    }

    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      mode: this.mode,
      context: { ...this.baseContext, ...context },
    };

    for (const sink of this.sinks) {
      try {
        sink.log(entry);
      } catch {
        // Logging must never break the main flow.
      }
    }
  }

  debug(message: string, context?: LogContext): void {
    this.log("debug", message, context);
  }

  info(message: string, context?: LogContext): void {
    this.log("info", message, context);
  }

  warn(message: string, context?: LogContext): void {
    this.log("warn", message, context);
  }

  error(message: string, context?: LogContext): void {
    this.log("error", message, context);
  }

  fatal(message: string, context?: LogContext): void {
    this.log("fatal", message, context);
  }

  child(context: LogContext): Logger {
    return new SinkLogger(this.mode, this.sinks, { ...this.baseContext, ...context }, this.minLevel);
  }
}

class NullLogger implements Logger {
  constructor(public readonly mode: RuntimeLogMode = "test") {}
  log(): void {}
  debug(): void {}
  info(): void {}
  warn(): void {}
  error(): void {}
  fatal(): void {}
  child(context: LogContext): Logger {
    return new NullLogger(this.mode);
  }
}

export function createLogger(options: {
  mode: RuntimeLogMode;
  sinks?: readonly LogSink[];
  context?: LogContext;
  minLevel?: LogLevel;
}): Logger {
  if (!options.sinks || options.sinks.length === 0) {
    return new NullLogger(options.mode);
  }
  return new SinkLogger(options.mode, options.sinks, options.context, options.minLevel);
}

let globalLogger: Logger = new NullLogger();

export function setLogger(logger: Logger): void {
  globalLogger = logger;
}

export function getLogger(): Logger {
  return globalLogger;
}

export function resetLogger(): void {
  globalLogger = new NullLogger();
}
