import type { Api, Model, ProviderCacheCapability } from "./types.js";

export const NO_CACHE_CAPABILITY: ProviderCacheCapability = {
	mode: "none",
	supported: false,
	supportsUsageMetrics: false,
	description: "This provider route does not expose a supported cache mechanism in Pie.",
};

export const ANTHROPIC_PROMPT_CACHE_CAPABILITY: ProviderCacheCapability = {
	mode: "prompt_cache",
	supported: true,
	supportsUsageMetrics: true,
	description: "Prompt caching is available through Anthropic-compatible cache_control.",
};

export function getModelCacheCapability(model: Model<Api>): ProviderCacheCapability {
	if (model.cacheCapability) {
		return model.cacheCapability;
	}

	if (model.api === "anthropic-messages") {
		return ANTHROPIC_PROMPT_CACHE_CAPABILITY;
	}

	return NO_CACHE_CAPABILITY;
}

export function isPromptCacheCapability(capability: ProviderCacheCapability): boolean {
	return capability.mode === "prompt_cache";
}

export function isSessionStoreCapability(capability: ProviderCacheCapability): boolean {
	return capability.mode === "session_store";
}
