/**
 * OpenAI-compatible provider using fetch() directly (no openai SDK).
 */

import { getEnvApiKey } from "../env-api-keys.js";
import { calculateCost } from "../models.js";
import type {
	AssistantMessage,
	AssistantMessageStream,
	Context,
	Model,
	SimpleStreamOptions,
	StreamFunction,
	TextContent,
	ThinkingContent,
	ToolCall,
} from "../types.js";
import { AssistantMessageEventStream } from "../utils/event-stream.js";
import { httpRequest } from "../utils/http.js";
import { parseStreamingJson } from "../utils/json-parse.js";
import { buildBaseOptions, clampReasoning } from "./simple-options.js";
import { getCompat } from "./openai-compat-config.js";
import { buildOpenAIChatCompletionsPayload } from "./openai-compat-payload.js";
import { mapOpenAIStopReason } from "./openai-compat-streaming.js";
import type { OpenAICompletionsOptions } from "./openai-compat-types.js";
import { assertAssistantHasContent, logEmptyAssistantContentError } from "./assistant-content-validation.js";
export type { OpenAICompletionsOptions } from "./openai-compat-types.js";
export { getCompat } from "./openai-compat-config.js";

// ─── Stream function (low-level) ─────────────────────────────────────────────

export const streamOpenAICompletions: StreamFunction<"openai-completions", OpenAICompletionsOptions> = (
	model: Model<"openai-completions">,
	context: Context,
	options?: OpenAICompletionsOptions,
): AssistantMessageEventStream => {
	const stream = new AssistantMessageEventStream();

	(async () => {
		const output: AssistantMessage = {
			role: "assistant",
			content: [],
			api: model.api,
			provider: model.provider,
			model: model.id,
			usage: {
				input: 0,
				output: 0,
				cacheRead: 0,
				cacheWrite: 0,
				totalTokens: 0,
				cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
			},
			stopReason: "stop",
			timestamp: Date.now(),
		};

		try {
			const apiKey = options?.apiKey || getEnvApiKey(model.provider, model.apiKeyEnv) || "";
			if (!apiKey) {
				throw new Error(`No API key for provider: ${model.provider}`);
			}

			const compat = getCompat(model);
			const params = buildOpenAIChatCompletionsPayload(model, context, options, compat);
			options?.onPayload?.(params);

			// HTTP request using Node.js native https module
			const headers: Record<string, string> = {
				"Content-Type": "application/json",
				Authorization: `Bearer ${apiKey}`,
				// Some OpenAI-compatible providers require caller-supplied SSE headers.
				...(model.headers || {}),
				...(options?.headers || {}),
			};

			const response = await httpRequest(`${model.baseUrl}/chat/completions`, {
				method: "POST",
				headers,
				body: JSON.stringify(params),
				signal: options?.signal,
			});

			if (!response.ok) {
				const errorBody = await response.text().catch(() => "");
				throw new Error(`API error ${response.status}: ${errorBody}`);
			}

			stream.push({ type: "start", partial: output });

			// Parse SSE stream using Node.js native http response
			let currentBlock: TextContent | ThinkingContent | (ToolCall & { partialArgs?: string }) | null =
				null;
			const blocks = output.content;
			const blockIndex = () => blocks.length - 1;

			const finishCurrentBlock = (block?: typeof currentBlock) => {
				if (block) {
					if (block.type === "text") {
						stream.push({
							type: "text_end",
							contentIndex: blockIndex(),
							content: block.text,
							partial: output,
						});
					} else if (block.type === "thinking") {
						stream.push({
							type: "thinking_end",
							contentIndex: blockIndex(),
							content: block.thinking,
							partial: output,
						});
					} else if (block.type === "toolCall") {
						block.arguments = parseStreamingJson(block.partialArgs);
						delete (block as any).partialArgs;
						stream.push({
							type: "toolcall_end",
							contentIndex: blockIndex(),
							toolCall: block,
							partial: output,
						});
					}
				}
			};

			if (!response.readSSELines) {
				throw new Error('SSE streaming not supported on this platform');
			}

			for await (const line of response.readSSELines!(options?.signal)) {
				{
					const trimmed = line.trim();
					if (!trimmed || trimmed.startsWith(":")) continue;

					if (trimmed.startsWith("data: ")) {
						const data = trimmed.slice(6);
						if (data === "[DONE]") continue;

						let chunk: any;
						try {
							chunk = JSON.parse(data);
						} catch {
							continue;
						}

						// Process usage
						if (chunk.usage) {
							const cachedTokens = chunk.usage.prompt_tokens_details?.cached_tokens || 0;
							const reasoningTokens =
								chunk.usage.completion_tokens_details?.reasoning_tokens || 0;
							const input = (chunk.usage.prompt_tokens || 0) - cachedTokens;
							const outputTokens = (chunk.usage.completion_tokens || 0) + reasoningTokens;
							output.usage = {
								input,
								output: outputTokens,
								cacheRead: cachedTokens,
								cacheWrite: 0,
								totalTokens: input + outputTokens + cachedTokens,
								cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
							};
							calculateCost(model, output.usage);

							// Debug: log cache usage
							if (process.env.PIE_DEBUG_CACHE) {
								console.error("[CACHE DEBUG] Response usage:", JSON.stringify({
									input_tokens: input,
									output_tokens: outputTokens,
									cached_tokens: cachedTokens,
									cache_hit_rate: chunk.usage.prompt_tokens ? 
										`${((cachedTokens / chunk.usage.prompt_tokens) * 100).toFixed(1)}%` : 'N/A',
								}, null, 2));
							}
						}

						const choice = chunk.choices?.[0];
						if (!choice) continue;

						if (choice.finish_reason) {
							output.stopReason = mapOpenAIStopReason(choice.finish_reason);
						}

						if (choice.delta) {
							// Text content
							if (
								choice.delta.content !== null &&
								choice.delta.content !== undefined &&
								choice.delta.content.length > 0
							) {
								if (!currentBlock || currentBlock.type !== "text") {
									finishCurrentBlock(currentBlock);
									currentBlock = { type: "text", text: "" };
									output.content.push(currentBlock);
									stream.push({
										type: "text_start",
										contentIndex: blockIndex(),
										partial: output,
									});
								}

								if (currentBlock.type === "text") {
									currentBlock.text += choice.delta.content;
									stream.push({
										type: "text_delta",
										contentIndex: blockIndex(),
										delta: choice.delta.content,
										partial: output,
									});
								}
							}

							// Reasoning / thinking content
							const reasoningFields = [
								"reasoning_content",
								"reasoning",
								"reasoning_text",
							];
							let foundReasoningField: string | null = null;
							for (const field of reasoningFields) {
								if (
									choice.delta[field] !== null &&
									choice.delta[field] !== undefined &&
									choice.delta[field].length > 0
								) {
									foundReasoningField = field;
									break;
								}
							}

							if (foundReasoningField) {
								if (!currentBlock || currentBlock.type !== "thinking") {
									finishCurrentBlock(currentBlock);
									currentBlock = {
										type: "thinking",
										thinking: "",
										thinkingSignature: foundReasoningField,
									};
									output.content.push(currentBlock);
									stream.push({
										type: "thinking_start",
										contentIndex: blockIndex(),
										partial: output,
									});
								}

								if (currentBlock.type === "thinking") {
									const delta = choice.delta[foundReasoningField];
									currentBlock.thinking += delta;
									stream.push({
										type: "thinking_delta",
										contentIndex: blockIndex(),
										delta,
										partial: output,
									});
								}
							}

							// Tool calls
							if (choice.delta.tool_calls) {
								for (const toolCall of choice.delta.tool_calls) {
									if (
										!currentBlock ||
										currentBlock.type !== "toolCall" ||
										(toolCall.id && currentBlock.id !== toolCall.id)
									) {
										finishCurrentBlock(currentBlock);
										currentBlock = {
											type: "toolCall",
											id: toolCall.id || "",
											name: toolCall.function?.name || "",
											arguments: {},
											partialArgs: "",
										};
										output.content.push(currentBlock);
										stream.push({
											type: "toolcall_start",
											contentIndex: blockIndex(),
											partial: output,
										});
									}

									if (currentBlock.type === "toolCall") {
										if (toolCall.id) currentBlock.id = toolCall.id;
										if (toolCall.function?.name)
											currentBlock.name = toolCall.function.name;
										let delta = "";
										if (toolCall.function?.arguments) {
											delta = toolCall.function.arguments;
											(currentBlock as any).partialArgs +=
												toolCall.function.arguments;
											currentBlock.arguments = parseStreamingJson(
												(currentBlock as any).partialArgs,
											);
										}
										stream.push({
											type: "toolcall_delta",
											contentIndex: blockIndex(),
											delta,
											partial: output,
										});
									}
								}
							}
						}
					}
				}
			}

			finishCurrentBlock(currentBlock);
			if (
				output.stopReason !== "error" &&
				output.stopReason !== "aborted" &&
				output.content.some((block) => block.type === "toolCall")
			) {
				output.stopReason = "toolUse";
			}

			if (options?.signal?.aborted) {
				throw new Error("Request was aborted");
			}

			if (output.stopReason === "aborted" || output.stopReason === "error") {
				throw new Error("An unknown error occurred");
			}
			assertAssistantHasContent(output);

			stream.push({ type: "done", reason: output.stopReason, message: output });
			stream.end();
			} catch (error) {
				logEmptyAssistantContentError(error, model, options);
				output.stopReason = options?.signal?.aborted ? "aborted" : "error";
				output.errorMessage = error instanceof Error ? error.message : JSON.stringify(error);
			stream.push({ type: "error", reason: output.stopReason, error: output });
			stream.end();
		}
	})();

	return stream;
};

// ─── streamSimple (unified reasoning interface) ──────────────────────────────

export const streamSimpleOpenAICompletions: StreamFunction<"openai-completions", SimpleStreamOptions> = (
	model: Model<"openai-completions">,
	context: Context,
	options?: SimpleStreamOptions,
): AssistantMessageStream => {
	const apiKey = options?.apiKey || getEnvApiKey(model.provider, model.apiKeyEnv);
	if (!apiKey) {
		throw new Error(`No API key for provider: ${model.provider}`);
	}

	const base = buildBaseOptions(model, options, apiKey);
	const reasoningEffort = clampReasoning(options?.reasoning);

	return streamOpenAICompletions(model, context, {
		...base,
		reasoningEffort,
	} satisfies OpenAICompletionsOptions);
};
