import { type UnityContextSnapshot } from "./inspect-unity-context.js";

declare const CS: {
  System: {
    IO: {
      Path: {
        Combine(...parts: string[]): string;
        GetDirectoryName(path: string): string;
      };
      Directory: {
        Exists(path: string): boolean;
        CreateDirectory(path: string): unknown;
      };
      File: {
        Exists(path: string): boolean;
        ReadAllText(path: string): string;
        WriteAllText(path: string, content: string): void;
      };
    };
  };
};

export function getProjectAgentsPath(projectRoot: string): string {
  return CS.System.IO.Path.Combine(projectRoot, "AGENTS.md");
}

function ensureProjectAgentsDir(projectRoot: string): void {
  const agentsPath = getProjectAgentsPath(projectRoot);
  const dir = CS.System.IO.Path.GetDirectoryName(agentsPath);
  if (dir && !CS.System.IO.Directory.Exists(dir)) {
    CS.System.IO.Directory.CreateDirectory(dir);
  }
}

export function readProjectAgentsFile(projectRoot: string): string {
  const agentsPath = getProjectAgentsPath(projectRoot);
  if (!CS.System.IO.File.Exists(agentsPath)) return "";
  return CS.System.IO.File.ReadAllText(agentsPath);
}

export function writeProjectAgentsFile(projectRoot: string, content: string): void {
  ensureProjectAgentsDir(projectRoot);
  CS.System.IO.File.WriteAllText(getProjectAgentsPath(projectRoot), content || "");
}

export function buildInitialProjectAgentsFile(snapshot: UnityContextSnapshot): string {
  const packageLines = snapshot.packageHints.length > 0
    ? snapshot.packageHints.map((hint) => `- ${hint}`).join("\n")
    : "- No SRP package hints detected";
  const rootObjectLines = snapshot.rootObjects.length > 0
    ? snapshot.rootObjects.map((name) => `- ${name}`).join("\n")
    : "- No root objects detected";

  return `# AGENTS.md instructions

## Project Overview
- Product: ${snapshot.productName}
- Unity Version: ${snapshot.unityVersion}
- Scene: ${snapshot.sceneName || "(unknown)"}
- Project Root: ${snapshot.projectRoot}

## Render Pipeline
- Active pipeline: ${snapshot.renderPipeline}
- Pipeline asset type: ${snapshot.renderPipelineAssetType}
- Color space: ${snapshot.colorSpace}

## Package Hints
${packageLines}

## Scene Snapshot
- Root object count: ${snapshot.rootObjectCount}
${rootObjectLines}

## Safe Editing Rules
- Always inspect Unity context before creating materials or shaders.
- Never assume Built-in, URP, or HDRP from memory alone.
- Prefer reusing existing scene shaders/materials when possible.
- Keep scene edits small and observable.

## Validation Checklist
- Confirm render pipeline before material creation.
- Confirm target scene object names before mutation.
- Summarize created or modified objects after each task.
`;
}
