/**
 * Platform detection utilities
 * Detects whether running in Node.js or PuerTS (Unity) environment
 */

import type { PlatformType, PlatformCapabilities } from "./types.js";

/** Global CS namespace for PuerTS */
declare const CS: any;

/**
 * Check if running in PuerTS (Unity) environment
 * Uses runtime detection via typeof CS !== 'undefined'
 */
export function isPuerTS(): boolean {
  try {
    return typeof CS !== "undefined" && CS !== null;
  } catch {
    return false;
  }
}

/**
 * Check if running in Node.js environment
 */
export function isNode(): boolean {
  try {
    return (
      typeof process !== "undefined" &&
      process.versions != null &&
      process.versions.node != null &&
      !isPuerTS() // PuerTS might have a mock process object
    );
  } catch {
    return false;
  }
}

/**
 * Detect the current platform type
 */
export function detectPlatform(): PlatformType {
  if (isPuerTS()) {
    return "puerts";
  }
  if (isNode()) {
    return "node";
  }
  return "unknown";
}

/**
 * Get platform capabilities
 */
export function getCapabilities(platform: PlatformType): PlatformCapabilities {
  switch (platform) {
    case "node":
      return {
        hasFileSystem: true,
        hasHttpClient: true,
        hasProcessEnv: true,
        supportsStreams: true,
      };
    case "puerts":
      return {
        hasFileSystem: true,
        hasHttpClient: true,
        hasProcessEnv: false,
        supportsStreams: false,
      };
    default:
      return {
        hasFileSystem: false,
        hasHttpClient: false,
        hasProcessEnv: false,
        supportsStreams: false,
      };
  }
}

/**
 * Safe access to Node.js require
 * Returns undefined in non-Node environments
 * 
 * NOTE: In ESM mode, this uses createRequire to get a require function.
 * In CJS mode, it uses the global require.
 */
export function getNodeRequire(): NodeRequire | undefined {
  try {
    // Use globalThis.require for ESM compatibility (if it exists, e.g., in bundled code)
    const g = globalThis as any;
    if (g.require) {
      return g.require;
    }
    // Fallback to standard require if available (CJS mode)
    if (typeof require !== "undefined") {
      return require;
    }
  } catch {
    // ignore
  }
  
  // ESM mode: try to create require using createRequire
  // We need to use dynamic import because we can't statically import 'node:module' in CJS
  try {
    // @ts-ignore - Module may not exist in all environments
    const moduleModule = requireNodeModule<typeof import("node:module")>("node:module");
    if (moduleModule?.createRequire) {
      // In ESM, we need import.meta.url, but we don't have access to it here
      // The caller should use createRequire directly if they know they're in ESM
      // Return undefined to let the caller handle it
    }
  } catch {
    // ignore
  }
  
  return undefined;
}

/**
 * Dynamically import Node.js modules (only works in Node environment)
 */
export function requireNodeModule<T>(name: string): T | undefined {
  const nodeRequire = getNodeRequire();
  if (!nodeRequire) {
    return undefined;
  }
  try {
    return nodeRequire(name) as T;
  } catch {
    return undefined;
  }
}
