import type { AgentTool } from "@pie/agent-core";

export interface ToolCapabilityMetadata {
	riskClass?:
		| "read_only"
		| "write"
		| "shell"
		| "network"
		| "destructive"
		| "external_side_effect"
		| "session_mutation"
		| "user_interaction";
	concurrencySafe?: boolean;
	requiresPermission?: boolean;
	permissionScope?: "filesystem" | "shell" | "network" | "session" | "host" | "unity" | "user";
	maxOutputChars?: number;
	readsWorkspace?: boolean;
	writesWorkspace?: boolean;
	readsFile?: boolean;
	writesFile?: boolean;
	readsHostResource?: boolean;
	writesHostResource?: boolean;
	readsNetwork?: boolean;
	writesNetwork?: boolean;
	executesShell?: boolean;
	mutatesSession?: boolean;
	asksUser?: boolean;
	externalSideEffect?: boolean;
	highRisk?: boolean;
	availableInPlanMode?: boolean;
	allowedForSubagentByDefault?: boolean;
}

export type RuntimeToolPolicyMode = "normal" | "plan" | "subagent";

type ToolWithCapabilityMetadata = AgentTool & {
	capabilityMetadata?: ToolCapabilityMetadata;
	risk?: ToolCapabilityMetadata;
};

