export interface ToolPolicyDecision {
	allowed: boolean;
	reason?: string;
}

export function getToolCapabilityMetadata(tool: Pick<AgentTool, "name"> & Partial<ToolWithCapabilityMetadata>): ToolCapabilityMetadata | undefined {
	return tool.capabilityMetadata ?? tool.risk ?? BUILTIN_TOOL_CAPABILITY_METADATA[tool.name];
}

export function requireToolCapabilityMetadata(tool: Pick<AgentTool, "name"> & Partial<ToolWithCapabilityMetadata>): ToolCapabilityMetadata {
	const metadata = getToolCapabilityMetadata(tool);
	if (!metadata) {
		throw new Error(`Tool ${tool.name} is missing capability metadata.`);
	}
	return metadata;
}

export function describeToolPolicyDecision(tool: AgentTool, mode: RuntimeToolPolicyMode): ToolPolicyDecision & {
	metadata?: ToolCapabilityMetadata;
	mode: RuntimeToolPolicyMode;
} {
	const metadata = getToolCapabilityMetadata(tool);
	if (!metadata) {
		return { allowed: false, reason: "unclassified_tool", mode };
	}
	if (mode === "normal") return { allowed: true, metadata, mode };
	if (mode === "plan") return { allowed: isToolAllowedInPlanMode(tool), reason: isToolAllowedInPlanMode(tool) ? undefined : "not available in plan mode", metadata, mode };
	const decision = getSubagentToolPolicyDecision(tool);
	return { ...decision, metadata, mode };
}

export function isToolAllowedInPlanMode(tool: AgentTool): boolean {
	const metadata = getToolCapabilityMetadata(tool);
	if (!metadata) return false;
	if (metadata.availableInPlanMode !== undefined) return metadata.availableInPlanMode;
	if (metadata.writesFile || metadata.writesWorkspace || metadata.writesNetwork || metadata.externalSideEffect) return false;
	if (metadata.executesShell) return true;
	return Boolean(
		metadata.readsFile
		|| metadata.readsWorkspace
		|| metadata.readsHostResource
		|| metadata.readsNetwork
		|| metadata.mutatesSession
		|| metadata.asksUser,
	);
}

export function getSubagentToolPolicyDecision(tool: AgentTool): ToolPolicyDecision {
	const metadata = getToolCapabilityMetadata(tool);
	if (!metadata) {
		return { allowed: false, reason: "unclassified_tool" };
	}
	if (metadata.allowedForSubagentByDefault) return { allowed: true };
	if (metadata.riskClass === "read_only" || metadata.riskClass === "network") return { allowed: true };
	if (metadata.writesFile || metadata.writesWorkspace || metadata.writesNetwork || metadata.externalSideEffect || metadata.highRisk) {
		return { allowed: false, reason: "subagents are read-only in this phase" };
	}
	if (metadata.readsFile || metadata.readsWorkspace || metadata.readsHostResource || metadata.readsNetwork || metadata.asksUser) {
		return { allowed: true };
	}
	return { allowed: false, reason: "unclassified_tool" };
}

export function selectToolsForRuntimePolicy(
	tools: readonly AgentTool[],
	mode: RuntimeToolPolicyMode,
): AgentTool[] {
	if (mode === "normal") return [...tools];
	if (mode === "plan") return tools.filter(isToolAllowedInPlanMode);
	return tools.filter((tool) => getSubagentToolPolicyDecision(tool).allowed || tool.name === "bash");
}

export const DEFAULT_PLAN_MODE_TOOL_NAMES = Object.entries(BUILTIN_TOOL_CAPABILITY_METADATA)
	.filter(([, metadata]) => metadata.availableInPlanMode)
	.map(([name]) => name);
