import type { FileToolRoot, PathResolutionOptions } from "@pie/shared-headless-capabilities";
import type { PieBridge } from "./pie-bridge.js";

interface BridgeFileToolRoot {
  name?: string;
  description?: string;
  path?: string;
  defaultPrefixes?: string[];
}

interface BridgeFileToolRootsPayload {
  defaultRoot?: string;
  roots?: BridgeFileToolRoot[];
}

export interface ActiveFileToolRootsConfig {
  roots: FileToolRoot[];
  defaultRoot?: string;
}

function normalizePrefixes(prefixes: string[] | undefined): string[] | undefined {
  if (!Array.isArray(prefixes)) return undefined;
  const seen = new Set<string>();
  const results: string[] = [];
  for (const prefix of prefixes) {
    const normalized = String(prefix || "").trim().replace(/\\/g, "/").replace(/^\/+|\/+$/g, "");
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    results.push(normalized);
  }
  return results.length > 0 ? results : undefined;
}

function parseBridgePayload(): BridgeFileToolRootsPayload {
  try {
    const bridge = (globalThis as { pieBridge?: PieBridge & { getFileToolRootsJson?: () => string } }).pieBridge;
    if (typeof bridge?.getFileToolRootsJson !== "function") {
      return {};
    }

    const raw = String(bridge.getFileToolRootsJson() || "");
    if (!raw) {
      return {};
    }

    const parsed = JSON.parse(raw) as BridgeFileToolRootsPayload;
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch {
    return {};
  }
}

export function getActiveFileToolRootsConfig(): ActiveFileToolRootsConfig {
  const parsed = parseBridgePayload();
  const seen = new Set<string>();
  const roots: FileToolRoot[] = [];

  for (const root of parsed.roots ?? []) {
    const name = String(root?.name || "").trim();
    const path = String(root?.path || "").trim();
    if (!name || !path || seen.has(name)) continue;
    seen.add(name);
    roots.push({
      name,
      path: path.replace(/\\/g, "/"),
      description: String(root?.description || "").trim() || undefined,
      defaultPrefixes: normalizePrefixes(root?.defaultPrefixes),
    });
  }

  const defaultRoot = String(parsed.defaultRoot || "").trim() || undefined;
  const resolvedDefaultRoot = defaultRoot && roots.some((root) => root.name === defaultRoot)
    ? defaultRoot
    : undefined;

  return {
    roots,
    defaultRoot: resolvedDefaultRoot,
  };
}

export function buildFileToolPathOptions(): PathResolutionOptions {
  const config = getActiveFileToolRootsConfig();
  return {
    roots: config.roots,
    defaultRoot: config.defaultRoot,
  };
}

export function buildFileToolPromptLines(): string[] {
  const config = getActiveFileToolRootsConfig();
  if (config.roots.length === 0) {
    return [];
  }

  const lines = [
    "Path-based file tools accept an optional `root` parameter.",
    `Available roots for this session: ${config.roots.map((root) => root.name).join(", ")}.`,
  ];

  for (const root of config.roots) {
    const prefixNote = root.defaultPrefixes && root.defaultPrefixes.length > 0
      ? ` Prefix fallback: ${root.defaultPrefixes.map((prefix) => `${prefix}/`).join(", ")}.`
      : "";
    lines.push(`- \`${root.name}\`: ${root.description || root.path} Path: ${root.path}.${prefixNote}`);
  }

  if (config.defaultRoot) {
    lines.push(`When \`root\` is omitted, unmatched relative paths default to \`${config.defaultRoot}\`.`);
  }

  const prefixFallbackRoots = config.roots.filter((root) => (root.defaultPrefixes?.length ?? 0) > 0);
  if (prefixFallbackRoots.length > 0) {
    lines.push(`When \`root\` is omitted, matching prefixes are resolved first: ${prefixFallbackRoots.map((root) => `\`${root.name}\``).join(", ")}.`);
  }

  lines.push("Prefer passing `root` explicitly when accessing project files or custom configured roots.");
  return lines;
}
