import { discoverRuntimeScriptExtensions } from "@pie/agent-framework";
import { createExtensionApi, registerLoadedExtension, resetExtensionRegistry, type PieExtensionContext } from "./registry.js";
import { getExtensionSearchPaths } from "../skills.js";

type SystemIO = {
  Directory: { Exists(path: string): boolean };
  File: { ReadAllText(path: string): string | null };
};

declare const CS: { System?: { IO?: SystemIO } } | undefined;

function getSystemIO(): SystemIO {
  if (typeof CS === "undefined" || !CS?.System?.IO) {
    throw new Error("CS.System.IO not available - not running in PuerTS environment");
  }
  return CS.System.IO;
}

function normalizePath(path: string): string {
  return path.replace(/\\/g, "/");
}

function compileExtensionModule(code: string, sourceUrl: string): (api: unknown) => unknown {
  const transformed = code.includes("export default")
    ? code.replace(/export\s+default\s+/, "module.exports = ")
    : code;

  const evaluator = new Function(
    "module",
    "exports",
    `"use strict";\n${transformed}\n//# sourceURL=${sourceUrl}\nreturn module.exports?.default ?? module.exports ?? exports.default ?? exports;`,
  );

  const module: { exports: Record<string, unknown> & { default?: unknown } } = { exports: {} };
  const exports = module.exports;
  const factory = evaluator(module, exports);
  if (typeof factory !== "function") {
    throw new Error("Extension must export a default function (or assign module.exports = function(api) { ... }).");
  }
  return factory;
}

export function loadProjectExtensions(context: PieExtensionContext): { loaded: string[]; errors: string[] } {
  resetExtensionRegistry();

  const IO = getSystemIO();
  const extensionRoots = getExtensionSearchPaths(context.projectRoot);
  for (const root of extensionRoots) {
    if (!IO.Directory.Exists(root)) {
      context.log(`[extension] search path not found: ${root}`);
    }
  }
  const files = discoverRuntimeScriptExtensions(extensionRoots);
  const loaded: string[] = [];
  const errors: string[] = [];

  for (const filePath of files) {
    try {
      const code = String(IO.File.ReadAllText(filePath) ?? "");
      const sourceUrl = normalizePath(filePath);
      const api = createExtensionApi(context, sourceUrl);
      const factory = compileExtensionModule(code, sourceUrl);
      const result = factory(api);
      if (result && typeof (result as Promise<unknown>).then === "function") {
        throw new Error("Async extension activation is not supported in the initial loader.");
      }

      registerLoadedExtension(sourceUrl);
      loaded.push(sourceUrl);
      context.log(`[extension] loaded ${sourceUrl}`);
    } catch (error: unknown) {
      const message = `[extension] failed ${filePath}: ${error instanceof Error ? error.message : String(error)}`;
      errors.push(message);
      context.log(message);
    }
  }

  return { loaded, errors };
}
