/**
 * Agent loop - ported from pi-mono/packages/agent/src/agent-loop.ts
 * Core orchestration: prompt -> LLM -> tool calls -> execute -> repeat.
 *
 * Enhanced with hook support for extensibility:
 * - beforeAgentStart / afterAgentEnd
 * - beforeToolCall / afterToolCall
 * - onError
 */

import {
	type AssistantMessage,
	type Context,
	EventStream,
	streamSimple,
	type ToolResultMessage,
	validateToolArguments,
} from "@pie/ai";
import type {
	AgentContext,
	AgentEvent,
	AgentHooks,
	AgentLoopConfig,
	AgentMessage,
	AgentTool,
	AgentToolResult,
	StreamFn,
} from "./types.js";

function createLoopErrorMessage(error: unknown, config: AgentLoopConfig, signal?: AbortSignal): AssistantMessage {
	const message = error instanceof Error ? error.message : String(error);
	return {
		role: "assistant",
		content: [{ type: "text", text: "" }],
		api: config.model.api,
		provider: config.model.provider,
		model: config.model.id,
		usage: {
			input: 0,
			output: 0,
			cacheRead: 0,
			cacheWrite: 0,
			totalTokens: 0,
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
		},
		stopReason: signal?.aborted ? "aborted" : "error",
		errorMessage: message,
		timestamp: Date.now(),
	} as AssistantMessage;
}

async function notifyOnError(config: AgentLoopConfig, error: unknown, phase: string): Promise<void> {
	try {
		await config.hooks?.onError?.(error instanceof Error ? error : new Error(String(error)), { phase });
	} catch (hookError) {
		console.warn(`[AgentLoop] onError hook failed during ${phase}:`, hookError);
	}
}

function endStreamWithError(
	stream: EventStream<AgentEvent, AgentMessage[]>,
	newMessages: AgentMessage[],
	config: AgentLoopConfig,
	signal: AbortSignal | undefined,
	error: unknown,
): void {
	const errorMessage = createLoopErrorMessage(error, config, signal);
	newMessages.push(errorMessage);
	stream.push({ type: "message_start", message: errorMessage });
	stream.push({ type: "message_end", message: errorMessage });
	stream.push({ type: "turn_end", message: errorMessage, toolResults: [] });
	stream.push({ type: "agent_end", messages: newMessages });
	stream.end(newMessages);
}

export function agentLoop(
	prompts: AgentMessage[],
	context: AgentContext,
	config: AgentLoopConfig,
	signal?: AbortSignal,
	streamFn?: StreamFn,
): EventStream<AgentEvent, AgentMessage[]> {
	const stream = createAgentStream();

	(async () => {
		const newMessages: AgentMessage[] = [...prompts];
		try {
			// Call beforeAgentStart hook
			try {
				await config.hooks?.beforeAgentStart?.();
			} catch (e) {
				console.warn("[AgentLoop] beforeAgentStart hook failed:", e);
			}

			const currentContext: AgentContext = {
				...context,
				messages: [...context.messages, ...prompts],
			};

			stream.push({ type: "agent_start" });
			stream.push({ type: "turn_start" });
			for (const prompt of prompts) {
				stream.push({ type: "message_start", message: prompt });
				stream.push({ type: "message_end", message: prompt });
			}

			try {
				await runLoop(currentContext, newMessages, config, signal, stream, streamFn);
			} catch (error) {
				await notifyOnError(config, error, "runLoop");
				endStreamWithError(stream, newMessages, config, signal, error);
				return;
			}

			// Call afterAgentEnd hook
			try {
				await config.hooks?.afterAgentEnd?.(newMessages);
			} catch (e) {
				console.warn("[AgentLoop] afterAgentEnd hook failed:", e);
			}
		} catch (error) {
			await notifyOnError(config, error, "agentLoop");
			endStreamWithError(stream, newMessages, config, signal, error);
		}
	})();

	return stream;
}

export function agentLoopContinue(
	context: AgentContext,
	config: AgentLoopConfig,
	signal?: AbortSignal,
	streamFn?: StreamFn,
): EventStream<AgentEvent, AgentMessage[]> {
	if (context.messages.length === 0) {
		throw new Error("Cannot continue: no messages in context");
	}

	if (context.messages[context.messages.length - 1].role === "assistant") {
		throw new Error("Cannot continue from message role: assistant");
	}

	const stream = createAgentStream();

	(async () => {
		const newMessages: AgentMessage[] = [];
		try {
			// Call beforeAgentStart hook
			try {
				await config.hooks?.beforeAgentStart?.();
			} catch (e) {
				console.warn("[AgentLoop] beforeAgentStart hook failed:", e);
			}

			const currentContext: AgentContext = { ...context };

			stream.push({ type: "agent_start" });
			stream.push({ type: "turn_start" });

			try {
				await runLoop(currentContext, newMessages, config, signal, stream, streamFn);
			} catch (error) {
				await notifyOnError(config, error, "runLoop");
				endStreamWithError(stream, newMessages, config, signal, error);
				return;
			}

			// Call afterAgentEnd hook
			try {
				await config.hooks?.afterAgentEnd?.(newMessages);
			} catch (e) {
				console.warn("[AgentLoop] afterAgentEnd hook failed:", e);
			}
		} catch (error) {
			await notifyOnError(config, error, "agentLoopContinue");
			endStreamWithError(stream, newMessages, config, signal, error);
		}
	})();

	return stream;
}

function createAgentStream(): EventStream<AgentEvent, AgentMessage[]> {
	return new EventStream<AgentEvent, AgentMessage[]>(
		(event: AgentEvent) => event.type === "agent_end",
		(event: AgentEvent) => (event.type === "agent_end" ? event.messages : []),
	);
}

async function runLoop(
	currentContext: AgentContext,
	newMessages: AgentMessage[],
	config: AgentLoopConfig,
	signal: AbortSignal | undefined,
	stream: EventStream<AgentEvent, AgentMessage[]>,
	streamFn?: StreamFn,
): Promise<void> {
	let firstTurn = true;
	let pendingMessages: AgentMessage[] = (await config.getSteeringMessages?.()) || [];

	while (true) {
		let hasMoreToolCalls = true;
		let steeringAfterTools: AgentMessage[] | null = null;

		while (hasMoreToolCalls || pendingMessages.length > 0) {
			if (!firstTurn) {
				stream.push({ type: "turn_start" });
			} else {
				firstTurn = false;
			}

			if (pendingMessages.length > 0) {
				for (const message of pendingMessages) {
					stream.push({ type: "message_start", message });
					stream.push({ type: "message_end", message });
					currentContext.messages.push(message);
					newMessages.push(message);
				}
				pendingMessages = [];
			}

			let message: AssistantMessage;
			try {
				message = await streamAssistantResponse(currentContext, config, signal, stream, streamFn);
			} catch (error) {
				await notifyOnError(config, error, "streamAssistantResponse");
				throw error;
			}
			newMessages.push(message);

			if (message.stopReason === "error" || message.stopReason === "aborted") {
				stream.push({ type: "turn_end", message, toolResults: [] });
				stream.push({ type: "agent_end", messages: newMessages });
				stream.end(newMessages);
				return;
			}

			const toolCalls = message.content.filter((c) => c.type === "toolCall");
			hasMoreToolCalls = toolCalls.length > 0;

			const toolResults: ToolResultMessage[] = [];
			if (hasMoreToolCalls) {
				const toolExecution = await executeToolCalls(
					currentContext.tools,
					message,
					signal,
					stream,
					config.getSteeringMessages,
					config.hooks,
				);
				toolResults.push(...toolExecution.toolResults);
				steeringAfterTools = toolExecution.steeringMessages ?? null;

				for (const result of toolResults) {
					currentContext.messages.push(result);
					newMessages.push(result);
				}
			}

			stream.push({ type: "turn_end", message, toolResults });

			if (steeringAfterTools && steeringAfterTools.length > 0) {
				pendingMessages = steeringAfterTools;
				steeringAfterTools = null;
			} else {
				pendingMessages = (await config.getSteeringMessages?.()) || [];
			}
		}

		const followUpMessages = (await config.getFollowUpMessages?.()) || [];
		if (followUpMessages.length > 0) {
			pendingMessages = followUpMessages;
			continue;
		}

		break;
	}

	stream.push({ type: "agent_end", messages: newMessages });
	stream.end(newMessages);
}

async function streamAssistantResponse(
	context: AgentContext,
	config: AgentLoopConfig,
	signal: AbortSignal | undefined,
	stream: EventStream<AgentEvent, AgentMessage[]>,
	streamFn?: StreamFn,
): Promise<AssistantMessage> {
	let messages = context.messages;
	if (config.transformContext) {
		messages = await config.transformContext(messages, signal);
	}

	const llmMessages = await config.convertToLlm(messages);

	const llmContext: Context = {
		systemPrompt: context.systemPrompt,
		messages: llmMessages,
		tools: context.tools,
	};

	const streamFunction = streamFn || streamSimple;

	const resolvedApiKey =
		(config.getApiKey ? await config.getApiKey(config.model.provider) : undefined) || config.apiKey;

	const response = await streamFunction(config.model, llmContext, {
		...config,
		apiKey: resolvedApiKey,
		signal,
	});

	let partialMessage: AssistantMessage | null = null;
	let addedPartial = false;

	for await (const event of response) {
		switch (event.type) {
			case "start":
				partialMessage = event.partial;
				context.messages.push(partialMessage);
				addedPartial = true;
				stream.push({ type: "message_start", message: { ...partialMessage } });
				break;

			case "text_start":
			case "text_delta":
			case "text_end":
			case "thinking_start":
			case "thinking_delta":
			case "thinking_end":
			case "toolcall_start":
			case "toolcall_delta":
			case "toolcall_end":
				if (partialMessage) {
					partialMessage = event.partial;
					context.messages[context.messages.length - 1] = partialMessage;
					stream.push({
						type: "message_update",
						assistantMessageEvent: event,
						message: { ...partialMessage },
					});
				}
				break;

			case "done":
			case "error": {
				const finalMessage = await response.result();
				if (addedPartial) {
					context.messages[context.messages.length - 1] = finalMessage;
				} else {
					context.messages.push(finalMessage);
				}
				if (!addedPartial) {
					stream.push({ type: "message_start", message: { ...finalMessage } });
				}
				stream.push({ type: "message_end", message: finalMessage });
				return finalMessage;
			}
		}
	}

	return await response.result();
}

async function executeToolCalls(
	tools: AgentTool<any>[] | undefined,
	assistantMessage: AssistantMessage,
	signal: AbortSignal | undefined,
	stream: EventStream<AgentEvent, AgentMessage[]>,
	getSteeringMessages?: AgentLoopConfig["getSteeringMessages"],
	hooks?: AgentHooks,
): Promise<{ toolResults: ToolResultMessage[]; steeringMessages?: AgentMessage[] }> {
	const toolCalls = assistantMessage.content.filter((c) => c.type === "toolCall");
	const results: ToolResultMessage[] = [];
	let steeringMessages: AgentMessage[] | undefined;

	for (let index = 0; index < toolCalls.length; index++) {
		const toolCall = toolCalls[index];
		const tool = tools?.find((t) => t.name === toolCall.name);

		// Call beforeToolCall hook
		let blocked = false;
		let blockReason: string | undefined;
		try {
			const hookResult = await hooks?.beforeToolCall?.(toolCall.name, toolCall.arguments);
			if (hookResult && hookResult.block) {
				blocked = true;
				blockReason = hookResult.reason || "Blocked by hook";
			}
		} catch (e) {
			console.warn(`[AgentLoop] beforeToolCall hook failed for ${toolCall.name}:`, e);
		}

		let result: AgentToolResult<any>;
		let isError = false;
		let executionArgs: any = toolCall.arguments;
		let started = false;

		const pushToolStart = () => {
			if (started) return;
			started = true;
			stream.push({
				type: "tool_execution_start",
				toolCallId: toolCall.id,
				toolName: toolCall.name,
				args: executionArgs,
			});
		};

		if (blocked) {
			pushToolStart();
			// Tool was blocked by hook
			result = {
				content: [{ type: "text", text: `Tool execution blocked: ${blockReason}` }],
				details: { blocked: true, reason: blockReason },
			};
			isError = true;
		} else {
			try {
				if (!tool) {
					throw new Error(`Tool ${toolCall.name} not found`);
				}

				const validatedArgs = validateToolArguments(tool, toolCall);
				executionArgs = validatedArgs;
				pushToolStart();

				result = await tool.execute(toolCall.id, validatedArgs, signal, (partialResult) => {
					stream.push({
						type: "tool_execution_update",
						toolCallId: toolCall.id,
						toolName: toolCall.name,
						args: executionArgs,
						partialResult,
					});
				});
				isError = isError || !!result.isError;
			} catch (e) {
				pushToolStart();
				result = {
					content: [{ type: "text", text: e instanceof Error ? e.message : String(e) }],
					details: {},
				};
				isError = true;

				try {
					await hooks?.onError?.(e instanceof Error ? e : new Error(String(e)), {
						toolName: toolCall.name,
						phase: "toolExecution",
					});
				} catch (hookError) {
					console.warn(`[AgentLoop] onError hook failed during toolExecution for ${toolCall.name}:`, hookError);
				}
			}
		}

		// Call afterToolCall hook
		try {
			await hooks?.afterToolCall?.(toolCall.name, toolCall.arguments, result, isError);
		} catch (e) {
			console.warn(`[AgentLoop] afterToolCall hook failed for ${toolCall.name}:`, e);
		}

		stream.push({
			type: "tool_execution_end",
			toolCallId: toolCall.id,
			toolName: toolCall.name,
			args: executionArgs,
			result,
			isError,
		});

		const toolResultMessage: ToolResultMessage = {
			role: "toolResult",
			toolCallId: toolCall.id,
			toolName: toolCall.name,
			content: result.content as ToolResultMessage["content"],
			details: result.details,
			isError,
			timestamp: Date.now(),
		};

		results.push(toolResultMessage);
		stream.push({ type: "message_start", message: toolResultMessage });
		stream.push({ type: "message_end", message: toolResultMessage });

		if (getSteeringMessages) {
			const steering = await getSteeringMessages();
			if (steering.length > 0) {
				steeringMessages = steering;
				const remainingCalls = toolCalls.slice(index + 1);
				for (const skipped of remainingCalls) {
					results.push(skipToolCall(skipped, stream));
				}
				break;
			}
		}
	}

	return { toolResults: results, steeringMessages };
}

function skipToolCall(
	toolCall: any,
	stream: EventStream<AgentEvent, AgentMessage[]>,
): ToolResultMessage {
	const result: AgentToolResult<any> = {
		content: [{ type: "text", text: "Skipped due to queued user message." }],
		details: {},
	};

	stream.push({
		type: "tool_execution_start",
		toolCallId: toolCall.id,
		toolName: toolCall.name,
		args: toolCall.arguments,
	});
	stream.push({
		type: "tool_execution_end",
		toolCallId: toolCall.id,
		toolName: toolCall.name,
		args: toolCall.arguments,
		result,
		isError: true,
	});

	const toolResultMessage: ToolResultMessage = {
		role: "toolResult",
		toolCallId: toolCall.id,
		toolName: toolCall.name,
		content: result.content as ToolResultMessage["content"],
		details: {},
		isError: true,
		timestamp: Date.now(),
	};

	stream.push({ type: "message_start", message: toolResultMessage });
	stream.push({ type: "message_end", message: toolResultMessage });

	return toolResultMessage;
}
