import * as path from "node:path";
import { completeSimple, type Api, type FileReferenceContent, type ImageContent, type Model, type TextContent, type ToolModelRouteDecision, type UserContentBlock } from "@pie/ai";
import type { ReadFileUnderstandingKind, ReadFileUnderstandingRequest, ReadFileUnderstandingResult, ReadToolDetails } from "./builtin/fs/read.js";

export interface ReadFileUnderstandingPreparedContent {
	content: UserContentBlock[];
	details?: Record<string, unknown>;
}

export interface ReadFileUnderstandingPrepareParams {
	request: ReadFileUnderstandingRequest;
	model: Model<Api>;
	apiKey: string;
	sessionId: string;
}

export interface ReadFileUnderstandingDeps {
	getAgentModel: () => Model<Api> | undefined;
	getSessionId: () => string | undefined;
	resolveToolModel: (purpose: `read_file.${ReadFileUnderstandingKind}`) => ToolModelRouteDecision;
	prepareFileContent: (params: ReadFileUnderstandingPrepareParams) => Promise<ReadFileUnderstandingPreparedContent>;
}

function getModelLabel(model: Model<Api> | undefined): string | undefined {
	return model ? `${model.provider}/${model.id}` : undefined;
}

function textFromAssistant(message: Awaited<ReturnType<typeof completeSimple>>): string {
	return message.content
		.filter((block): block is TextContent => block.type === "text")
		.map((block) => block.text)
		.join("\n")
		.trim();
}

export function modalityForReadFileUnderstandingKind(kind: ReadFileUnderstandingKind): FileReferenceContent["modality"] {
	if (kind === "image") return "image";
	if (kind === "video") return "video";
	return "file";
}

export function buildReadFileUnderstandingPrompt(request: ReadFileUnderstandingRequest): TextContent {
	const question = request.question?.trim()
		|| `Summarize this ${request.kind} file with factual details useful to the coding task.`;
	return {
		type: "text",
		text: [
			`Analyze this ${request.kind} file for a coding agent.`,
			`File name: ${path.basename(request.displayPath)}`,
			`MIME type: ${request.mimeType}`,
			`Task: ${question}`,
			"Return concise factual observations. Do not invent details.",
		].join("\n"),
	};
}

export function buildDirectImageUnderstandingContent(request: ReadFileUnderstandingRequest): UserContentBlock[] | undefined {
	if (request.kind !== "image" || !request.imageInfo) return undefined;
	const image: ImageContent = {
		type: "image",
		mimeType: request.imageInfo.mimeType,
		data: request.imageInfo.base64,
	};
	return [image];
}

export function createReadFileUnderstandingHandler(
	deps: ReadFileUnderstandingDeps,
): (request: ReadFileUnderstandingRequest) => Promise<ReadFileUnderstandingResult> {
	return async (request) => understandFileWithModel(deps, request);
}

export async function understandFileWithModel(
	deps: ReadFileUnderstandingDeps,
	request: ReadFileUnderstandingRequest,
): Promise<ReadFileUnderstandingResult> {
	const purpose = `read_file.${request.kind}` as const;
	const decision = deps.resolveToolModel(purpose);
	const agentModel = deps.getAgentModel();
	const routeDetails = {
		purpose,
		requiredCapability: decision.requiredCapability,
		routeSource: decision.routeSource,
		agentModel: getModelLabel(agentModel),
		toolModel: getModelLabel(decision.model),
		fallbackReason: decision.fallbackReason,
		kind: request.kind,
		mimeType: request.mimeType,
	};

	if (!decision.model || !decision.apiKey) {
		return {
			content: [{
				type: "text",
				text: decision.fallbackReason || `No configured model declares ${request.kind} capability for ${purpose}.`,
			}],
			details: { understanding: routeDetails } satisfies ReadToolDetails,
			isError: true,
		};
	}

	const sessionId = deps.getSessionId() || `read-file-${Date.now()}`;
	try {
		const directImageContent = buildDirectImageUnderstandingContent(request);
		const prepared = directImageContent
			? { content: directImageContent, details: { inputMode: "inlineDataUrl" } }
			: await deps.prepareFileContent({
				request,
				model: decision.model,
				apiKey: decision.apiKey,
				sessionId,
			});
		const fileContent = prepared.content;
		const content = [
			buildReadFileUnderstandingPrompt(request),
			...fileContent,
		];
		const response = await completeSimple(
			decision.model,
			{
				systemPrompt: "You are a file-understanding tool. Answer only from the provided file. Keep the answer concise and factual.",
				messages: [{ role: "user", content, timestamp: Date.now() }],
			},
			{
				apiKey: decision.apiKey,
				maxTokens: Math.min(decision.model.maxTokens || 4096, 4096),
				signal: request.signal,
			},
		);
		const errorMessage = response.stopReason === "error" || response.stopReason === "aborted"
			? response.errorMessage
			: undefined;
		const text = textFromAssistant(response)
			|| (errorMessage ? `read_file ${request.kind} understanding failed: ${errorMessage}` : "(file understanding model returned no text)");
		return {
			content: [{ type: "text", text }],
			details: {
				understanding: {
					...routeDetails,
					toolModel: getModelLabel(decision.model),
					responseStopReason: response.stopReason,
					...prepared.details,
					...(errorMessage ? { error: errorMessage } : {}),
				},
			},
			isError: response.stopReason === "error" || response.stopReason === "aborted",
		};
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		return {
			content: [{ type: "text", text: `read_file ${request.kind} understanding failed: ${message}` }],
			details: {
				understanding: {
					...routeDetails,
					toolModel: getModelLabel(decision.model),
					error: message,
				},
			},
			isError: true,
		};
	}
}
