import {
	MODEL_CLASS_FALLBACK_ORDER,
	modelSupportsToolPurpose,
	requiredCapabilityForToolPurpose,
	sortToolModelCandidatesByCapability,
	type Api,
	type FileCapabilities,
	type Model,
	type OpenAICompletionsCompat,
	type ProviderCacheCapability,
	type ToolModelPurpose,
	type ToolModelRoute,
	type ToolModelRouteDecision,
	type WebSearchCapability,
} from "@pie/ai";
import type { PieBridge } from "./pie-bridge.js";

declare const CS: {
  System: {
    Environment: {
      SpecialFolder: { UserProfile: unknown };
      GetFolderPath(folder: unknown): string;
    };
    IO: {
      Path: { Combine(...parts: string[]): string };
      File: { Exists(path: string): boolean; ReadAllText(path: string): string | null };
    };
  };
};

type EndpointModelConfig = {
  id: string;
  name?: string;
  reasoning?: boolean;
  input?: Array<"text" | "image" | "audio" | "video">;
  cost?: { input: number; output: number; cacheRead: number; cacheWrite: number };
  contextWindow?: number;
  maxTokens?: number;
  compat?: OpenAICompletionsCompat;
  cacheCapability?: ProviderCacheCapability;
  headers?: Record<string, string>;
  apiKeyEnv?: string;
  displayName?: string;
  filePlatform?: string;
  attachmentPlatform?: string;
  webSearch?: WebSearchCapability;
  fileCapabilities?: FileCapabilities;
};

type EndpointProfile = {
  baseUrl: string;
  api: string;
  apiKey?: string;
  apiKeyEnv?: string;
  headers?: Record<string, string>;
  displayName?: string;
  filePlatform?: string;
  attachmentPlatform?: string;
  webSearch?: WebSearchCapability;
  fileCapabilities?: FileCapabilities;
  compat?: OpenAICompletionsCompat;
  cacheCapability?: ProviderCacheCapability;
  models?: EndpointModelConfig[];
};

type ModelsConfig = {
  profiles?: Record<string, EndpointProfile>;
  defaults?: {
    provider?: string;
    modelId?: string;
    modelClasses?: Partial<Record<"light" | "balanced" | "strong", ToolModelRoute>>;
    toolModels?: Partial<Record<ToolModelPurpose, ToolModelRoute>>;
  };
};

export type ResolvedEndpointModel = {
  model: Model<Api>;
  apiKey?: string;
};

export type ResolveConfiguredModelOptions = {
  allowMissingApiKey?: boolean;
};

export type UnityRuntimeModelCredential = {
  provider: string;
  modelId: string;
  apiKey: string;
};

export type ResolveUnityToolModelCandidatesOptions = {
  runtimeCredential?: UnityRuntimeModelCredential | null;
};

function validateEndpointProfile(
  profileId: string,
  profile: EndpointProfile,
  options: ResolveConfiguredModelOptions = {},
): string | null {
  const missing: string[] = [];
  if (!profile.api) missing.push("api");
  if (!profile.baseUrl) missing.push("baseUrl");
  if (!Array.isArray(profile.models) || profile.models.length === 0) missing.push("models");
  const hasProfileKeySource = !!(profile.apiKey || profile.apiKeyEnv);
  const hasModelKeySource = !!(profile.models || []).some((model) => !!model.apiKeyEnv);
  if (!options.allowMissingApiKey && !hasProfileKeySource && !hasModelKeySource) missing.push("apiKey or apiKeyEnv");
  if (missing.length > 0) {
    return `Profile "${profileId}" is missing required field${missing.length > 1 ? "s" : ""}: ${missing.join(", ")}.`;
  }

  for (let index = 0; index < (profile.models || []).length; index += 1) {
    const model = profile.models![index];
    const modelMissing: string[] = [];
    if (!model.id) modelMissing.push("id");
    if (!Array.isArray(model.input) || model.input.length === 0) modelMissing.push("input");
    if (!model.cost) modelMissing.push("cost");
    if (!model.contextWindow) modelMissing.push("contextWindow");
    if (!model.maxTokens) modelMissing.push("maxTokens");
    if (modelMissing.length > 0) {
      const label = model.id || `#${index}`;
      return `Profile "${profileId}" model "${label}" is missing required field${modelMissing.length > 1 ? "s" : ""}: ${modelMissing.join(", ")}.`;
    }
  }

  return null;
}

function getModelsConfigPath(): string {
  return CS.System.IO.Path.Combine(
    CS.System.Environment.GetFolderPath(CS.System.Environment.SpecialFolder.UserProfile),
    ".pie",
    "models.json",
  );
}

function readModelsConfig(bridge: PieBridge): ModelsConfig | null {
  const modelsPath = getModelsConfigPath();
  if (!CS.System.IO.File.Exists(modelsPath)) return null;
  try {
    const raw = String(CS.System.IO.File.ReadAllText(modelsPath) || "");
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === "object" && "providers" in parsed) {
      bridge.log("warn", `[pie/index] Legacy models.json format is not supported in Unity. Use top-level "profiles". Path: ${modelsPath}`);
      return null;
    }
    return parsed as ModelsConfig;
  } catch (error: unknown) {
    bridge.log("error", `[pie/index] Failed to read models.json: ${error instanceof Error ? error.message : String(error)}`);
    return null;
  }
}

export function getEndpointProfiles(bridge: PieBridge): Record<string, EndpointProfile> {
  const profiles = readModelsConfig(bridge)?.profiles || {};
  for (const [profileId, profile] of Object.entries(profiles)) {
    const validationError = validateEndpointProfile(profileId, profile);
    if (validationError) {
      bridge.log("warn", `[pie/index] ${validationError}`);
    }
  }
  return profiles;
}

export function getDefaultSelection(
  bridge: PieBridge,
  profiles: Record<string, EndpointProfile>,
): { provider: string; modelId: string } | null {
  const defaults = readModelsConfig(bridge)?.defaults;
  if (
    defaults?.provider &&
    defaults?.modelId &&
    profiles[defaults.provider]?.models?.some((model) => model.id === defaults.modelId)
  ) {
    return {
      provider: defaults.provider,
      modelId: defaults.modelId,
    };
  }
  return null;
}

export function createUnconfiguredModel(): Model<Api> {
  return {
    id: "unconfigured",
    name: "Unconfigured Model",
    api: "openai-completions",
    provider: "unconfigured",
    baseUrl: "",
    reasoning: false,
    input: ["text"],
    cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
    contextWindow: 0,
    maxTokens: 0,
  };
}

export function createRuntimeConfiguredModel(provider: string, modelId: string, baseUrl: string): ResolvedEndpointModel | null {
  const trimmedProvider = String(provider || "").trim();
  const trimmedModelId = String(modelId || "").trim();
  const trimmedBaseUrl = String(baseUrl || "").trim();
  if (!trimmedProvider || !trimmedModelId || !trimmedBaseUrl) return null;

  return {
    model: {
      id: trimmedModelId,
      name: trimmedModelId,
      api: "openai-completions",
      provider: trimmedProvider,
      baseUrl: trimmedBaseUrl,
      reasoning: false,
      input: ["text"],
      cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
      contextWindow: 128000,
      maxTokens: 8192,
    },
  };
}

export function resolveConfiguredModel(
  bridge: PieBridge,
  provider: string,
  modelId: string,
  options: ResolveConfiguredModelOptions = {},
): ResolvedEndpointModel | null {
  if (!provider || !modelId) return null;
  const profiles = getEndpointProfiles(bridge);
  const profile = profiles[provider];
  if (!profile || validateEndpointProfile(provider, profile, options)) return null;
  const modelDef = (profile.models || []).find((candidate) => candidate.id === modelId);
  if (!modelDef) return null;

  return {
    model: {
      id: modelDef.id,
      name: modelDef.name || modelDef.id,
      api: profile.api as Api,
      provider,
      baseUrl: profile.baseUrl,
      reasoning: modelDef.reasoning ?? false,
      input: modelDef.input || ["text"],
      cost: modelDef.cost || { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
      contextWindow: modelDef.contextWindow || 128000,
      maxTokens: modelDef.maxTokens || 8192,
      apiKeyEnv: modelDef.apiKeyEnv || profile.apiKeyEnv,
      displayName: modelDef.displayName || profile.displayName,
      filePlatform: modelDef.filePlatform || profile.filePlatform,
      attachmentPlatform: modelDef.attachmentPlatform || profile.attachmentPlatform,
      headers: profile.headers ? { ...profile.headers, ...modelDef.headers } : modelDef.headers,
      compat: modelDef.compat || profile.compat,
      cacheCapability: modelDef.cacheCapability || profile.cacheCapability,
      webSearch: modelDef.webSearch || profile.webSearch,
      fileCapabilities: modelDef.fileCapabilities || profile.fileCapabilities,
    },
    apiKey: profile.apiKey,
  };
}

function resolveRoute(bridge: PieBridge, route: ToolModelRoute | undefined): ResolvedEndpointModel | null {
  if (!route?.provider || !route?.modelId) return null;
  return resolveConfiguredModel(bridge, route.provider, route.modelId);
}

function runtimeCredentialForModel(
  model: Model<Api> | undefined,
  options?: ResolveUnityToolModelCandidatesOptions,
): string | undefined {
  const credential = options?.runtimeCredential;
  if (!model || !credential?.apiKey) return undefined;
  return credential.provider === model.provider && credential.modelId === model.id
    ? credential.apiKey
    : undefined;
}

function resolveCandidateApiKey(
  resolved: ResolvedEndpointModel | null | undefined,
  options?: ResolveUnityToolModelCandidatesOptions,
): string | undefined {
  return resolved?.apiKey || runtimeCredentialForModel(resolved?.model, options);
}

function missingApiKeyReason(model: Model<Api>, purpose: ToolModelPurpose): string {
  return `${model.provider}/${model.id} declares ${requiredCapabilityForToolPurpose(purpose)} for ${purpose}, but no API key is available from models.json or the matching Unity runtime model selection.`;
}

function getAllResolvedModels(bridge: PieBridge): ResolvedEndpointModel[] {
  const profiles = getEndpointProfiles(bridge);
  const resolved: ResolvedEndpointModel[] = [];
  for (const [provider, profile] of Object.entries(profiles)) {
    for (const model of profile.models || []) {
      const item = resolveConfiguredModel(bridge, provider, model.id);
      if (item) resolved.push(item);
    }
  }
  return resolved;
}

export function resolveUnityToolModelCandidates(
  bridge: PieBridge,
  purpose: ToolModelPurpose,
  currentModel?: Model<Api>,
  options?: ResolveUnityToolModelCandidatesOptions,
): ToolModelRouteDecision[] {
  const defaults = readModelsConfig(bridge)?.defaults;
  const requiredCapability = requiredCapabilityForToolPurpose(purpose);
  const candidates: ToolModelRouteDecision[] = [];
  const seen = new Set<string>();
  const add = (decision: ToolModelRouteDecision | undefined): void => {
    if (!decision) return;
    if (!decision.model) {
      if (decision.routeSource === "unavailable") candidates.push(decision);
      return;
    }
    const key = `${decision.model.provider}/${decision.model.id}`;
    if (seen.has(key)) return;
    seen.add(key);
    candidates.push(decision);
  };

  const explicitRoute = defaults?.toolModels?.[purpose];
  if (explicitRoute?.provider && explicitRoute.modelId) {
    const explicit = resolveRoute(bridge, explicitRoute);
    const explicitApiKey = resolveCandidateApiKey(explicit, options);
    if (explicit?.model && modelSupportsToolPurpose(explicit.model, purpose)) {
      add({
        purpose,
        requiredCapability,
        routeSource: "explicit",
        model: explicit.model,
        apiKey: explicitApiKey,
        fallbackReason: explicitApiKey ? undefined : missingApiKeyReason(explicit.model, purpose),
      });
    } else {
      add({
        purpose,
        requiredCapability,
        routeSource: "unavailable",
        model: explicit?.model,
        fallbackReason: `models.json defaults.toolModels.${purpose} is unavailable or does not declare ${requiredCapability}`,
      });
    }
  }

  if (currentModel && modelSupportsToolPurpose(currentModel, purpose)) {
    const current = resolveConfiguredModel(bridge, currentModel.provider, currentModel.id);
    const currentApiKey = resolveCandidateApiKey(current, options) || runtimeCredentialForModel(currentModel, options);
    const model = current?.model || currentModel;
    if (model) {
      add({
        purpose,
        requiredCapability,
        routeSource: "current_model",
        model,
        apiKey: currentApiKey,
        fallbackReason: currentApiKey ? undefined : missingApiKeyReason(model, purpose),
      });
    }
  }

  const classCandidates: ToolModelRouteDecision[] = [];
  for (const modelClass of MODEL_CLASS_FALLBACK_ORDER) {
    const resolved = resolveRoute(bridge, defaults?.modelClasses?.[modelClass]);
    const apiKey = resolveCandidateApiKey(resolved, options);
    if (resolved?.model && modelSupportsToolPurpose(resolved.model, purpose)) {
      classCandidates.push({
        purpose,
        requiredCapability,
        routeSource: "model_class",
        model: resolved.model,
        apiKey,
        fallbackReason: apiKey ? undefined : missingApiKeyReason(resolved.model, purpose),
      });
    }
  }
  for (const decision of sortToolModelCandidatesByCapability(purpose, classCandidates)) add(decision);

  const configuredCandidates = getAllResolvedModels(bridge)
    .filter((resolved) => modelSupportsToolPurpose(resolved.model, purpose))
    .map((resolved): ToolModelRouteDecision => ({
      purpose,
      requiredCapability,
      routeSource: "configured_model",
      model: resolved.model,
      apiKey: resolveCandidateApiKey(resolved, options),
      fallbackReason: resolveCandidateApiKey(resolved, options) ? undefined : missingApiKeyReason(resolved.model, purpose),
    }));
  for (const decision of sortToolModelCandidatesByCapability(purpose, configuredCandidates)) add(decision);

  if (candidates.some((candidate) => candidate.model)) {
    return candidates.filter((candidate) => candidate.model);
  }
  return candidates.length > 0 ? candidates : [{
    purpose,
    requiredCapability,
    routeSource: "unavailable",
    fallbackReason: `No configured model declares ${requiredCapability} capability for ${purpose}.`,
  }];
}

export function describeUnityToolModelRoute(
  bridge: PieBridge,
  purpose: ToolModelPurpose,
  currentModel?: Model<Api>,
  options?: ResolveUnityToolModelCandidatesOptions,
): string {
  const candidates = resolveUnityToolModelCandidates(bridge, purpose, currentModel, options);
  const preferred = candidates.find((candidate) => candidate.model && candidate.apiKey)
    || candidates.find((candidate) => candidate.model);
  if (!preferred?.model) {
    const unavailable = candidates.find((candidate) => candidate.routeSource === "unavailable");
    return `${purpose}: unavailable (${unavailable?.fallbackReason || `missing ${requiredCapabilityForToolPurpose(purpose)} capability`})`;
  }
  const candidateCount = candidates.filter((candidate) => candidate.model && candidate.apiKey).length;
  const capability = purpose === "web_search"
    ? preferred.model.webSearch?.type || "webSearch"
    : requiredCapabilityForToolPurpose(purpose);
  return [
    `${purpose}: ${preferred.model.provider}/${preferred.model.id}`,
    `route=${preferred.routeSource}`,
    `capability=${capability}`,
    `candidates=${candidateCount}`,
    ...(preferred.apiKey ? [] : [`status=${preferred.fallbackReason || "missing API key"}`]),
  ].join(" ");
}

export function describeUnityToolModelRoutes(
  bridge: PieBridge,
  currentModel?: Model<Api>,
  options?: ResolveUnityToolModelCandidatesOptions,
): string[] {
  return ([
    "web_search",
    "read_file.image",
    "read_file.video",
    "read_file.audio",
    "read_file.document",
  ] as ToolModelPurpose[]).map((purpose) => describeUnityToolModelRoute(bridge, purpose, currentModel, options));
}
