import { getLogger } from "@pie/platform";
import type { AssistantMessage, Model, StreamOptions } from "../types.js";

export const EMPTY_ASSISTANT_CONTENT_ERROR = "stream ended without assistant content";
export const EMPTY_ASSISTANT_CONTENT_ERROR_CODE = "empty_assistant_content";

export class EmptyAssistantContentError extends Error {
	readonly code = EMPTY_ASSISTANT_CONTENT_ERROR_CODE;

	constructor(message = EMPTY_ASSISTANT_CONTENT_ERROR) {
		super(message);
		this.name = "EmptyAssistantContentError";
	}
}

export function hasAssistantContent(message: AssistantMessage): boolean {
	return message.content.some((block) => {
		if (block.type === "text") {
			return block.text.trim().length > 0;
		}
		if (block.type === "thinking") {
			return block.thinking.trim().length > 0;
		}
		if (block.type === "toolCall") {
			return block.name.trim().length > 0;
		}
		return false;
	});
}

export function assertAssistantHasContent(message: AssistantMessage): void {
	if (!hasAssistantContent(message)) {
		throw new EmptyAssistantContentError();
	}
}

export function isEmptyAssistantContentError(error: unknown): error is EmptyAssistantContentError {
	return error instanceof EmptyAssistantContentError ||
		(typeof error === "object" &&
			error !== null &&
			"code" in error &&
			(error as { code?: unknown }).code === EMPTY_ASSISTANT_CONTENT_ERROR_CODE);
}

export function logEmptyAssistantContentError(
	error: unknown,
	model: Model<any>,
	options?: Pick<StreamOptions, "sessionId" | "metadata">,
): void {
	if (!isEmptyAssistantContentError(error)) {
		return;
	}

	getLogger().child({ module: "ai.provider" }).warn(EMPTY_ASSISTANT_CONTENT_ERROR, {
		code: EMPTY_ASSISTANT_CONTENT_ERROR_CODE,
		provider: model.provider,
		model: model.id,
		api: model.api,
		sessionId: options?.sessionId,
		metadata: options?.metadata,
	});
}
