/**
 * Model registry and management
 * 
 * Models can be registered at runtime via `registerModel()` or loaded from
 * configuration. The registry supports any profile id that implements the
 * Model interface.
 */

import type { Api, FileCapabilities, Model, WebSearchCapability } from "./types.js";
import { getBuiltInModels } from "./models.builtins.js";

export { getBuiltInModels } from "./models.builtins.js";

/**
 * Global model registry
 */
const modelRegistry = new Map<string, Map<string, Model<Api>>>();

/**
 * Get a model from the registry
 * @throws Error if model not found
 */
export function getModel(provider: string, modelId: string): Model<Api> {
	const providerModels = modelRegistry.get(provider);
	const model = providerModels?.get(modelId);
	if (!model) {
		throw new Error(`Model "${modelId}" not found for provider "${provider}". ` +
			`Available: ${listAvailableModels().join(", ") || "(none)"}`);
	}
	return model;
}

/**
 * Register a model at runtime
 */
export function registerModel(model: Model<Api>): void {
	let providerModels = modelRegistry.get(model.provider);
	if (!providerModels) {
		providerModels = new Map();
		modelRegistry.set(model.provider, providerModels);
	}
	providerModels.set(model.id, model);
}

/**
 * Register multiple models at once
 */
export function registerModels(models: Model<Api>[]): void {
	for (const model of models) {
		registerModel(model);
	}
}

/**
 * Unregister a model
 */
export function unregisterModel(provider: string, modelId: string): boolean {
	const providerModels = modelRegistry.get(provider);
	if (!providerModels) return false;
	
	const deleted = providerModels.delete(modelId);
	
	// Clean up empty providers
	if (providerModels.size === 0) {
		modelRegistry.delete(provider);
	}
	
	return deleted;
}

/**
 * Get all registered providers
 */
export function getProviders(): string[] {
	return Array.from(modelRegistry.keys());
}

/**
 * Get all models for a provider
 */
export function getModels(provider: string): Model<Api>[] {
	const models = modelRegistry.get(provider);
	return models ? Array.from(models.values()) : [];
}

/**
 * Get all registered models across all providers
 */
export function getAllModels(): Model<Api>[] {
	const all: Model<Api>[] = [];
	for (const providerModels of modelRegistry.values()) {
		all.push(...providerModels.values());
	}
	return all;
}

/**
 * List all available model IDs as "provider/modelId" strings
 */
export function listAvailableModels(): string[] {
	const ids: string[] = [];
	for (const [provider, models] of modelRegistry) {
		for (const modelId of models.keys()) {
			ids.push(`${provider}/${modelId}`);
		}
	}
	return ids.sort();
}

/**
 * Check if a model exists in the registry
 */
export function hasModel(provider: string, modelId: string): boolean {
	return modelRegistry.get(provider)?.has(modelId) ?? false;
}

/**
 * Clear all models (mainly for testing)
 */
export function clearModels(): void {
	modelRegistry.clear();
}

/**
 * Calculate cost based on usage and model pricing
 */
export function calculateCost<TApi extends Api>(model: Model<TApi>, usage: {
	input: number;
	output: number;
	cacheRead: number;
	cacheWrite: number;
}): {
	input: number;
	output: number;
	cacheRead: number;
	cacheWrite: number;
	total: number;
} {
	const input = (model.cost.input / 1000000) * usage.input;
	const output = (model.cost.output / 1000000) * usage.output;
	const cacheRead = (model.cost.cacheRead / 1000000) * usage.cacheRead;
	const cacheWrite = (model.cost.cacheWrite / 1000000) * usage.cacheWrite;
	
	return {
		input,
		output,
		cacheRead,
		cacheWrite,
		total: input + output + cacheRead + cacheWrite,
	};
}

/**
 * Create a model definition
 * Helper function to ensure type safety
 */
export function createModel<TApi extends Api>(
	id: string,
	config: Omit<Model<TApi>, "id">
): Model<TApi> {
	return {
		id,
		...config,
	} as Model<TApi>;
}

/**
 * @deprecated @pie/ai no longer bundles concrete provider model catalogs.
 * Register provider models from product/user configuration instead.
 */
export function registerDefaultModels(): void {
	registerModels(getBuiltInModels());
}

/**
 * Load models from a configuration object
 * Useful for loading from ~/.pie/models.json
 */
export interface ModelConfig {
	profiles?: Record<string, {
		baseUrl: string;
		api: string;
		apiKey?: string;
		apiKeyEnv?: string;
		headers?: Record<string, string>;
		displayName?: string;
		filePlatform?: string;
		attachmentPlatform?: string;
		webSearch?: WebSearchCapability;
		fileCapabilities?: FileCapabilities;
		models: Array<{
			id: string;
			name: string;
			reasoning: boolean;
			input: ("text" | "image" | "audio" | "video")[];
			contextWindow: number;
			maxTokens: number;
			cost: {
				input: number;
				output: number;
				cacheRead: number;
				cacheWrite: number;
			};
			compat?: any;
			cacheCapability?: any;
			webSearch?: WebSearchCapability;
			fileCapabilities?: FileCapabilities;
			headers?: Record<string, string>;
			apiKeyEnv?: string;
			displayName?: string;
			filePlatform?: string;
			attachmentPlatform?: string;
		}>;
	}>;
}

/**
 * Register models from configuration
 * @param config Model configuration object
 * @returns Map of provider -> apiKey for later use
 */
export function registerModelsFromConfig(config: ModelConfig): Map<string, string> {
	const apiKeys = new Map<string, string>();
	const configuredProfiles = config.profiles || {};

	for (const [providerName, providerConfig] of Object.entries(configuredProfiles)) {
		// Store API key if provided
		if (providerConfig.apiKey) {
			apiKeys.set(providerName, providerConfig.apiKey);
		}

		// Register each model
		for (const modelDef of providerConfig.models) {
			const model: Model<any> = {
				id: modelDef.id,
				name: modelDef.name,
				api: providerConfig.api as any,
				provider: providerName,
				baseUrl: providerConfig.baseUrl,
				reasoning: modelDef.reasoning,
				input: modelDef.input,
				cost: modelDef.cost,
				contextWindow: modelDef.contextWindow,
				maxTokens: modelDef.maxTokens,
				apiKeyEnv: modelDef.apiKeyEnv || providerConfig.apiKeyEnv,
				displayName: modelDef.displayName || providerConfig.displayName,
				filePlatform: modelDef.filePlatform || providerConfig.filePlatform,
				attachmentPlatform: modelDef.attachmentPlatform || providerConfig.attachmentPlatform,
				headers: providerConfig.headers
					? { ...providerConfig.headers, ...modelDef.headers }
					: modelDef.headers,
				compat: modelDef.compat,
				cacheCapability: modelDef.cacheCapability,
				webSearch: modelDef.webSearch || providerConfig.webSearch,
				fileCapabilities: modelDef.fileCapabilities || providerConfig.fileCapabilities,
			};
			registerModel(model);
		}
	}

	return apiKeys;
}
