import { requestInteraction, InteractionUnavailableError } from "@pie/agent-framework";
import { Type } from "@sinclair/typebox";
import { defineSharedCapability } from "./capability.js";

const OTHER_OPTION = "✏️ Other (type your own)";
const BACK_OPTION = "← Back";
const REVIEW_OPTION = "☰ Review all answers";
const CONFIRM_OPTION = "✓ Confirm and continue";
const RESTART_OPTION = "↺ Restart all";
const DEFAULT_ASK_TIMEOUT_MS = 60_000;

export const AskUserParamsSchema = Type.Object({
	question: Type.String({
		description: "REQUIRED: The question text to ask the user",
	}),
	options: Type.Optional(Type.Array(
		Type.String({ description: "An option label" }),
	)),
	allowOther: Type.Optional(Type.Boolean({
		description: "Whether to show 'Other' option (default: true when options provided)",
		default: true,
	})),
	allowBack: Type.Optional(Type.Boolean({
		description: "Whether to allow going back (adds '← Back' option)",
		default: false,
	})),
	placeholder: Type.Optional(Type.String({
		description: "Placeholder text for input field",
	})),
});

export const AskUserMultiParamsSchema = Type.Object({
	prompt: Type.Optional(Type.String({
		description: "Legacy-compatible shortcut for a single question. Equivalent to `question`.",
	})),
	question: Type.Optional(Type.String({
		description: "Preferred shortcut for a single question. Use this for the common case.",
	})),
	options: Type.Optional(Type.Array(
		Type.String({ description: "Shortcut options for the single-question form." }),
	)),
	placeholder: Type.Optional(Type.String({
		description: "Shortcut placeholder for the single-question form.",
	})),
	questions: Type.Optional(Type.Array(
		Type.Union([
			Type.String({
				description:
					"Lightweight question syntax. Use `Question text|Option A|Option B` for single choice, or just `Question text` for free text.",
			}),
			Type.Object({
				id: Type.Optional(Type.String({ description: "Question identifier; optional and auto-generated if omitted." })),
				question: Type.String({ description: "Question text" }),
				options: Type.Optional(Type.Array(Type.String())),
				allowOther: Type.Optional(Type.Boolean()),
				placeholder: Type.Optional(Type.String()),
			}),
		]),
		{ description: "Questions to ask sequentially. Can be strings or lightweight objects." },
	)),
	allowReview: Type.Optional(Type.Boolean({
		description: "Allow user to review and modify answers at the end",
		default: true,
	})),
});

function buildUnsupportedResult(error: unknown) {
	const message = error instanceof InteractionUnavailableError
		? error.message
		: error instanceof Error
			? error.message
			: String(error);

	return {
		content: [{ type: "text" as const, text: `Interaction unavailable: ${message}` }],
		details: { unsupported: true, error: message },
		isError: true,
	};
}

function validateQuestions(questions: unknown): string | null {
	if (!Array.isArray(questions) || questions.length === 0) {
		return "'questions' must be a non-empty array";
	}
	for (let index = 0; index < questions.length; index++) {
		const question = questions[index];
		if (!question || typeof question !== "object") {
			return `questions[${index}] must be an object`;
		}
		const candidate = question as {
			id?: unknown;
			question?: unknown;
			options?: unknown;
		};
		if (typeof candidate.id !== "string" || candidate.id.trim().length === 0) {
			return `questions[${index}].id must be a non-empty string`;
		}
		if (typeof candidate.question !== "string" || candidate.question.trim().length === 0) {
			return `questions[${index}].question must be a non-empty string`;
		}
		if (candidate.options !== undefined) {
			if (!Array.isArray(candidate.options) || candidate.options.length === 0) {
				return `questions[${index}].options must be a non-empty array when provided`;
			}
			for (let optionIndex = 0; optionIndex < candidate.options.length; optionIndex++) {
				const option = candidate.options[optionIndex];
				if (typeof option !== "string" || option.trim().length === 0) {
					return `questions[${index}].options[${optionIndex}] must be a non-empty string`;
				}
			}
		}
	}
	return null;
}

type NormalizedAskQuestion = {
	id: string;
	question: string;
	options?: string[];
	allowOther?: boolean;
	placeholder?: string;
};

function normalizeStringQuestion(value: string, index: number): NormalizedAskQuestion | null {
	const parts = value
		.split("|")
		.map((part) => part.trim())
		.filter((part) => part.length > 0);
	if (parts.length === 0) return null;
	const [question, ...options] = parts;
	return {
		id: `q${index + 1}`,
		question,
		options: options.length > 0 ? options : undefined,
	};
}

function normalizeQuestionObject(value: Record<string, unknown>, index: number): NormalizedAskQuestion {
	const options = Array.isArray(value.options)
		? value.options
				.filter((option): option is string => typeof option === "string")
				.map((option) => option.trim())
				.filter((option) => option.length > 0)
		: undefined;

	return {
		id: typeof value.id === "string" && value.id.trim().length > 0 ? value.id.trim() : `q${index + 1}`,
		question: typeof value.question === "string" ? value.question.trim() : "",
		options: options && options.length > 0 ? options : undefined,
		allowOther: typeof value.allowOther === "boolean" ? value.allowOther : undefined,
		placeholder: typeof value.placeholder === "string" ? value.placeholder : undefined,
	};
}

function normalizeAskUserArgs(args: any): { questions: NormalizedAskQuestion[]; allowReview: boolean } | { error: string } {
	if (typeof args === "string") {
		try {
			args = JSON.parse(args);
		} catch {
			const preview = args.length > 200 ? `${args.slice(0, 200)}...` : args;
			return { error: `Tool arguments must be an object or valid JSON object string (received string: ${preview})` };
		}
	}

	const allowReview = args?.allowReview ?? true;
	const singleQuestionText =
		typeof args?.question === "string" && args.question.trim().length > 0
			? args.question.trim()
			: typeof args?.prompt === "string" && args.prompt.trim().length > 0
				? args.prompt.trim()
				: undefined;

	const normalizedSingleQuestion = singleQuestionText
		? {
				id: "q1",
				question: singleQuestionText,
				options: Array.isArray(args.options)
					? args.options
							.filter((option: unknown): option is string => typeof option === "string")
							.map((option: string) => option.trim())
							.filter((option: string) => option.length > 0)
					: undefined,
				placeholder: typeof args?.placeholder === "string" ? args.placeholder : undefined,
			}
		: undefined;

	if (normalizedSingleQuestion && Array.isArray(args?.questions) && args.questions.length === 0) {
		return { questions: [normalizedSingleQuestion], allowReview };
	}

	if (!Array.isArray(args?.questions)) {
		if (normalizedSingleQuestion) {
			return { questions: [normalizedSingleQuestion], allowReview };
		}
		return { error: "Provide `question` or `prompt` for a single question, or provide a non-empty `questions` array" };
	}

	const normalizedQuestions = args.questions
		.map((question: unknown, index: number) => {
			if (typeof question === "string") {
				return normalizeStringQuestion(question, index);
			}
			if (question && typeof question === "object") {
				return normalizeQuestionObject(question as Record<string, unknown>, index);
			}
			return null;
		})
		.filter((question: NormalizedAskQuestion | null): question is NormalizedAskQuestion => {
			if (question === null) return false;
			return typeof question.question === "string" && question.question.trim().length > 0;
		});

	if (normalizedQuestions.length > 0) {
		return { questions: normalizedQuestions, allowReview };
	}

	if (normalizedSingleQuestion) {
		return { questions: [normalizedSingleQuestion], allowReview };
	}

	return { error: "Provide `question` or `prompt` for a single question, or provide a non-empty `questions` array" };
}

async function requestTextAnswer(question: string, placeholder?: string, multiline = false): Promise<string | undefined> {
	const response = await requestInteraction(
		multiline
			? { type: "multiline_input", id: `ask-user:${Date.now()}`, prompt: question, timeoutMs: DEFAULT_ASK_TIMEOUT_MS }
			: { type: "text_input", id: `ask-user:${Date.now()}`, prompt: question, placeholder, timeoutMs: DEFAULT_ASK_TIMEOUT_MS },
	);

	if (response.type !== (multiline ? "multiline_input" : "text_input")) {
		return undefined;
	}

	return response.value;
}

function buildSkippedResult(question: string, timedOut = false) {
	return {
		content: [{ type: "text" as const, text: "(skipped)" }],
		details: {
			answer: "(skipped)",
			skipped: true,
			timedOut,
			question,
			cancelled: false,
		},
	};
}

async function askSingleQuestion(args: any): Promise<any> {
	const { question, options, allowOther = true, allowBack = false, allowReview = false, placeholder } = args;

	if (!question || typeof question !== "string") {
		return {
			content: [{ type: "text" as const, text: "Error: 'question' parameter is required" }],
			isError: true,
		};
	}

	if (!options || options.length === 0) {
		const response = await requestInteraction({
			type: "multiline_input",
			id: `ask-user:${Date.now()}`,
			prompt: question,
			timeoutMs: DEFAULT_ASK_TIMEOUT_MS,
		});
		if (response.type === "multiline_input" && (response.skipped || response.timedOut)) {
			return buildSkippedResult(question, response.timedOut === true);
		}
		const answer = response.type === "multiline_input" ? response.value : undefined;
		if (answer === undefined) {
			return { content: [{ type: "text" as const, text: "User cancelled" }], details: { cancelled: true } };
		}
		return {
			content: [{ type: "text" as const, text: answer }],
			details: { answer, cancelled: false },
		};
	}

	const displayOptions = [...options];
	if (allowOther !== false) displayOptions.push(OTHER_OPTION);
	if (allowBack) displayOptions.push(BACK_OPTION);
	if (allowReview) displayOptions.push(REVIEW_OPTION);

	const selection = await requestInteraction({
		type: "select_one",
		id: `ask-user:select:${Date.now()}`,
		prompt: question,
		options: displayOptions,
		timeoutMs: DEFAULT_ASK_TIMEOUT_MS,
	});

	if (selection.type === "select_one" && (selection.skipped || selection.timedOut)) {
		return buildSkippedResult(question, selection.timedOut === true);
	}

	if (selection.type !== "select_one" || selection.selection === undefined) {
		return { content: [{ type: "text" as const, text: "User cancelled" }], details: { cancelled: true } };
	}

	if (selection.selection === BACK_OPTION) {
		return { content: [{ type: "text" as const, text: "BACK" }], details: { goBack: true, cancelled: false } };
	}

	if (selection.selection === REVIEW_OPTION) {
		return { content: [{ type: "text" as const, text: "REVIEW" }], details: { goReview: true, cancelled: false } };
	}

	if (selection.selection === OTHER_OPTION) {
		const response = await requestInteraction({
			type: "text_input",
			id: `ask-user:${Date.now()}`,
			prompt: `${question} (Other)`,
			placeholder,
			timeoutMs: DEFAULT_ASK_TIMEOUT_MS,
		});
		if (response.type === "text_input" && (response.skipped || response.timedOut)) {
			return buildSkippedResult(question, response.timedOut === true);
		}
		const customAnswer = response.type === "text_input" ? response.value : undefined;
		if (customAnswer === undefined) {
			return { content: [{ type: "text" as const, text: "User cancelled" }], details: { cancelled: true } };
		}
		return {
			content: [{ type: "text" as const, text: `Other: ${customAnswer}` }],
			details: { answer: customAnswer, isOther: true, cancelled: false },
		};
	}

	const selectedIndex = displayOptions.indexOf(selection.selection);
	return {
		content: [{ type: "text" as const, text: `${String.fromCharCode(65 + selectedIndex)}. ${selection.selection}` }],
		details: {
			answer: selection.selection,
			selectedIndex,
			isOther: false,
			cancelled: false,
		},
	};
}

export function createAskUserCapability() {
	const tools = [
		{
				name: "ask_user_multi",
				label: "Ask User",
				description:
					"Ask one or more questions with review and back navigation. Use this for all user questioning flows, including demonstrations that should actually ask the user instead of only describing the questionnaire. " +
					"When you decide to use this tool, invoke it immediately. Do not print explanatory preambles, numbered plans, or example JSON in chat before calling it. " +
					"For a generic demo such as '演示一下 ask 工具', '演示一下提问工具', or 'ask me', ask exactly one simple single-choice question with 3-5 explicit options so the user sees a selector instead of a free-text editor. Do not switch to an open-ended or multi-question flow unless the user explicitly asks for it. " +
					"Prefer the shortest valid shape. For a single question, use {\"question\":\"Choose a color\",\"options\":[\"Red\",\"Blue\",\"Green\"]}. " +
					"You may also use {\"prompt\":\"Choose a color\",\"options\":[...]} for compatibility. " +
					"For multiple questions, use `questions`. Question ids are optional and will be auto-generated.",
				parameters: AskUserMultiParamsSchema,
				async execute(toolCallIdOrArgs: any, maybeArgs?: any) {
					try {
						const args = typeof toolCallIdOrArgs === "string" && maybeArgs !== undefined
							? maybeArgs
							: toolCallIdOrArgs;
						const normalized = normalizeAskUserArgs(args);
						if ("error" in normalized) {
							return {
								content: [
									{
										type: "text" as const,
										text:
											`Error: ${normalized.error}. ` +
											"Use one of these shapes: " +
											'{"question":"Choose a color","options":["Red","Blue","Green"]} ' +
											'or {"prompt":"Choose a color","options":["Red","Blue","Green"]} ' +
											'or {"questions":[{"question":"Choose a color","options":["Red","Blue","Green"]},{"question":"Describe why"}],"allowReview":true}',
									},
								],
								isError: true,
							};
						}
						const { questions, allowReview } = normalized;
						const validationError = validateQuestions(questions);
						if (validationError) {
							return {
								content: [
									{
										type: "text" as const,
										text:
											`Error: ${validationError}. ` +
											"Use one of these shapes: " +
											'{"question":"Choose a color","options":["Red","Blue","Green"]} ' +
											'or {"prompt":"Choose a color","options":["Red","Blue","Green"]} ' +
											'or {"questions":["Choose a color|Red|Blue|Green","Describe why"],"allowReview":true}',
									},
								],
								isError: true,
							};
						}

						const answers: Record<string, any> = {};
						let currentIndex = 0;

						while (currentIndex < questions.length) {
							const q = questions[currentIndex];
							const result = await askSingleQuestion({
								question: `${currentIndex + 1}/${questions.length}: ${q.question}`,
								options: q.options,
								allowOther: q.allowOther,
								allowBack: currentIndex > 0,
								allowReview: allowReview && Object.keys(answers).length > 0,
								placeholder: q.placeholder,
							});

							if (result.details?.cancelled) {
								return { content: [{ type: "text" as const, text: "User cancelled" }], details: { cancelled: true } };
							}

							if (result.details?.goBack) {
								currentIndex = Math.max(0, currentIndex - 1);
								delete answers[questions[currentIndex].id];
								continue;
							}

							if (result.details?.goReview) {
								break;
							}

							answers[q.id] = {
								question: q.question,
								answer: result.details?.answer || result.content[0].text,
								...result.details,
							};
							currentIndex++;
						}

						if (allowReview && Object.keys(answers).length > 0) {
							while (true) {
								const reviewOptions = [
									CONFIRM_OPTION,
									...questions.map((q: any, i: number) => {
										const answer = answers[q.id]?.answer || "(not answered)";
										const displayAnswer = answer.length > 20 ? `${answer.substring(0, 20)}...` : answer;
										return `✏️ Q${i + 1}: ${displayAnswer}`;
									}),
									RESTART_OPTION,
								];

								const review = await requestInteraction({
									type: "select_one",
									id: `ask-user:review:${Date.now()}`,
									prompt: "☰ Review your answers (select to edit):",
									options: reviewOptions,
									timeoutMs: DEFAULT_ASK_TIMEOUT_MS,
								});

								if (review.type === "select_one" && (review.skipped || review.timedOut)) {
									break;
								}

								if (review.type !== "select_one" || review.selection === undefined) {
									return { content: [{ type: "text" as const, text: "User cancelled during review" }], details: { cancelled: true } };
								}

								const reviewIndex = reviewOptions.indexOf(review.selection);
								if (review.selection === CONFIRM_OPTION) {
									break;
								}
								if (review.selection === RESTART_OPTION) {
									Object.keys(answers).forEach((key) => delete answers[key]);
									currentIndex = 0;
									break;
								}

								const questionIndex = reviewIndex - 1;
								if (questionIndex < 0 || questionIndex >= questions.length) {
									continue;
								}
								const q = questions[questionIndex];
								const result = await askSingleQuestion({
									question: `✏️ Edit Q${questionIndex + 1}/${questions.length}: ${q.question}`,
									options: q.options,
									allowOther: q.allowOther,
									allowBack: questionIndex > 0,
									allowReview: true,
									placeholder: q.placeholder,
								});

								if (result.details?.cancelled) {
									return { content: [{ type: "text" as const, text: "User cancelled" }], details: { cancelled: true } };
								}

								if (result.details?.goBack && questionIndex > 0) {
									delete answers[q.id];
									currentIndex = questionIndex - 1;
									break;
								}

								if (result.details?.goReview) {
									continue;
								}

								answers[q.id] = {
									question: q.question,
									answer: result.details?.answer || result.content[0].text,
									...result.details,
								};
							}
						}

						const summary = Object.entries(answers)
							.map(([id, data]: [string, any]) => `${id}: ${data.answer}`)
							.join("\n");

						return {
							content: [{ type: "text" as const, text: summary }],
							details: { answers, cancelled: false },
						};
					} catch (error) {
						return buildUnsupportedResult(error);
					}
				},
		},
	];

	return {
		...defineSharedCapability({
			id: "ask-user",
			description: "Ask the user one or more questions through the shared interaction protocol.",
			tools,
			requiredInteractions: ["select_one", "confirm", "text_input", "multiline_input"],
			systemPromptAdditions: [
				"When the user asks you to ask questions, collect choices, or gather structured input, call `ask_user_multi` instead of describing the questions in plain text.",
				"When demonstrating `ask_user_multi`, call it immediately instead of first printing explanations, plans, or example JSON.",
				"When the user asks for a generic ask-tool demo, such as '演示一下 ask 工具', '演示一下提问工具', or 'ask me', ask exactly one simple single-choice question with explicit options so the interaction opens as a selector.",
				"For a single question, prefer the shortest valid argument shape such as `question` plus optional `options`.",
			],
		}),
		tools,
	};
}
