/**
 * HTTP utility using platform-abstracted HTTP client.
 * Supports both Node.js and PuerTS (Unity) environments.
 */

import { getHttpClient, detectPlatform } from "@pie/platform";
import type { HttpResponse, HttpRequestOptions } from "@pie/platform";

export type { HttpResponse, HttpRequestOptions } from "@pie/platform";

/**
 * Make an HTTP/HTTPS request using the platform's HTTP client.
 * Drop-in replacement for the subset of fetch() we use.
 */
export function httpRequest(url: string, options: HttpRequestOptions = {}): Promise<HttpResponse> {
	const client = getHttpClient();
	return client.request(url, options);
}

/**
 * Check if the current platform supports HTTP requests
 */
export function isHttpSupported(): boolean {
	const platform = detectPlatform();
	return platform === "node" || platform === "puerts";
}

/**
 * Legacy Node.js HTTP implementation (for reference and fallback)
 * This is kept for compatibility but delegates to platform implementation
 */
export async function nodeHttpRequest(url: string, options: HttpRequestOptions = {}): Promise<HttpResponse> {
	// Use Node.js native modules directly
	const _require = (globalThis as any).require || require;
	const https = _require("https");
	const http = _require("http");
	const { URL } = _require("url");

	return new Promise((resolve, reject) => {
		const parsedUrl = new URL(url);
		const isHttps = parsedUrl.protocol === "https:";
		const lib = isHttps ? https : http;

		const requestOptions = {
			hostname: parsedUrl.hostname,
			port: parsedUrl.port || (isHttps ? 443 : 80),
			path: parsedUrl.pathname + parsedUrl.search,
			method: options.method || "GET",
			headers: options.headers || {},
		};

		const req = lib.request(requestOptions, (res: any) => {
			const status = res.statusCode || 0;
			const responseHeaders: Record<string, string> = {};
			for (const [key, value] of Object.entries(res.headers)) {
				if (value) responseHeaders[key] = Array.isArray(value) ? value.join(", ") : String(value);
			}

			const response: HttpResponse = {
				status,
				statusText: res.statusMessage || "",
				ok: status >= 200 && status < 300,
				headers: responseHeaders,

				text(): Promise<string> {
					return new Promise((resolveText, rejectText) => {
						const chunks: Buffer[] = [];
						res.on("data", (chunk: Buffer) => chunks.push(chunk));
						res.on("end", () => resolveText(Buffer.concat(chunks).toString("utf-8")));
						res.on("error", rejectText);
					});
				},

				async json(): Promise<any> {
					const text = await this.text();
					return JSON.parse(text);
				},

				async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
					let buffer = "";

					if (signal) {
						signal.addEventListener("abort", () => {
							res.destroy();
						}, { once: true });
					}

					const lineQueue: string[] = [];
					let done = false;
					let error: Error | null = null;
					let waiting: ((value: void) => void) | null = null;

					res.on("data", (chunk: Buffer) => {
						buffer += chunk.toString("utf-8");
						const lines = buffer.split("\n");
						buffer = lines.pop() || "";
						for (const line of lines) {
							lineQueue.push(line);
						}
						if (waiting) {
							const w = waiting;
							waiting = null;
							w();
						}
					});

					res.on("end", () => {
						if (buffer.length > 0) {
							lineQueue.push(buffer);
							buffer = "";
						}
						done = true;
						if (waiting) {
							const w = waiting;
							waiting = null;
							w();
						}
					});

					res.on("error", (e: Error) => {
						error = e;
						done = true;
						if (waiting) {
							const w = waiting;
							waiting = null;
							w();
						}
					});

					while (true) {
						while (lineQueue.length > 0) {
							yield lineQueue.shift()!;
						}

						if (done) {
							if (error) throw error;
							return;
						}

						await new Promise<void>((r) => {
							waiting = r;
						});
					}
				},
			};

			resolve(response);
		});

		req.on("error", (e: Error) => {
			reject(e);
		});

		if (options.signal) {
			options.signal.addEventListener("abort", () => {
				req.destroy(new Error("Request was aborted"));
			}, { once: true });
		}

		if (options.body) {
			req.write(options.body);
		}
		req.end();
	});
}
