/**
 * API provider registry
 */

import type {
	Api,
	AssistantMessageStream,
	Context,
	Model,
	SimpleStreamOptions,
	StreamFunction,
	StreamOptions,
} from "./types.js";

export type ApiStreamFunction = (
	model: Model<Api>,
	context: Context,
	options?: StreamOptions,
) => AssistantMessageStream;

export type ApiStreamSimpleFunction = (
	model: Model<Api>,
	context: Context,
	options?: SimpleStreamOptions,
) => AssistantMessageStream;

export interface ApiProvider<TApi extends Api = Api, TOptions extends StreamOptions = StreamOptions> {
	api: TApi;
	stream: StreamFunction<TApi, TOptions>;
	streamSimple: StreamFunction<TApi, SimpleStreamOptions>;
}

interface ApiProviderInternal {
	api: Api;
	stream: ApiStreamFunction;
	streamSimple: ApiStreamSimpleFunction;
}

const apiProviderRegistry = new Map<string, ApiProviderInternal>();

export function registerApiProvider<TApi extends Api, TOptions extends StreamOptions>(
	provider: ApiProvider<TApi, TOptions>,
): void {
	apiProviderRegistry.set(provider.api, {
		api: provider.api,
		stream: (model, context, options) => provider.stream(model as Model<TApi>, context, options as TOptions),
		streamSimple: (model, context, options) =>
			provider.streamSimple(model as Model<TApi>, context, options),
	});
}

export function getApiProvider(api: Api): ApiProviderInternal | undefined {
	return apiProviderRegistry.get(api);
}

export function getApiProviders(): ApiProviderInternal[] {
	return Array.from(apiProviderRegistry.values());
}

export function clearApiProviders(): void {
	apiProviderRegistry.clear();
}
