import type { AgentHooks, AgentTool } from "@pie/agent-core";
import { Type, type TSchema } from "@sinclair/typebox";
import type {
  RuntimeExtensionApi,
  RuntimeExtensionContext,
  RuntimeExtensionDefinition,
  RuntimeExtensionHostContext,
} from "./types.js";

type BeforeToolCallHook = NonNullable<AgentHooks["beforeToolCall"]>;
type AfterToolCallHook = NonNullable<AgentHooks["afterToolCall"]>;
type OnErrorHook = NonNullable<AgentHooks["onError"]>;

const typeBoxKind = Symbol.for("TypeBox.Kind");

function isTypeBoxSchema(value: unknown): value is TSchema {
  return !!value && typeof value === "object" && typeBoxKind in (value as Record<PropertyKey, unknown>);
}

function convertJsonSchemaToTypeBox(schema: any): TSchema {
  if (!schema || typeof schema !== "object") {
    throw new Error("Tool parameters must be a TypeBox schema or a JSON schema object.");
  }

  if (isTypeBoxSchema(schema)) {
    return schema;
  }

  const description = typeof schema.description === "string" ? schema.description : undefined;
  const options = description ? { description } : undefined;

  switch (schema.type) {
    case "string":
      return Type.String(options);
    case "number":
      return Type.Number(options);
    case "integer":
      return Type.Integer(options);
    case "boolean":
      return Type.Boolean(options);
    case "null":
      return Type.Null(options);
    case "array":
      return Type.Array(convertJsonSchemaToTypeBox(schema.items ?? { type: "string" }), options);
    case "object": {
      const properties = schema.properties ?? {};
      const required = new Set<string>(Array.isArray(schema.required) ? schema.required : []);
      const converted: Record<string, TSchema> = {};

      for (const [key, value] of Object.entries(properties)) {
        const child = convertJsonSchemaToTypeBox(value);
        converted[key] = required.has(key) ? child : Type.Optional(child);
      }

      return Type.Object(converted, options);
    }
    default:
      throw new Error(`Unsupported JSON schema type for extension tool: ${String(schema.type ?? "unknown")}`);
  }
}

function extensionLog(context: RuntimeExtensionHostContext, message: string) {
  context.log(`[extension] ${message}`);
}

function tryParseHostResult(raw: unknown): any {
  if (typeof raw !== "string") {
    return raw;
  }

  const trimmed = raw.trim();
  if (!trimmed) return "";

  const looksLikeJson =
    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
    (trimmed.startsWith("[") && trimmed.endsWith("]")) ||
    trimmed === "null" ||
    trimmed === "true" ||
    trimmed === "false" ||
    /^-?\d+(\.\d+)?$/.test(trimmed);

  if (!looksLikeJson) {
    return raw;
  }

  try {
    return JSON.parse(trimmed);
  } catch {
    return raw;
  }
}

export class RuntimeExtensionRegistry {
  private extensionTools: AgentTool<any>[] = [];
  private beforeToolCallHooks: BeforeToolCallHook[] = [];
  private afterToolCallHooks: AfterToolCallHook[] = [];
  private onErrorHooks: OnErrorHook[] = [];
  private systemPromptPatches: string[] = [];
  private loadedExtensions: string[] = [];

  reset(): void {
    this.extensionTools.length = 0;
    this.beforeToolCallHooks.length = 0;
    this.afterToolCallHooks.length = 0;
    this.onErrorHooks.length = 0;
    this.systemPromptPatches.length = 0;
    this.loadedExtensions.length = 0;
  }

  getTools(): AgentTool<any>[] {
    return this.extensionTools.slice();
  }

  getLoadedExtensions(): string[] {
    return this.loadedExtensions.slice();
  }

  getSystemPromptPatches(): string[] {
    return this.systemPromptPatches.slice();
  }

  buildHooks(): AgentHooks | undefined {
    if (
      this.beforeToolCallHooks.length === 0 &&
      this.afterToolCallHooks.length === 0 &&
      this.onErrorHooks.length === 0
    ) {
      return undefined;
    }

    return {
      beforeToolCall: this.beforeToolCallHooks.length === 0
        ? undefined
        : async (toolName, args) => {
            for (const hook of this.beforeToolCallHooks) {
              const result = await hook(toolName, args);
              if (result?.block) {
                return result;
              }
            }
            return undefined;
          },
      afterToolCall: this.afterToolCallHooks.length === 0
        ? undefined
        : async (toolName, args, result, isError) => {
            for (const hook of this.afterToolCallHooks) {
              await hook(toolName, args, result, isError);
            }
          },
      onError: this.onErrorHooks.length === 0
        ? undefined
        : (error, ctx) => {
            for (const hook of this.onErrorHooks) {
              hook(error, ctx);
            }
          },
    };
  }

  createContext<TExtra extends object = {}>(
    definition: RuntimeExtensionDefinition,
    context: RuntimeExtensionHostContext & TExtra,
  ): RuntimeExtensionContext<TExtra> {
    return {
      manifest: definition.manifest,
      dir: definition.dir,
      config: definition.config ?? {},
      ...context,
      registerTool: (tool) => {
        const normalizedTool = {
          ...tool,
          parameters: convertJsonSchemaToTypeBox(tool.parameters),
        };
        this.extensionTools.push(normalizedTool);
        extensionLog(context, `registered tool: ${tool.name}`);
      },
      registerBeforeToolCall: (hook) => {
        this.beforeToolCallHooks.push(hook);
        extensionLog(context, "registered beforeToolCall hook");
      },
      registerAfterToolCall: (hook) => {
        this.afterToolCallHooks.push(hook);
        extensionLog(context, "registered afterToolCall hook");
      },
      registerOnError: (hook) => {
        this.onErrorHooks.push(hook);
        extensionLog(context, "registered onError hook");
      },
      appendSystemPrompt: (text) => {
        const trimmed = (text ?? "").trim();
        if (!trimmed) return;
        this.systemPromptPatches.push(trimmed);
        extensionLog(context, "appended system prompt patch");
      },
      async callHost(name, args) {
        if (!context.callHost) {
          throw new Error(`Host bridge is unavailable for extension call: ${name}`);
        }
        const raw = await context.callHost(name, args);
        return tryParseHostResult(raw) as any;
      },
    };
  }

  createApi(context: RuntimeExtensionHostContext): RuntimeExtensionApi {
    return this.createContext(
      {
        manifest: { name: "runtime-extension", version: "0.0.0", main: "index.js" },
        dir: ".",
        config: {},
      },
      context,
    );
  }

  registerLoadedExtension(path: string): void {
    this.loadedExtensions.push(path);
  }
}

export function createRuntimeExtensionRegistry(): RuntimeExtensionRegistry {
  return new RuntimeExtensionRegistry();
}
