/**
 * Skill parser - parses Markdown skill files with YAML frontmatter
 */

import type { SkillFrontmatter, ParsedSkill, Skill } from "./types.js";

/**
 * Parse YAML frontmatter from markdown content
 */
function parseFrontmatter(yaml: string): SkillFrontmatter {
	const result: SkillFrontmatter = {};
	const lines = yaml.split("\n");

	for (const line of lines) {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith("#")) continue;

		const colonIndex = trimmed.indexOf(":");
		if (colonIndex === -1) continue;

		const key = trimmed.slice(0, colonIndex).trim();
		let value: unknown = trimmed.slice(colonIndex + 1).trim();

		// Remove quotes if present
		if (typeof value === "string") {
			if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
				value = value.slice(1, -1);
			}
		}

		// Parse arrays [item1, item2]
		if (typeof value === "string" && value.startsWith("[") && value.endsWith("]")) {
			const items = value
				.slice(1, -1)
				.split(",")
				.map((s) => s.trim())
				.filter((s) => s.length > 0)
				.map((s) => s.replace(/^["']|["']$/g, ""));
			value = items;
		}

		switch (key) {
			case "name":
				result.name = String(value);
				break;
			case "displayName":
				result.displayName = String(value);
				break;
			case "description":
				result.description = String(value);
				break;
			case "tools":
				if (Array.isArray(value)) {
					result.tools = value;
				} else if (typeof value === "string") {
					result.tools = value.split(",").map((s) => s.trim());
				}
				break;
			case "tags":
				if (Array.isArray(value)) {
					result.tags = value;
				} else if (typeof value === "string") {
					result.tags = value.split(",").map((s) => s.trim());
				}
				break;
			case "author":
				result.author = String(value);
				break;
			case "version":
				result.version = String(value);
				break;
		}
	}

	return result;
}

/**
 * Parse a skill markdown file content
 */
export function parseSkillFile(content: string, filePath?: string): ParsedSkill {
	// Check for frontmatter
	const frontmatterMatch = content.match(/^---\s*\n([\s\S]*?)\n---\s*\n([\s\S]*)$/);

	if (frontmatterMatch) {
		const frontmatter = parseFrontmatter(frontmatterMatch[1]);
		const skillContent = frontmatterMatch[2].trim();
		return { frontmatter, content: skillContent };
	}

	// No frontmatter - treat entire content as the prompt
	return {
		frontmatter: {},
		content: content.trim(),
	};
}

/**
 * Create a Skill object from parsed content
 */
export function createSkill(parsed: ParsedSkill, fileName: string, filePath?: string): Skill {
	const { frontmatter, content } = parsed;

	// Extract name from frontmatter or filename (remove .md extension)
	const name = frontmatter.name || fileName.replace(/\.md$/i, "");

	// Extract display name
	const displayName = frontmatter.displayName || name;

	// Extract description (first non-empty line if not in frontmatter)
	let description = frontmatter.description || "";
	if (!description && content) {
		const firstLine = content.split("\n").find((line) => line.trim());
		if (firstLine) {
			description = firstLine.trim().slice(0, 200);
		}
	}

	return {
		name,
		displayName,
		description,
		prompt: content,
		allowedTools: Array.isArray(frontmatter.tools) ? frontmatter.tools : typeof frontmatter.tools === 'string' ? [frontmatter.tools] : undefined,
		tags: Array.isArray(frontmatter.tags) ? frontmatter.tags : typeof frontmatter.tags === 'string' ? [frontmatter.tags] : undefined,
		author: frontmatter.author,
		version: frontmatter.version,
		filePath,
	};
}

/**
 * Parse a complete skill file
 */
export function parseSkill(content: string, fileName: string, filePath?: string): Skill {
	const parsed = parseSkillFile(content, filePath);
	return createSkill(parsed, fileName, filePath);
}
