type DevRpcBridge = {
  devRpc?: {
    call(method: string, args?: Record<string, unknown>): unknown;
  };
  host?: {
    call(fullNameOrNamespace: string, nameOrArgs?: string | unknown, maybeArgs?: unknown): unknown;
    hasCapability?(name: string): boolean;
    listCapabilities?(namespace?: string): Array<{ name?: string; namespace?: string }>;
  };
  log?: (level: string, message: string) => void;
  isEditor?: boolean;
};

type ScriptRunStatus = "running" | "completed" | "failed" | "cancelled";
type ScriptIterator = Iterator<unknown, unknown, unknown>;
type UnityScriptHostGlobal = typeof globalThis & {
  __pieUnityScriptRuns?: Map<string, ScriptRunTask>;
  __pieUnityScriptHost?: {
    invoke(method: string, argsJson: string): string;
    tick(): void;
  };
  __pieUnityRuntimeBridge?: {
    has(path: string): boolean;
    get(path: string): unknown;
    members(path?: string): unknown[];
    call(path: string, argsJson: string): unknown;
  };
};

type ScriptRunTask = {
  id: string;
  mode: string;
  name: string;
  iterator: ScriptIterator | null;
  status: ScriptRunStatus;
  result: unknown;
  errorCode: string;
  errorMessage: string;
  logs: string[];
  createdRefs: unknown[];
  frames: number;
  startMs: number;
  updatedAt: string;
  totalTimeoutMs: number;
  perStepTimeoutMs: number;
  maxFrames: number;
  waitFrames: number;
  waitUntilMs: number;
  stepDeadlineMs: number;
  hasPendingInput: boolean;
  pendingInput: unknown;
  waiters: Array<(result: ReturnType<typeof buildStatus>) => void>;
};

type ScriptRunRequest = {
  name?: string;
  script?: string;
  entry?: string;
  args?: Record<string, unknown>;
  totalTimeoutMs?: number;
  perStepTimeoutMs?: number;
  maxFrames?: number;
};

const DEFAULT_TOTAL_TIMEOUT_MS = 30_000;
const DEFAULT_PER_STEP_TIMEOUT_MS = 100;
const DEFAULT_MAX_FRAMES = 1_800;
const MAX_LOG_LINES = 200;
const STEP_TIMEOUT_ERROR_CODE = "STEP_TIMEOUT";

let installedBridge: DevRpcBridge | null = null;

function getRunStore(): Map<string, ScriptRunTask> {
  const key = "__pieUnityScriptRuns";
  const unityGlobal = globalThis as UnityScriptHostGlobal;
  const existing = unityGlobal[key];
  if (!existing || typeof existing.get !== "function" || typeof existing.set !== "function") {
    const created = new Map<string, ScriptRunTask>();
    unityGlobal[key] = created;
    return created;
  }
  return existing;
}

function nowIso(): string {
  return new Date().toISOString();
}

function createRunId(): string {
  return `unity_script_run_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}

function toPositiveNumber(value: unknown, fallback: number): number {
  const numeric = Number(value);
  return Number.isFinite(numeric) && numeric > 0 ? numeric : fallback;
}

function summarizeValue(value: unknown): string {
  if (value === null) return "null";
  if (value === undefined) return "undefined";
  if (Array.isArray(value)) return `Array(${value.length})`;
  if (typeof value === "object") {
    const keys = Object.keys(value);
    return `Object(${keys.slice(0, 6).join(", ")})`;
  }
  return String(value);
}

function toSerializable(value: unknown): unknown {
  if (value === null || value === undefined) return value ?? null;
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") return value;
  if (Array.isArray(value)) return value.map((item) => toSerializable(item));
  if (typeof value === "object") {
    try {
      return JSON.parse(JSON.stringify(value));
    } catch {
      return { text: String(value) };
    }
  }
  return String(value);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function createScriptHostError(code: string, message: string): Error & { code: string } {
  const error = new Error(message) as Error & { code: string };
  error.code = code;
  return error;
}

function extractRefs(value: unknown): unknown[] {
  if (!isRecord(value)) return [];
  if (Array.isArray(value.results)) return value.results;
  if (Array.isArray(value.createdRefs)) return value.createdRefs;
  if (value.target) return [value.target];
  return [];
}

function normalizeModuleSource(source: string): string {
  return String(source || "")
    .replace(/\bexport\s+default\s+function\s*\*/g, "function* run")
    .replace(/\bexport\s+default\s+function/g, "function run")
    .replace(/\bexport\s+/g, "");
}

function injectStepGuards(source: string): string {
  // This guard is deliberately source-level and host-independent. pie-unity
  // uses PuerTS 2.2.2 JsEnv + BackendType.V8 and does not depend on native V8
  // termination as a safety boundary.
  //
  // Coverage target: the common loop shapes we expect agent-authored scripts to
  // use in practice, including braced and single-statement while/for/do loops,
  // plus for-of / for-in forms.
  return String(source || "")
    .replace(/\b(for|while)\s*\(([^)]*)\)\s*\{/g, (_match, keyword, header) => `${keyword} (${header}) { __pieStepGuard(); `)
    .replace(/\bdo\s*\{/g, "do { __pieStepGuard(); ")
    .replace(/\b(for|while)\s*\(([^)]*)\)\s*([^\s{][\s\S]*?;)/g, (_match, keyword, header, statement) => `${keyword} (${header}) { __pieStepGuard(); ${statement} }`)
    .replace(/\bdo\s*([^\s{][\s\S]*?;)\s*while\s*\(([^)]*)\)/g, (_match, statement, header) => `do { __pieStepGuard(); ${statement} } while (${header})`);
}

function isStepTimeoutError(error: unknown): boolean {
  return isRecord(error) && (error.code === STEP_TIMEOUT_ERROR_CODE || error.name === "PieStepTimeoutError");
}

function buildStatus(task: ScriptRunTask) {
  const done = task.status === "completed" || task.status === "failed" || task.status === "cancelled";
  const hardStepTermination = false;
  return {
    taskId: task.id,
    name: task.name,
    mode: task.mode,
    status: task.status,
    done,
    ok: task.status === "completed",
    summary: task.status === "completed" ? summarizeValue(task.result) : task.errorMessage || task.status,
    result: task.status === "completed" ? toSerializable(task.result) : null,
    errorCode: task.errorCode,
    errorMessage: task.errorMessage,
    logs: task.logs.slice(-MAX_LOG_LINES),
    refs: toSerializable(task.createdRefs || []),
    frames: task.frames,
    durationMs: Math.max(0, Date.now() - task.startMs),
    totalTimeoutMs: task.totalTimeoutMs,
    perStepTimeoutMs: task.perStepTimeoutMs,
    maxFrames: task.maxFrames,
    updatedAt: task.updatedAt,
    protection: {
      model: "cooperative-yield",
      hardStepTermination,
      note: "The task is frame-scheduled and guarded by a script-level step deadline on common loop shapes. pie-unity uses PuerTS 2.2.2 JsEnv + BackendType.V8 and does not rely on native V8 termination.",
    },
  };
}

function notifyWaiters(task: ScriptRunTask) {
  if (task.waiters.length === 0) return;
  const result = buildStatus(task);
  const waiters = task.waiters.splice(0, task.waiters.length);
  for (const waiter of waiters) {
    try {
      waiter(result);
    } catch {
      // Ignore waiter failures; the task is already terminal.
    }
  }
}

function completeTask(task: ScriptRunTask, result: unknown) {
  if (task.status !== "running") return;
  task.status = "completed";
  task.result = result;
  task.updatedAt = nowIso();
  notifyWaiters(task);
}

function failTask(task: ScriptRunTask, code: string, message: string) {
  if (task.status !== "running") return;
  task.status = "failed";
  task.errorCode = code;
  task.errorMessage = message;
  task.updatedAt = nowIso();
  notifyWaiters(task);
}

function cancelTask(task: ScriptRunTask, reason: string) {
  if (task.status !== "running") return;
  task.status = "cancelled";
  task.errorCode = "CANCELLED";
  task.errorMessage = reason || "Unity script run cancelled.";
  task.updatedAt = nowIso();
  notifyWaiters(task);
}

function getUnityHostApi(bridge: DevRpcBridge, task: ScriptRunTask) {
  const call = (method: string, args: Record<string, unknown> = {}) => {
    if (!bridge.devRpc?.call) {
      throw new Error("bridge.devRpc is not available.");
    }
    const result = bridge.devRpc.call(method, args);
    const refs = extractRefs(result);
    if (refs.length > 0) {
      task.createdRefs = refs;
    }
    return result;
  };

  return {
    query(args: Record<string, unknown> = {}) {
      return call("unity_scene_query", args);
    },
    inspect(args: Record<string, unknown> = {}) {
      return call("unity_scene_object_inspect", args);
    },
    edit(args: Record<string, unknown> = {}) {
      return call("unity_scene_object_edit", args);
    },
    refresh() {
      return call("unity_refresh", {});
    },
  };
}

function getRegisteredHostApi(bridge: DevRpcBridge) {
  const call = (fullNameOrNamespace: string, nameOrArgs?: string | unknown, maybeArgs?: unknown) => {
    if (!bridge.host?.call) {
      throw new Error("Runtime host bridge is not available.");
    }
    return bridge.host.call(fullNameOrNamespace, nameOrArgs as string | unknown, maybeArgs);
  };

  const resolveCapabilityName = (namespace: string, name: string) => {
    const normalizedNamespace = String(namespace || "").trim();
    const normalizedName = String(name || "").trim();
    if (!normalizedNamespace) {
      throw new Error("Runtime host namespace is required.");
    }
    if (!normalizedName) {
      throw new Error("Runtime host capability name is required.");
    }
    if (bridge.host?.hasCapability?.(normalizedName)) {
      return normalizedName;
    }
    const inferred = `${normalizedNamespace}_${normalizedName}`;
    if (bridge.host?.hasCapability?.(inferred)) {
      return inferred;
    }

    const available = bridge.host?.listCapabilities?.(normalizedNamespace) ?? [];
    const names = available
      .map((item) => String(item?.name || "").trim())
      .filter(Boolean)
      .join(", ");
    throw new Error(`Runtime host capability not found: ${normalizedNamespace}.${normalizedName}${names ? ` (available: ${names})` : ""}`);
  };

  const byNamespace = (namespace: string) => ({
    call(name: string, args: Record<string, unknown> = {}) {
      return call(namespace, resolveCapabilityName(namespace, name), args);
    },
    list() {
      return bridge.host?.listCapabilities?.(String(namespace || "").trim()) ?? [];
    },
  });

  return {
    call(fullName: string, args: Record<string, unknown> = {}) {
      const normalized = String(fullName || "").trim();
      if (!normalized) {
        throw new Error("Runtime host capability name is required.");
      }
      return call(normalized, args);
    },
    hasCapability(name: string) {
      return bridge.host?.hasCapability?.(name) === true;
    },
    list(namespace?: string) {
      return bridge.host?.listCapabilities?.(namespace) ?? [];
    },
    namespace(namespace: string) {
      return byNamespace(namespace);
    },
  };
}

function parseRuntimePath(path: string): string[] {
  const normalized = String(path || "").trim();
  if (!normalized) {
    throw createScriptHostError("RUNTIME_PATH_NOT_FOUND", "Runtime path is required.");
  }

  const parts = normalized
    .split(".")
    .map((part) => String(part || "").trim())
    .filter(Boolean);
  if (parts.length === 0) {
    throw createScriptHostError("RUNTIME_PATH_NOT_FOUND", "Runtime path is required.");
  }
  return parts;
}

function collectRuntimeMemberNames(value: unknown): string[] {
  if ((value === null || value === undefined) || (typeof value !== "object" && typeof value !== "function")) {
    return [];
  }

  const seen = new Set<string>();
  const names: string[] = [];
  let current: object | null = value as object;
  let depth = 0;
  while (current && depth < 3) {
    for (const name of Object.getOwnPropertyNames(current)) {
      if (!name || name === "constructor" || seen.has(name)) continue;
      seen.add(name);
      names.push(name);
    }
    current = Object.getPrototypeOf(current);
    depth += 1;
  }

  names.sort((left, right) => left.localeCompare(right));
  return names;
}

function safeSerializeRuntimeValue(value: unknown): unknown {
  if (value === null || value === undefined) return value ?? null;
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") return value;
  if (Array.isArray(value)) return value.map((item) => safeSerializeRuntimeValue(item));
  if (typeof value === "function") {
    return {
      type: "function",
      summary: String(value.name || "(anonymous)"),
    };
  }
  if (typeof value === "object") {
    try {
      return JSON.parse(JSON.stringify(value));
    } catch {
      return {
        type: "object",
        summary: summarizeValue(value),
        members: collectRuntimeMemberNames(value).slice(0, 20),
      };
    }
  }
  return String(value);
}

function describeRuntimeValue(value: unknown) {
  const type = value === null ? "null" : Array.isArray(value) ? "array" : typeof value;
  return {
    type,
    callable: typeof value === "function",
    summary: summarizeValue(value),
    value: safeSerializeRuntimeValue(value),
  };
}

function resolveRuntimePath(path: string) {
  const parts = parseRuntimePath(path);
  let parent: unknown = globalThis;
  let value: unknown = globalThis;
  const traversed: string[] = [];

  for (const segment of parts) {
    if ((value === null || value === undefined) || (typeof value !== "object" && typeof value !== "function")) {
      throw createScriptHostError("RUNTIME_PATH_NOT_FOUND", `Runtime path not found: ${parts.join(".")}`);
    }

    parent = value;
    traversed.push(segment);
    value = (value as Record<string, unknown>)[segment];
    if (value === undefined) {
      throw createScriptHostError("RUNTIME_PATH_NOT_FOUND", `Runtime path not found: ${traversed.join(".")}`);
    }
  }

  return {
    path: parts.join("."),
    parent,
    value,
  };
}

function parseRuntimeCallArgs(args: unknown): unknown[] {
  if (Array.isArray(args)) return args;
  if (args === null || args === undefined) return [];
  throw createScriptHostError("RUNTIME_CALL_FAILED", "ctx.runtime.call(path, argsArray) requires an array of arguments.");
}

function installRuntimeAccessBridge() {
  const unityGlobal = globalThis as UnityScriptHostGlobal;
  unityGlobal.__pieUnityRuntimeBridge = {
    has(path: string): boolean {
      try {
        resolveRuntimePath(path);
        return true;
      } catch {
        return false;
      }
    },
    get(path: string): unknown {
      const resolved = resolveRuntimePath(path);
      return {
        path: resolved.path,
        ...describeRuntimeValue(resolved.value),
      };
    },
    members(path = ""): unknown[] {
      const target = String(path || "").trim() ? resolveRuntimePath(path).value : globalThis;
      return collectRuntimeMemberNames(target).map((name) => {
        let value: unknown;
        try {
          value = (target as Record<string, unknown>)[name];
        } catch {
          value = undefined;
        }
        return {
          name,
          ...describeRuntimeValue(value),
        };
      });
    },
    call(path: string, argsJson: string): unknown {
      const resolved = resolveRuntimePath(path);
      if (typeof resolved.value !== "function") {
        throw createScriptHostError("RUNTIME_MEMBER_NOT_CALLABLE", `Runtime member is not callable: ${resolved.path}`);
      }

      const rawArgs = argsJson ? JSON.parse(String(argsJson)) : [];
      const args = parseRuntimeCallArgs(rawArgs);
      try {
        const result = (resolved.value as (...items: unknown[]) => unknown).apply(resolved.parent, args);
        if (result && typeof (result as Promise<unknown>).then === "function") {
          throw createScriptHostError("RUNTIME_CALL_FAILED", `Runtime path returned a Promise and cannot be awaited through ctx.runtime.call: ${resolved.path}`);
        }
        return safeSerializeRuntimeValue(result);
      } catch (error: unknown) {
        if (isRecord(error) && typeof error.code === "string") {
          throw error;
        }
        throw createScriptHostError("RUNTIME_CALL_FAILED", error instanceof Error ? error.message : String(error));
      }
    },
  };
}

function getRuntimeApi() {
  const bridge = (globalThis as UnityScriptHostGlobal).__pieUnityRuntimeBridge;
  if (!bridge) {
    throw createScriptHostError("RUNTIME_BRIDGE_NOT_READY", "Runtime bridge is not ready.");
  }

  return {
    has(path: string) {
      return bridge.has(path);
    },
    get(path: string) {
      return bridge.get(path);
    },
    members(path = "") {
      return bridge.members(path);
    },
    call(path: string, args: unknown[] = []) {
      return bridge.call(path, JSON.stringify(parseRuntimeCallArgs(args)));
    },
  };
}

function createTaskContext(bridge: DevRpcBridge, task: ScriptRunTask, args: Record<string, unknown>) {
  const unity = getUnityHostApi(bridge, task);
  const runtimeHost = getRegisteredHostApi(bridge);
  const hostSelector = ((namespace?: string) => (namespace ? runtimeHost.namespace(namespace) : runtimeHost)) as
    ((namespace?: string) => ReturnType<typeof runtimeHost.namespace> | typeof runtimeHost) & {
      call(fullName: string, hostArgs?: Record<string, unknown>): unknown;
      hasCapability(name: string): boolean;
      list(namespace?: string): Array<{ name?: string; namespace?: string }>;
    };
  hostSelector.call = runtimeHost.call;
  hostSelector.hasCapability = runtimeHost.hasCapability;
  hostSelector.list = runtimeHost.list;
  return {
    args,
    log(...parts: unknown[]) {
      const text = parts.map((part) => String(part)).join(" ");
      task.logs.push(text);
      if (task.logs.length > MAX_LOG_LINES) task.logs.splice(0, task.logs.length - MAX_LOG_LINES);
      bridge.log?.("info", `[unity.script.run:${task.id}] ${text}`);
      return text;
    },
    nextFrame() {
      return { type: "nextFrame" };
    },
    waitFrames(frames: number) {
      return { type: "waitFrames", frames: Math.max(1, Math.floor(Number(frames) || 1)) };
    },
    waitSeconds(seconds: number) {
      return { type: "waitSeconds", seconds: Math.max(0, Number(seconds) || 0) };
    },
    query: unity.query,
    inspect: unity.inspect,
    edit: unity.edit,
    refresh: unity.refresh,
    host: hostSelector,
    runtime: getRuntimeApi(),
    get frame() {
      return task.frames;
    },
    get elapsedMs() {
      return Date.now() - task.startMs;
    },
  };
}

function compileRunIterator(script: string, entryName: string, ctx: unknown, args: Record<string, unknown>, task: ScriptRunTask): ScriptIterator {
  const normalized = injectStepGuards(normalizeModuleSource(script));
  const module = { exports: {} as Record<string, unknown> };
  const exports = module.exports;
  const stepGuard = () => {
    if (task.stepDeadlineMs > 0 && Date.now() > task.stepDeadlineMs) {
      const error = new Error(`Unity script step exceeded ${task.perStepTimeoutMs}ms.`) as Error & { code?: string };
      error.name = "PieStepTimeoutError";
      error.code = STEP_TIMEOUT_ERROR_CODE;
      throw error;
    }
  };
  const executor = new Function(
    "module",
    "exports",
    "console",
    "__pieStepGuard",
    `"use strict";\nconst CS = undefined;\nconst puer = undefined;\n${normalized}\nreturn { run: (typeof run !== "undefined" ? run : (module.exports.run || exports.run)), default: (module.exports.default || exports.default) };`,
  );
  const exported = executor(module, exports, console, stepGuard) as Record<string, unknown> | null | undefined;
  const entry = exported?.[entryName] || (entryName === "run" ? exported?.default : null);
  if (typeof entry !== "function") {
    throw new Error(`Script must define export function* ${entryName}(ctx, args).`);
  }
  const iterator = (entry as (ctx: unknown, args: Record<string, unknown>) => unknown)(ctx, args);
  if (!isRecord(iterator) || typeof iterator.next !== "function") {
    throw new Error(`Script entry ${entryName} must be a generator function. Use export function* ${entryName}(ctx, args) and yield ctx.nextFrame() for long work.`);
  }
  return iterator as unknown as ScriptIterator;
}

function interpretYield(task: ScriptRunTask, value: unknown) {
  task.waitFrames = 1;
  task.waitUntilMs = 0;
  if (!isRecord(value)) return;
  if (value.type === "waitFrames") {
    task.waitFrames = Math.max(1, Math.floor(Number(value.frames) || 1));
    return;
  }
  if (value.type === "waitSeconds") {
    task.waitFrames = 0;
    task.waitUntilMs = Date.now() + Math.max(0, Number(value.seconds) || 0) * 1000;
    return;
  }

  // Host-call helpers such as `ctx.edit(...)` return structured values. When
  // authors write `const result = yield ctx.edit(...)`, feed that yielded
  // value back into the generator on the next step instead of treating it as
  // an opaque one-frame wait.
  task.waitFrames = 0;
  task.hasPendingInput = true;
  task.pendingInput = value;
}

function stepTask(task: ScriptRunTask) {
  if (task.status !== "running") return;

  const now = Date.now();
  if (now - task.startMs > task.totalTimeoutMs) {
    failTask(task, "TOTAL_TIMEOUT", `Unity script run exceeded ${task.totalTimeoutMs}ms.`);
    return;
  }
  if (task.frames >= task.maxFrames) {
    failTask(task, "MAX_FRAMES", `Unity script run exceeded ${task.maxFrames} frames.`);
    return;
  }
  if (task.waitUntilMs > 0 && now < task.waitUntilMs) {
    return;
  }
  if (task.waitFrames > 0) {
    task.waitFrames -= 1;
    return;
  }

  task.frames += 1;
  const stepStart = Date.now();
  try {
    const iterator = task.iterator;
    if (!iterator) {
      failTask(task, "SCRIPT_ERROR", "Unity script iterator was not initialized.");
      return;
    }
    task.stepDeadlineMs = stepStart + task.perStepTimeoutMs;
    const input = task.hasPendingInput ? task.pendingInput : undefined;
    task.hasPendingInput = false;
    task.pendingInput = null;
    const next = iterator.next(input);
    const elapsed = Date.now() - stepStart;
    task.updatedAt = nowIso();
    if (elapsed > task.perStepTimeoutMs) {
      failTask(task, "STEP_TIMEOUT", `Unity script step exceeded ${task.perStepTimeoutMs}ms after returning.`);
      return;
    }
    if (next?.done) {
      completeTask(task, next.value);
      return;
    }
    interpretYield(task, next?.value);
  } catch (error: unknown) {
    const stepTimeout = isStepTimeoutError(error);
    const explicitCode = isRecord(error) && typeof error.code === "string" ? String(error.code) : "";
    failTask(
      task,
      stepTimeout ? "STEP_TIMEOUT" : (explicitCode || "SCRIPT_ERROR"),
      stepTimeout
        ? `Unity script step exceeded ${task.perStepTimeoutMs}ms.`
        : error instanceof Error ? error.message : String(error),
    );
  } finally {
    task.stepDeadlineMs = 0;
  }
}

function createScriptRun(bridge: DevRpcBridge, payload: ScriptRunRequest) {
  const script = String(payload.script || "");
  if (!script.trim()) {
    throw new Error("script is required");
  }

  const task: ScriptRunTask = {
    id: createRunId(),
    mode: bridge.isEditor ? "editor" : "runtime",
    name: String(payload.name || "unity-script-run"),
    iterator: null,
    status: "running",
    result: null,
    errorCode: "",
    errorMessage: "",
    logs: [],
    createdRefs: [],
    frames: 0,
    startMs: Date.now(),
    updatedAt: nowIso(),
    totalTimeoutMs: toPositiveNumber(payload.totalTimeoutMs, DEFAULT_TOTAL_TIMEOUT_MS),
    perStepTimeoutMs: toPositiveNumber(payload.perStepTimeoutMs, DEFAULT_PER_STEP_TIMEOUT_MS),
    maxFrames: Math.floor(toPositiveNumber(payload.maxFrames, DEFAULT_MAX_FRAMES)),
    waitFrames: 0,
    waitUntilMs: 0,
    stepDeadlineMs: 0,
    hasPendingInput: false,
    pendingInput: null,
    waiters: [],
  };

  const args = isRecord(payload.args) ? payload.args : {};
  const ctx = createTaskContext(bridge, task, args as Record<string, unknown>);
  task.iterator = compileRunIterator(script, String(payload.entry || "run"), ctx, args as Record<string, unknown>, task);
  getRunStore().set(task.id, task);
  return task;
}

function getTaskOrThrow(taskId: string): ScriptRunTask {
  const task = getRunStore().get(String(taskId || ""));
  if (!task) {
    throw new Error(`Unity script run not found: ${taskId}`);
  }
  return task;
}

export function tickUnityScriptHost() {
  const tasks = Array.from(getRunStore().values());
  for (const task of tasks) {
    stepTask(task);
  }
}

export function runUnityScriptTask(bridge: DevRpcBridge, payload: ScriptRunRequest): Promise<ReturnType<typeof buildStatus>> {
  const task = createScriptRun(bridge, payload);
  if (task.status !== "running") {
    return Promise.resolve(buildStatus(task));
  }
  return new Promise((resolve) => {
    task.waiters.push(resolve);
  });
}

export function installUnityScriptHost(bridge: DevRpcBridge) {
  installedBridge = bridge;
  installRuntimeAccessBridge();
  (globalThis as UnityScriptHostGlobal).__pieUnityScriptHost = {
    invoke(method: string, argsJson: string) {
      const parsedPayload = argsJson ? JSON.parse(String(argsJson)) : {};
      const payload = isRecord(parsedPayload) ? parsedPayload : {};
      switch (String(method || "")) {
        case "run_start": {
          if (!installedBridge) throw new Error("Unity script host bridge is not installed.");
          const task = createScriptRun(installedBridge, payload);
          return JSON.stringify(buildStatus(task));
        }
        case "run_status": {
          return JSON.stringify(buildStatus(getTaskOrThrow(String(payload.taskId || ""))));
        }
        case "run_cancel": {
          const task = getTaskOrThrow(String(payload.taskId || ""));
          cancelTask(task, String(payload.reason || "Unity script run cancelled."));
          return JSON.stringify(buildStatus(task));
        }
        default:
          throw new Error(`Unknown unity script host method: ${method}`);
      }
    },
    tick() {
      tickUnityScriptHost();
    },
  };
}

