export const AGENTS_CONTEXT_FILE_NAME = "AGENTS.md";

export interface ProjectContextFile {
	path: string;
	content: string;
}

export interface BuildProjectContextSectionOptions {
	heading?: string;
	intro?: string;
}

function normalizeContextPath(path: string): string {
	return String(path || "").replace(/\\/g, "/").replace(/^\/+/, "").trim() || AGENTS_CONTEXT_FILE_NAME;
}

function normalizeContextContent(content: string): string {
	return String(content || "").replace(/\r\n/g, "\n").trim();
}

export function dedupeProjectContextFiles(files: readonly ProjectContextFile[]): ProjectContextFile[] {
	const seen = new Set<string>();
	const result: ProjectContextFile[] = [];
	for (const file of files) {
		const path = normalizeContextPath(file.path);
		const key = path.toLowerCase();
		const content = normalizeContextContent(file.content);
		if (!content || seen.has(key)) {
			continue;
		}
		seen.add(key);
		result.push({ path, content });
	}
	return result;
}

export function buildProjectContextSection(
	files: readonly ProjectContextFile[],
	options: BuildProjectContextSectionOptions = {},
): string {
	const contextFiles = dedupeProjectContextFiles(files);
	if (contextFiles.length === 0) {
		return "";
	}

	const heading = options.heading?.trim() || "Project Context";
	const intro = options.intro?.trim()
		|| "Project-specific instructions from AGENTS.md files. Apply them in order; later files may add narrower instructions.";
	const lines = [`## ${heading}`, intro, ""];
	for (const file of contextFiles) {
		lines.push(`### ${file.path}`, file.content, "");
	}
	return lines.join("\n").trimEnd();
}
