import type { AgentTool } from "@pie/agent-core";
import { describeToolPolicyDecision, getToolCapabilityMetadata, type RuntimeToolPolicyMode } from "./tool-policy.js";

type ToolPromptInput = Pick<AgentTool, "name" | "description"> & {
	capabilityMetadata?: unknown;
};

function normalizeDescription(description: string | undefined): string {
	const text = String(description || "").replace(/\s+/g, " ").trim();
	if (!text) return "";
	return text.replace(/[.;:]\s*$/, "");
}

function buildToolLine(tool: ToolPromptInput, mode: RuntimeToolPolicyMode): string | undefined {
	const decision = describeToolPolicyDecision(tool as unknown as AgentTool, mode);
	if (!decision.allowed) return undefined;
	const description = normalizeDescription(tool.description);
	const metadata = getToolCapabilityMetadata(tool as unknown as AgentTool);
	const policy = metadata
		? [
				metadata.readsFile ? "reads files" : undefined,
				metadata.writesFile ? "writes files" : undefined,
				metadata.readsNetwork ? "reads network" : undefined,
				metadata.executesShell ? "executes shell" : undefined,
				metadata.highRisk ? "high risk" : undefined,
				metadata.availableInPlanMode ? "plan-mode available" : undefined,
		  ].filter(Boolean).join("; ")
		: "";
	const suffix = policy ? ` (${policy})` : "";
	return description
		? `- ${tool.name}: ${description}${suffix}`
		: `- ${tool.name}${suffix}`;
}

export function buildToolsPromptSection(
	tools: readonly ToolPromptInput[],
	options: { mode?: RuntimeToolPolicyMode } = {},
): string {
	const mode = options.mode ?? "normal";
	return `<tools>\n${tools.map((tool) => buildToolLine(tool, mode)).filter(Boolean).join("\n")}\n</tools>`;
}
