import type { TodoItem, TodoStatus } from "./todo.js";
import type { PlanTodoItem } from "./plan.js";
import { createTodoClosureLoop, restoreLoopState, type LoopState } from "./loop.js";

export type ExecutionMode = "idle" | "todo" | "plan";
export type ExecutionLifecycle = "active" | "paused" | "aborted" | "completed" | "stale" | "stalled";
export type ExecutionSource = "user_todo" | "plan_mode" | "system_auto";

export interface ExecutionStep {
	id: number;
	title: string;
	description: string;
	status: TodoStatus;
}

export interface ExecutionState {
	mode: ExecutionMode;
	lifecycle: ExecutionLifecycle;
	steps: ExecutionStep[];
	currentStepId: number | null;
	lastCompletedStepId: number | null;
	source: ExecutionSource;
	loop: LoopState | null;
	awaitingContinuation: boolean;
	failureSummary: string | null;
	updatedAt: string;
}

const CONTINUE_PATTERNS = [/^继续(?:\s|$|[，。,.!?！？])/u, /\bcontinue\b/i];

function nowIso(): string {
	return new Date().toISOString();
}

function normalizeTodoStatus(status: string): TodoStatus {
	switch (String(status || "").trim().toLowerCase()) {
		case "completed":
		case "done":
		case "finished":
			return "completed";
		case "in-progress":
		case "in progress":
		case "doing":
		case "active":
			return "in-progress";
		default:
			return "not-started";
	}
}

function normalizeStep(step: Partial<ExecutionStep>, index: number): ExecutionStep {
	return {
		id: Number.isInteger(step.id) && (step.id as number) > 0 ? step.id as number : index + 1,
		title: typeof step.title === "string" && step.title.trim().length > 0 ? step.title.trim() : `Step ${index + 1}`,
		description: typeof step.description === "string" ? step.description : "",
		status: normalizeTodoStatus(String(step.status || "not-started")),
	};
}

function normalizeSteps(steps: Partial<ExecutionStep>[]): ExecutionStep[] {
	return (Array.isArray(steps) ? steps : []).map((step, index) => ({
		...normalizeStep(step, index),
		id: index + 1,
	}));
}

function inferCurrentStepId(steps: ExecutionStep[]): number | null {
	const inProgress = steps.find((step) => step.status === "in-progress");
	if (inProgress) return inProgress.id;
	const next = steps.find((step) => step.status !== "completed");
	return next?.id ?? null;
}

function inferLastCompletedStepId(steps: ExecutionStep[]): number | null {
	const completed = [...steps].reverse().find((step) => step.status === "completed");
	return completed?.id ?? null;
}

function createRestoredTodoLoop(state: ExecutionState, lifecycle: ExecutionLifecycle, restoredLoop: LoopState | null): LoopState | null {
	if (state.mode !== "todo" || (lifecycle !== "active" && lifecycle !== "paused") || state.steps.length === 0) {
		return null;
	}
	if (restoredLoop) {
		return restoredLoop;
	}
	const loop = createTodoClosureLoop({ ...state, lifecycle: "active" });
	return lifecycle === "paused" && loop ? { ...loop, status: "paused" } : loop;
}

export function createEmptyExecutionState(): ExecutionState {
	return {
		mode: "idle",
		lifecycle: "stale",
		steps: [],
		currentStepId: null,
		lastCompletedStepId: null,
		source: "system_auto",
		loop: null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	};
}

export function cloneExecutionState(state: ExecutionState): ExecutionState {
	return {
		...state,
		steps: state.steps.map((step) => ({ ...step })),
	};
}

export function restoreExecutionState(raw: unknown): ExecutionState {
	if (!raw || typeof raw !== "object") {
		return createEmptyExecutionState();
	}

	const state = raw as Partial<ExecutionState>;
	const steps = normalizeSteps((state.steps as Partial<ExecutionStep>[]) || []);
	const lifecycle = steps.length === 0
		? "stale"
		: state.lifecycle === "active" || state.lifecycle === "paused" || state.lifecycle === "aborted" || state.lifecycle === "completed" || state.lifecycle === "stale" || state.lifecycle === "stalled"
			? state.lifecycle
			: "active";
	const mode = state.mode === "todo" || state.mode === "plan" || state.mode === "idle" ? state.mode : (steps.length > 0 ? "todo" : "idle");
	const loop = restoreLoopState((state as Partial<ExecutionState>).loop);

	return {
		mode,
		lifecycle,
		steps,
		currentStepId: typeof state.currentStepId === "number" ? state.currentStepId : inferCurrentStepId(steps),
		lastCompletedStepId: typeof state.lastCompletedStepId === "number" ? state.lastCompletedStepId : inferLastCompletedStepId(steps),
		source: state.source === "user_todo" || state.source === "plan_mode" || state.source === "system_auto"
			? state.source
			: "system_auto",
		loop: createRestoredTodoLoop({
				mode,
				lifecycle,
				steps,
				currentStepId: typeof state.currentStepId === "number" ? state.currentStepId : inferCurrentStepId(steps),
				lastCompletedStepId: typeof state.lastCompletedStepId === "number" ? state.lastCompletedStepId : inferLastCompletedStepId(steps),
				source: state.source === "user_todo" || state.source === "plan_mode" || state.source === "system_auto"
					? state.source
					: "system_auto",
				loop: null,
				awaitingContinuation: Boolean((state as Partial<ExecutionState>).awaitingContinuation),
				failureSummary: typeof (state as Partial<ExecutionState>).failureSummary === "string"
					? (state as Partial<ExecutionState>).failureSummary as string
					: null,
				updatedAt: typeof state.updatedAt === "string" && state.updatedAt.length > 0 ? state.updatedAt : nowIso(),
			}, lifecycle, loop),
		awaitingContinuation: Boolean((state as Partial<ExecutionState>).awaitingContinuation),
		failureSummary: typeof (state as Partial<ExecutionState>).failureSummary === "string"
			? (state as Partial<ExecutionState>).failureSummary as string
			: null,
		updatedAt: typeof state.updatedAt === "string" && state.updatedAt.length > 0 ? state.updatedAt : nowIso(),
	};
}

export function createExecutionStateStore(initialState?: Partial<ExecutionState>) {
	let state = restoreExecutionState(initialState);

	return {
		read(): ExecutionState {
			return cloneExecutionState(state);
		},
		write(nextState: Partial<ExecutionState>): ExecutionState {
			state = restoreExecutionState({ ...state, ...nextState });
			return cloneExecutionState(state);
		},
		replace(nextState: Partial<ExecutionState>): ExecutionState {
			state = restoreExecutionState(nextState);
			return cloneExecutionState(state);
		},
		clear(): ExecutionState {
			state = createEmptyExecutionState();
			return cloneExecutionState(state);
		},
	};
}

export function createExecutionStateFromTodos(
	todos: TodoItem[],
	mode: ExecutionMode = "todo",
	source: ExecutionSource = "user_todo",
): ExecutionState {
		const steps = normalizeSteps(
			todos.map((todo) => ({
				id: todo.id,
				title: todo.title,
				description: todo.description,
				status: normalizeTodoStatus(String(todo.status)),
			})),
		);
	const allCompleted = steps.length > 0 && steps.every((step) => step.status === "completed");
	return restoreExecutionState({
		mode,
		lifecycle: steps.length === 0 ? "stale" : allCompleted ? "completed" : "active",
		steps,
		currentStepId: inferCurrentStepId(steps),
		lastCompletedStepId: inferLastCompletedStepId(steps),
		source,
		loop: null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	});
}

export function createExecutionStateFromPlan(
	items: PlanTodoItem[],
	source: ExecutionSource = "plan_mode",
): ExecutionState {
	const allCompleted = items.length > 0 && items.every((item) => item.completed);
	return restoreExecutionState({
		mode: "plan",
		lifecycle: items.length === 0 ? "stale" : allCompleted ? "completed" : "active",
		steps: items.map((item) => ({
			id: item.step,
			title: item.text,
			description: "",
			status: item.completed ? "completed" as TodoStatus : "not-started" as TodoStatus,
		})),
		source,
		loop: null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	});
}

export function executionStateToTodos(state: ExecutionState): TodoItem[] {
	return state.steps.map((step) => ({
		id: step.id,
		title: step.title,
		description: step.description,
		status: step.status,
	}));
}

export function createTodoWidgetView(state: ExecutionState): ExecutionStep[] {
	if (state.lifecycle !== "active" && state.lifecycle !== "paused" && state.lifecycle !== "aborted" && state.lifecycle !== "stalled") {
		return [];
	}
	return state.steps.map((step) => ({ ...step }));
}

export function buildExecutionReminder(state: ExecutionState): string | null {
	if ((state.lifecycle !== "active" && state.lifecycle !== "stalled") || state.steps.length === 0) {
		return null;
	}

	const currentStep = state.steps.find((step) => step.id === state.currentStepId)
		|| state.steps.find((step) => step.status === "in-progress")
		|| state.steps.find((step) => step.status !== "completed");
	const nextSteps = state.steps
		.filter((step) => step.status !== "completed" && step.id !== currentStep?.id)
		.slice(0, 2);

	if (!currentStep && nextSteps.length === 0) {
		return null;
	}

	const lines = ["<system-reminder>", "[Execution]"];
	if (currentStep) {
		lines.push(`Current: ${currentStep.title}`);
	}
	if (nextSteps.length > 0) {
		lines.push(`Next: ${nextSteps.map((step) => step.title).join("; ")}`);
	}
	lines.push("</system-reminder>", "");
	return lines.join("\n");
}

export function abortExecutionState(state: ExecutionState): ExecutionState {
	if (state.steps.length === 0) {
		return createEmptyExecutionState();
	}
	return restoreExecutionState({
		...state,
		lifecycle: "aborted",
		loop: null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	});
}

export function continueExecutionState(state: ExecutionState): ExecutionState {
	if (state.steps.length === 0) {
		return createEmptyExecutionState();
	}
	const activeState = restoreExecutionState({
		...state,
		lifecycle: "active",
		currentStepId: inferCurrentStepId(state.steps),
		loop: null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	});
	return restoreExecutionState({
		...activeState,
		loop: activeState.mode === "todo" ? createTodoClosureLoop(activeState) : null,
		awaitingContinuation: false,
		failureSummary: null,
		updatedAt: nowIso(),
	});
}

export function pauseExecutionState(state: ExecutionState, summary: string | null = null): ExecutionState {
	if (state.steps.length === 0) {
		return createEmptyExecutionState();
	}
	return restoreExecutionState({
		...state,
		lifecycle: "paused",
		loop: state.loop ? { ...state.loop, status: "paused" } : null,
		awaitingContinuation: false,
		failureSummary: summary,
		updatedAt: nowIso(),
	});
}

export function clearExecutionState(state?: ExecutionState): ExecutionState {
	if (!state || state.steps.length === 0) {
		return createEmptyExecutionState();
	}
	return createEmptyExecutionState();
}

export function supersedeExecutionState(): ExecutionState {
	return createEmptyExecutionState();
}

export function shouldPreserveExecutionStateForUserText(text: string): boolean {
	const trimmed = String(text || "").trim();
	if (!trimmed) return false;
	return CONTINUE_PATTERNS.some((pattern) => pattern.test(trimmed));
}
