import { getFileSystem } from "@pie/platform";
import type { Api, FileReferenceContent, Model, ToolModelRouteDecision, UserContentBlock } from "@pie/ai";
import {
	createReadFileUnderstandingHandler,
	type ReadFileUnderstandingKind,
	type ReadFileUnderstandingPrepareParams,
	type ReadFileUnderstandingPreparedContent,
	type ReadToolOptions,
} from "@pie/shared-headless-capabilities";

export interface UnityReadFileUnderstandingOptions {
	getAgentModel: () => Model<Api> | undefined;
	getSessionId: () => string | undefined;
	resolveToolModel: (purpose: `read_file.${ReadFileUnderstandingKind}`) => ToolModelRouteDecision;
	fetch: typeof fetch;
}

const DEFAULT_INLINE_LIMIT_MB = 100;
const MAX_EXTRACTED_DOCUMENT_CHARS = 120_000;

declare const CS: {
	Pie?: {
		PieHttpBridge?: {
			UploadFileMultipartAsync?(
				url: string,
				filePath: string,
				bearerToken: string,
				purpose: string,
				mimeType: string,
				sourceName: string,
				headersJson?: string | null,
			): unknown;
		};
	};
};

declare const puer: { $promise?: <T>(task: unknown) => Promise<T> } | undefined;

function fileNameFromPath(path: string): string {
	const normalized = String(path || "").replace(/\\/g, "/");
	return normalized.slice(normalized.lastIndexOf("/") + 1) || normalized || "file";
}

function getCapabilityLimitMb(model: Model<Api>, kind: ReadFileUnderstandingKind): number {
	const value = model.fileCapabilities?.[kind];
	if (value && typeof value === "object" && typeof value.maxFileSizeMb === "number") {
		return value.maxFileSizeMb;
	}
	return DEFAULT_INLINE_LIMIT_MB;
}

async function prepareInlineFileContent(params: ReadFileUnderstandingPrepareParams): Promise<ReadFileUnderstandingPreparedContent> {
	const fs = getFileSystem();
	const stat = await fs.stat(params.request.absolutePath);
	const limitMb = getCapabilityLimitMb(params.model, params.request.kind);
	const limitBytes = limitMb * 1024 * 1024;
	if (stat.size > limitBytes) {
		throw new Error(
			`Unity ${params.request.kind} understanding supports inline files up to ${limitMb}MB for ${params.model.provider}/${params.model.id}; ${fileNameFromPath(params.request.displayPath)} is ${(stat.size / 1024 / 1024).toFixed(1)}MB.`,
		);
	}

	const base64 = await fs.readFile(params.request.absolutePath, "base64");
	if (params.request.kind === "video") {
		return {
			content: [{
				type: "video",
				data: base64,
				mimeType: params.request.mimeType,
			}],
			details: {
				inputMode: "inlineDataUrl",
				inlineFileSizeBytes: stat.size,
				inlineLimitMb: limitMb,
			},
		};
	}
	if (params.request.kind === "audio") {
		return {
			content: [{
				type: "audio",
				data: base64,
				mimeType: params.request.mimeType,
			}],
			details: {
				inputMode: "inlineDataUrl",
				inlineFileSizeBytes: stat.size,
				inlineLimitMb: limitMb,
			},
		};
	}

	const fileRef: FileReferenceContent = {
		type: "fileRef",
		url: `data:${params.request.mimeType};base64,${base64}`,
		mimeType: params.request.mimeType,
		modality: "file",
	};
	return {
		content: [fileRef],
		details: {
			inputMode: "inlineDataUrl",
			inlineFileSizeBytes: stat.size,
			inlineLimitMb: limitMb,
		},
	};
}

async function awaitUnityTask<T>(task: unknown): Promise<T> {
	const promiseFactory = (globalThis as { puer?: { $promise?: <T>(task: unknown) => Promise<T> } }).puer?.$promise
		?? (typeof puer !== "undefined" ? puer?.$promise : undefined);
	if (typeof promiseFactory === "function") {
		return promiseFactory<T>(task);
	}
	if (task && typeof (task as Promise<T>).then === "function") {
		return task as Promise<T>;
	}
	return task as T;
}

function authHeaders(model: Model<Api>, apiKey: string): Record<string, string> {
	return {
		Authorization: `Bearer ${apiKey}`,
		...(model.headers || {}),
	};
}

async function uploadDocumentForExtraction(
	params: ReadFileUnderstandingPrepareParams,
	fetchImpl: typeof fetch,
): Promise<ReadFileUnderstandingPreparedContent> {
	const upload = CS?.Pie?.PieHttpBridge?.UploadFileMultipartAsync;
	if (typeof upload !== "function") {
		throw new Error("Unity document understanding requires PieHttpBridge.UploadFileMultipartAsync. Rebuild/reload the Pie Unity package.");
	}
	const baseUrl = params.model.baseUrl?.replace(/\/+$/, "");
	if (!baseUrl) {
		throw new Error(`Model ${params.model.provider}/${params.model.id} has no baseUrl for document upload.`);
	}
	const uploadJson = await awaitUnityTask<string>(upload(
		`${baseUrl}/files`,
		params.request.absolutePath,
		params.apiKey,
		"file-extract",
		params.request.mimeType,
		fileNameFromPath(params.request.displayPath),
		JSON.stringify(params.model.headers || {}),
	));
	const uploaded = JSON.parse(String(uploadJson || "{}")) as { id?: string; fileId?: string; status?: string };
	const fileId = uploaded.id || uploaded.fileId;
	if (!fileId) {
		throw new Error(`Document upload did not return a file id: ${uploadJson}`);
	}

	const headers = authHeaders(params.model, params.apiKey);
	const started = Date.now();
	while (Date.now() - started < 120_000) {
		const statusResponse = await fetchImpl(`${baseUrl}/files/${fileId}`, { headers });
		if (statusResponse.status === 404) {
			throw new Error(`Uploaded document ${fileId} was not found by provider.`);
		}
		if (!statusResponse.ok) {
			throw new Error(`Document status check failed: HTTP ${statusResponse.status}: ${await statusResponse.text()}`);
		}
		const statusJson = await statusResponse.json() as { status?: string; status_details?: string };
		const status = String(statusJson.status || uploaded.status || "").toLowerCase();
		if (!status || status === "ok" || status === "active" || status === "ready") break;
		if (status === "error" || status === "expired") {
			throw new Error(`Uploaded document is not ready: ${status}${statusJson.status_details ? ` (${statusJson.status_details})` : ""}`);
		}
		if (params.request.signal?.aborted) throw new Error("Operation aborted");
		await new Promise((resolve) => setTimeout(resolve, 1500));
	}

	const contentResponse = await fetchImpl(`${baseUrl}/files/${fileId}/content`, { headers });
	if (!contentResponse.ok) {
		throw new Error(`Document content extraction failed: HTTP ${contentResponse.status}: ${await contentResponse.text()}`);
	}
	const extracted = extractProviderContent(await contentResponse.text());
	const truncated = extracted.length > MAX_EXTRACTED_DOCUMENT_CHARS;
	const documentText = truncated
		? `${extracted.slice(0, MAX_EXTRACTED_DOCUMENT_CHARS)}\n\n[Document extraction truncated after ${MAX_EXTRACTED_DOCUMENT_CHARS} characters.]`
		: extracted;
	return {
		content: [{
			type: "text",
			text: [
				"Extracted document content:",
				documentText || "(document extraction returned no text)",
			].join("\n"),
		}],
		details: {
			inputMode: "fileUploadExtraction",
			uploadedFileId: fileId,
		},
	};
}

function extractProviderContent(raw: string): string {
	try {
		const parsed = JSON.parse(raw) as { content?: unknown; text?: unknown };
		if (typeof parsed.content === "string") return parsed.content;
		if (typeof parsed.text === "string") return parsed.text;
	} catch {
		// Plain text extraction is valid.
	}
	return raw;
}

export function createUnityReadFileUnderstanding(
	options: UnityReadFileUnderstandingOptions,
): NonNullable<ReadToolOptions["understandFile"]> {
	return createReadFileUnderstandingHandler({
		getAgentModel: options.getAgentModel,
		getSessionId: options.getSessionId,
		resolveToolModel: options.resolveToolModel,
		prepareFileContent: (params) => params.request.kind === "document"
			? uploadDocumentForExtraction(params, options.fetch)
			: prepareInlineFileContent(params),
	});
}
