import {
  createRuntimeExtensionRegistry,
  type RuntimeExtensionContext,
} from "@pie/agent-framework";

export interface PieExtensionContext {
  projectRoot: string;
  isEditor: boolean;
  log: (message: string) => void;
}

export type PieExtensionApi = RuntimeExtensionContext<PieExtensionContext>;

type PieBridgeGlobal = {
  pieBridge?: {
    callHost?: (name: string, data: string) => unknown;
    host?: {
      call?: (fullNameOrNamespace: string, nameOrArgs?: string | unknown, maybeArgs?: unknown) => unknown;
      listCapabilities?: (namespace?: string) => unknown[];
    };
  };
};

const registry = createRuntimeExtensionRegistry();

export function resetExtensionRegistry() {
  registry.reset();
}

export function getExtensionTools() {
  return registry.getTools();
}

export function getLoadedExtensions(): string[] {
  return registry.getLoadedExtensions();
}

export function getSystemPromptPatches(): string[] {
  return registry.getSystemPromptPatches();
}

export function buildRegisteredHooks() {
  return registry.buildHooks();
}

export function createExtensionApi(context: PieExtensionContext, filePath: string): PieExtensionApi {
  const normalizedPath = String(filePath ?? "").replace(/\\/g, "/");
  const fileName = normalizedPath.split("/").pop() || "extension.js";
  const name = fileName.replace(/\.js$/i, "");
  const dir = normalizedPath.slice(0, Math.max(0, normalizedPath.length - fileName.length)).replace(/\/$/, "") || ".";

  return registry.createContext({
    manifest: {
      name,
      version: "0.0.0",
      main: fileName,
    },
    dir,
    config: {},
	  }, {
	    ...context,
		    callHost: async <T = unknown>(name: string, args?: unknown): Promise<T> => {
		      const json = JSON.stringify(args ?? {});
		      return (globalThis as PieBridgeGlobal).pieBridge?.callHost?.(name, json) as T;
		    },
        host: {
          listCapabilities: (namespace?: string) =>
            ((globalThis as PieBridgeGlobal).pieBridge?.host?.listCapabilities?.(namespace) ?? []) as unknown[],
          call: async <T = unknown>(namespace: string, name: string, args?: unknown): Promise<T> =>
            ((globalThis as PieBridgeGlobal).pieBridge?.host?.call?.(namespace, name, args)) as T,
        },
  }) as PieExtensionApi;
}

export function registerLoadedExtension(path: string) {
  registry.registerLoadedExtension(path);
}
