/**
 * unity-http-client.ts
 *
 * Push-based SSE streaming: C# drives data delivery from OnEditorUpdate,
 * JS receives lines via resolved Promises (zero polling, zero blocking).
 *
 * Flow:
 *   1. JS calls StartStreamRequest(method, ...) → C# managed HTTP stream reads SSE
 *   2. C# OnEditorUpdate drains queued lines → calls JS globalThis._pieSSEPush(id, line)
 *   3. JS Promise resolves → async generator yields → consumer processes
 *   4. Generator awaits next Promise (won't resolve until next frame's push)
 */

import type { HttpClient, HttpResponse, HttpRequestOptions } from "@pie/platform";

declare const CS: {
  Pie: {
    PieHttpBridge: {
      StartStreamRequest(method: string, url: string, body: string, bearer: string, headersJson: string | null): number;
      CancelRequest(requestId: number): void;
      CreateUtf8UploadHandler(body: string): unknown;
      FetchTextAsync(method: string, url: string, body: string, bearer: string, headersJson: string | null): unknown;
    };
  };
  UnityEngine?: {
    Networking: {
      UnityWebRequest: new (url: string, method: string) => {
        SetRequestHeader(key: string, value: string): void;
        Abort(): void;
        SendWebRequest(): { isDone: boolean };
        responseCode: number;
        error?: string;
        uploadHandler?: unknown;
        downloadHandler?: { text?: string };
        GetResponseHeaderKeys?: () => string[];
        GetResponseHeader(key: string): string | null;
      };
      DownloadHandlerBuffer: new () => { text?: string };
    };
  };
};

declare const puer: { $promise<T>(task: unknown): Promise<T> } | undefined;

interface UnityHttpGlobal {
  _pieSSEPush?: (requestId: number, line: string | null) => void;
  _pieSSEStatus?: (requestId: number, status: number, error: string | null) => void;
  pieBridge?: { log?: (level: string, message: string) => void };
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ─── Push-based SSE line delivery ──────────────────────────────────────────────

interface SSEBuffer {
  lines: string[];
  done?: boolean;
  error?: Error | null;
  httpStatus?: number;
  httpError?: string | null;
  resolve?: () => void;
}

const sseBuffers = new Map<number, SSEBuffer>();

/** Called by C# PieBridge.OnEditorUpdate → PushSSEData for each queued SSE line. */
(globalThis as UnityHttpGlobal)._pieSSEPush = (requestId: number, line: string | null) => {
  let buf = sseBuffers.get(requestId);
  if (!buf) {
    buf = { lines: [] };
    sseBuffers.set(requestId, buf);
  }
  if (line === null) {
    buf.done = true;
  } else {
    buf.lines.push(line);
  }
  // Wake up the waiting generator
  if (buf.resolve) {
    const r = buf.resolve;
    buf.resolve = undefined;
    r();
  }
};

/** Called by C# to set the HTTP status once response headers arrive. */
(globalThis as UnityHttpGlobal)._pieSSEStatus = (requestId: number, status: number, error: string | null) => {
  let buf = sseBuffers.get(requestId);
  if (!buf) {
    buf = { lines: [] };
    sseBuffers.set(requestId, buf);
  }
  buf.httpStatus = status;
  buf.httpError = error;
  if (status >= 400) {
    buf.error = new Error(error || `HTTP ${status}`);
    buf.done = true;
  }
  if (buf.resolve) {
    const r = buf.resolve;
    buf.resolve = undefined;
    r();
  }
};

function waitForData(requestId: number): Promise<void> {
  const buf = sseBuffers.get(requestId);
  if (!buf) return Promise.resolve();
  if (buf.lines.length > 0 || buf.done || buf.error) return Promise.resolve();
  return new Promise<void>((resolve) => { buf.resolve = resolve; });
}

function waitForStatus(requestId: number): Promise<void> {
  const buf = sseBuffers.get(requestId);
  if (!buf) return Promise.resolve();
  if (buf.httpStatus !== undefined) return Promise.resolve();
  return new Promise<void>((resolve) => { buf.resolve = resolve; });
}

// ─── HttpClient implementation ─────────────────────────────────────────────────

export class UnityHttpClient implements HttpClient {
  private static readonly TRANSPORT_MODE: "managed_stream" | "buffered_fallback" | "plain" = "managed_stream";
  private static readonly MAX_RETRIES = 5;
  private static readonly RETRYABLE_STATUS = new Set([429, 500, 502, 503, 504]);

  async request(url: string, options: HttpRequestOptions = {}): Promise<HttpResponse> {
    if (UnityHttpClient.TRANSPORT_MODE === "buffered_fallback") {
      const buffered = this.tryBuildBufferedCompletionRequest(url, options);
      if (buffered) {
        return this.requestViaUnityWebRequestBufferedFallback(url, buffered.options, buffered.mode);
      }
    }

    const requestedMethod = (options.method || "GET").toUpperCase();
    if ((requestedMethod === "GET" || requestedMethod === "HEAD") && !options.body) {
      // Shared browser-style capabilities such as web_fetch need the raw HTTP
      // response body, headers, and final text. The provider stream bridge is
      // line-oriented, so use a narrow C# text bridge for ordinary fetches.
      return this.requestViaManagedTextFetch(url, options);
    }

    if (UnityHttpClient.TRANSPORT_MODE !== "managed_stream") {
      return this.requestViaUnityWebRequestBufferedFallback(url, options, "plain");
    }

    const method  = options.method  || "POST";
    const body    = options.body    || "";
    const headers = options.headers || {};

    const authHeader =
      headers["Authorization"] ||
      headers["authorization"] ||
      "";
    const bearer = authHeader.replace(/^Bearer\s+/i, "");

    const extraHeaders: Record<string, string> = {};
    for (const [k, v] of Object.entries(headers)) {
      if (k.toLowerCase() === "authorization") continue;
      if (k.toLowerCase() === "content-type")  continue;
      extraHeaders[k] = v;
    }
    const headersJson = Object.keys(extraHeaders).length > 0
      ? JSON.stringify(extraHeaders)
      : null;
    // The shared OpenAI-compatible provider treats `data: [DONE]` as a
    // non-content marker and waits for the platform SSE iterator to finish.
    // Unity's managed HTTP stream may keep the transport open after `[DONE]`,
    // so the Unity adapter owns this platform-specific iterator shutdown.
    const endOnOpenAIStreamDone = shouldEndOnOpenAIStreamDone(url, options);

    let requestId: number = -1;
    let httpStatus = -1;

    for (let attempt = 0; attempt <= UnityHttpClient.MAX_RETRIES; attempt++) {
      requestId = CS.Pie.PieHttpBridge.StartStreamRequest(
        method,
        url,
        method === "GET" ? "" : body,
        bearer,
        headersJson,
      );

      // Initialize buffer for this request
      sseBuffers.set(requestId, { lines: [] });

      // Wait for C# to push the HTTP status (non-blocking — resolved by _pieSSEStatus)
      const headerTimeoutMs = 60_000;
      const headerStart = Date.now();
      while (true) {
        const buf = sseBuffers.get(requestId)!;
        if (buf.httpStatus !== undefined) {
          httpStatus = buf.httpStatus;
          break;
        }
        if (Date.now() - headerStart > headerTimeoutMs) {
          CS.Pie.PieHttpBridge.CancelRequest(requestId);
          sseBuffers.delete(requestId);
          throw new Error("Timed out waiting for HTTP response headers");
        }
        await waitForStatus(requestId);
      }

      if (httpStatus >= 200 && httpStatus < 300) break;

      // Check retryable
      if (UnityHttpClient.RETRYABLE_STATUS.has(httpStatus) && attempt < UnityHttpClient.MAX_RETRIES) {
        const errorBody: string = sseBuffers.get(requestId)?.httpError ?? "";
        CS.Pie.PieHttpBridge.CancelRequest(requestId);
        sseBuffers.delete(requestId);

        let retryAfterMs = 0;
        const retryMatch = errorBody.match(/"retry.after":\s*(\d+)/i);
        if (retryMatch) retryAfterMs = parseInt(retryMatch[1], 10) * 1000;

        const backoffMs = Math.max(retryAfterMs, (2 ** attempt) * 1000 + Math.random() * 500);
        (globalThis as UnityHttpGlobal).pieBridge?.log?.("warn", `[UnityHttpClient] ${httpStatus} – retrying in ${Math.round(backoffMs)}ms (attempt ${attempt + 1}/${UnityHttpClient.MAX_RETRIES})`);
        await sleep(backoffMs);
        continue;
      }

      // Non-retryable or exhausted
      const errorBody: string = sseBuffers.get(requestId)?.httpError ?? `HTTP ${httpStatus}`;
      CS.Pie.PieHttpBridge.CancelRequest(requestId);
      sseBuffers.delete(requestId);
      const err = new Error(errorBody) as Error & { status?: number; statusCode?: number };
      err.status = httpStatus;
      err.statusCode = httpStatus;
      throw err;
    }

    const capturedRequestId = requestId;

    const response: HttpResponse = {
      status:     httpStatus,
      statusText: httpStatus >= 200 && httpStatus < 300 ? "OK" : "Error",
      ok:         httpStatus >= 200 && httpStatus < 300,
      headers:    { "content-type": "application/json" },

      async text(): Promise<string> {
        const lines: string[] = [];
        for await (const line of response.readSSELines?.() ?? []) {
          lines.push(line);
        }
        return lines.join("\n");
      },

      async json(): Promise<unknown> {
        return JSON.parse(await response.text());
      },

      async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
        const maxWaitMs = 180_000;
        const startTime = Date.now();

        try {
          while (true) {
            if (signal?.aborted) {
              CS.Pie.PieHttpBridge.CancelRequest(capturedRequestId);
              throw new Error("Request aborted");
            }

            if (Date.now() - startTime > maxWaitMs) {
              CS.Pie.PieHttpBridge.CancelRequest(capturedRequestId);
              throw new Error("Request timed out");
            }

            const buf = sseBuffers.get(capturedRequestId);
            if (!buf) return;

            while (buf.lines.length > 0) {
              const line = buf.lines.shift()!;
              yield line;
              if (endOnOpenAIStreamDone && line.trim() === "data: [DONE]") {
                // Let the shared provider see `[DONE]`, then end this platform
                // iterator so it does not wait for an underlying HTTP EOF.
                return;
              }
            }

            if (buf.done) {
              if (buf.error) throw buf.error;
              return;
            }

            await waitForData(capturedRequestId);
          }
        } finally {
          try {
            CS.Pie.PieHttpBridge.CancelRequest(capturedRequestId);
          } catch {
            // Ignore cleanup races during domain reload or completed requests.
          }
          sseBuffers.delete(capturedRequestId);
        }
      },
    };

    return response;
  }

  private tryBuildBufferedCompletionRequest(
    url: string,
    options: HttpRequestOptions,
  ): { options: HttpRequestOptions; mode: "plain" | "openai-buffered-sse" } | null {
    if (!/\/chat\/completions\/?$/.test(url)) return null;
    if (!options.body || typeof options.body !== "string") return null;

    let parsed: { stream?: boolean; stream_options?: unknown } & Record<string, unknown>;
    try {
      parsed = JSON.parse(options.body);
    } catch {
      return null;
    }

    if (!parsed || parsed.stream !== true) return null;

    const cloned = { ...parsed, stream: false };
    delete cloned.stream_options;

    return {
      options: {
        ...options,
        body: JSON.stringify(cloned),
      },
      mode: "openai-buffered-sse",
    };
  }

  /**
   * Buffered fallback for provider compatibility and Unity-managed TLS edge cases.
   * Ordinary GET/HEAD fetches still prefer FetchTextAsync, but Unity's managed
   * HttpClient can fail certificate negotiation for public sites that
   * UnityWebRequest handles correctly.
   */
  private requestViaUnityWebRequestBufferedFallback(
    url: string,
    options: HttpRequestOptions = {},
    mode: "plain" | "openai-buffered-sse" = "plain",
  ): Promise<HttpResponse> {
    if (typeof CS === "undefined" || !CS?.UnityEngine?.Networking) {
      throw new Error("UnityWebRequest is not available in this environment");
    }

    const { UnityEngine } = CS;
    const method = options.method || "GET";
    const headers = options.headers || {};
    const body = options.body;

    return new Promise((resolve, reject) => {
      const request = new UnityEngine.Networking.UnityWebRequest(url, method);

      for (const [key, value] of Object.entries(headers)) {
        request.SetRequestHeader(key, value);
      }

      if (body && ["POST", "PUT", "PATCH"].includes(method.toUpperCase())) {
        request.uploadHandler = CS.Pie.PieHttpBridge.CreateUtf8UploadHandler(String(body));
      }

      request.downloadHandler = new UnityEngine.Networking.DownloadHandlerBuffer();

      let aborted = false;
      if (options.signal) {
        const onAbort = () => {
          aborted = true;
          request.Abort();
          reject(new Error("Request was aborted"));
        };
        options.signal.addEventListener("abort", onAbort, { once: true });
      }

      const asyncOp = request.SendWebRequest();
      const checkComplete = () => {
        try {
          if (aborted) return;

          if (asyncOp.isDone) {
            const status = request.responseCode;
            const responseHeaders: Record<string, string> = {};
            const contentType = request.GetResponseHeader?.("content-type") || request.GetResponseHeader?.("Content-Type");
            if (contentType) responseHeaders["content-type"] = String(contentType);

            const responseText = request.downloadHandler?.text || "";
            resolve({
              status,
              statusText: request.error || "",
              ok: status >= 200 && status < 300,
              headers: responseHeaders,
              text(): Promise<string> {
                return Promise.resolve(responseText);
              },
              async json(): Promise<unknown> {
                return JSON.parse(responseText);
              },
              async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
                const lines = mode === "openai-buffered-sse"
                  ? buildOpenAICompatibleSseLines(responseText)
                  : responseText.split("\n");
                for (const line of lines) {
                  if (signal?.aborted) {
                    throw new Error("Request was aborted");
                  }
                  yield line;
                }
              },
            });
            return;
          }

          setTimeout(checkComplete, 16);
        } catch (error) {
          reject(error instanceof Error ? error : new Error(String(error)));
        }
      };

      checkComplete();
    });
  }

  private async requestViaManagedTextFetch(
    url: string,
    options: HttpRequestOptions = {},
  ): Promise<HttpResponse> {
    if (typeof puer === "undefined" || typeof puer.$promise !== "function") {
      throw new Error("PuerTS promise bridge is not available for Unity text fetch");
    }

    const method = options.method || "GET";
    const headers = options.headers || {};
    const authHeader =
      headers["Authorization"] ||
      headers["authorization"] ||
      "";
    const bearer = authHeader.replace(/^Bearer\s+/i, "");
    const extraHeaders: Record<string, string> = {};
    for (const [key, value] of Object.entries(headers)) {
      if (key.toLowerCase() === "authorization") continue;
      extraHeaders[key] = value;
    }
    const headersJson = Object.keys(extraHeaders).length > 0
      ? JSON.stringify(extraHeaders)
      : null;

    let raw: string;
    try {
      raw = await puer.$promise<string>(CS.Pie.PieHttpBridge.FetchTextAsync(
        method,
        url,
        options.body || "",
        bearer,
        headersJson,
      ));
    } catch (error) {
      if (this.shouldFallbackToUnityWebRequestForManagedFetch(error, method)) {
        return this.requestViaUnityWebRequestBufferedFallback(url, options, "plain");
      }
      throw error;
    }
    const parsed = JSON.parse(String(raw || "{}")) as {
      status?: number;
      statusText?: string;
      ok?: boolean;
      url?: string;
      headers?: Record<string, string>;
      body?: string;
    };
    const responseText = String(parsed.body || "");
    const status = Number(parsed.status || 0);
    return {
      status,
      statusText: String(parsed.statusText || ""),
      ok: typeof parsed.ok === "boolean" ? parsed.ok : status >= 200 && status < 300,
      headers: parsed.headers || {},
      text(): Promise<string> {
        return Promise.resolve(responseText);
      },
      async json(): Promise<unknown> {
        return JSON.parse(responseText);
      },
      async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
        for (const line of responseText.split("\n")) {
          if (signal?.aborted) {
            throw new Error("Request was aborted");
          }
          yield line;
        }
      },
    };
  }

  private shouldFallbackToUnityWebRequestForManagedFetch(error: unknown, method: string): boolean {
    const normalizedMethod = method.toUpperCase();
    if (normalizedMethod !== "GET" && normalizedMethod !== "HEAD") return false;

    const message = error instanceof Error ? error.message : String(error);
    return /SSL connection could not be established|certificate|authentication failed/i.test(message);
  }
}

function shouldEndOnOpenAIStreamDone(url: string, options: HttpRequestOptions): boolean {
  if (!/\/chat\/completions\/?$/.test(url)) return false;
  if (!options.body || typeof options.body !== "string") return false;

  try {
    const parsed = JSON.parse(options.body);
    return parsed?.stream === true;
  } catch {
    return false;
  }
}

function buildOpenAICompatibleSseLines(responseText: string): string[] {
  const parsed = JSON.parse(responseText || "{}");
  const choice = parsed?.choices?.[0] || {};
  const message = choice?.message || {};
  const lines: string[] = [];

  lines.push(`data: ${JSON.stringify({
    id: parsed?.id || "",
    object: "chat.completion.chunk",
    created: parsed?.created || Math.floor(Date.now() / 1000),
    model: parsed?.model || "",
    choices: [{ index: 0, delta: { role: message?.role || "assistant" }, finish_reason: null }],
  })}`);

  if (typeof message?.content === "string" && message.content.length > 0) {
    lines.push(`data: ${JSON.stringify({
      id: parsed?.id || "",
      object: "chat.completion.chunk",
      created: parsed?.created || Math.floor(Date.now() / 1000),
      model: parsed?.model || "",
      choices: [{ index: 0, delta: { content: message.content }, finish_reason: null }],
    })}`);
  }

  if (Array.isArray(message?.tool_calls)) {
    for (const toolCall of message.tool_calls) {
      lines.push(`data: ${JSON.stringify({
        id: parsed?.id || "",
        object: "chat.completion.chunk",
        created: parsed?.created || Math.floor(Date.now() / 1000),
        model: parsed?.model || "",
        choices: [{
          index: 0,
          delta: {
            tool_calls: [{
              id: toolCall?.id || "",
              type: toolCall?.type || "function",
              function: {
                name: toolCall?.function?.name || "",
                arguments: toolCall?.function?.arguments || "",
              },
            }],
          },
          finish_reason: null,
        }],
      })}`);
    }
  }

  lines.push(`data: ${JSON.stringify({
    id: parsed?.id || "",
    object: "chat.completion.chunk",
    created: parsed?.created || Math.floor(Date.now() / 1000),
    model: parsed?.model || "",
    choices: [{ index: 0, delta: {}, finish_reason: choice?.finish_reason || "stop" }],
    usage: parsed?.usage,
  })}`);
  lines.push("data: [DONE]");
  return lines;
}
