import type { AgentTool } from "@pie/agent-core";
import {
	describeToolPolicyDecision,
	getToolCapabilityMetadata,
	type RuntimeToolPolicyMode,
	type ToolCapabilityMetadata,
} from "./tool-policy.js";

const POLICY_ENFORCED = Symbol.for("pie.capabilityPolicy.enforced");
type PolicyEnforcedTool = AgentTool & { [POLICY_ENFORCED]?: true };

export type ToolPermissionDisposition = "allow" | "deny" | "confirm";

export interface ToolPermissionDecision {
	disposition: ToolPermissionDisposition;
	allowed: boolean;
	reason?: string;
	riskClass?: ToolCapabilityMetadata["riskClass"];
	permissionScope?: ToolCapabilityMetadata["permissionScope"];
	requiresPermission?: boolean;
	policyReason?: string;
	mode: RuntimeToolPolicyMode;
	yoloMode?: boolean;
}

export interface CapabilityPolicyContext {
	mode?: RuntimeToolPolicyMode;
	yoloMode?: boolean;
	confirmationPolicy?: "allow" | "confirm" | "deny";
}

export interface ToolPermissionRequest {
	toolName: string;
	args: unknown;
	decision: ToolPermissionDecision;
}

export interface ToolPermissionProvider {
	confirm(request: ToolPermissionRequest): Promise<boolean>;
}

export function evaluateToolPermission(tool: AgentTool, context: CapabilityPolicyContext = {}): ToolPermissionDecision {
	const mode = context.mode ?? "normal";
	const metadata = getToolCapabilityMetadata(tool);
	const base = describeToolPolicyDecision(tool, mode);
	if (!metadata && mode === "normal") {
		return {
			disposition: "allow",
			allowed: true,
			reason: "unclassified_tool",
			policyReason: "unclassified_tool",
			mode,
			yoloMode: context.yoloMode,
		};
	}
	if (!metadata || !base.allowed) {
		return {
			disposition: "deny",
			allowed: false,
			reason: base.reason ?? "tool not allowed by runtime policy",
			policyReason: base.reason ?? "tool not allowed by runtime policy",
			mode,
			yoloMode: context.yoloMode,
			riskClass: metadata?.riskClass,
			permissionScope: metadata?.permissionScope,
			requiresPermission: metadata?.requiresPermission,
		};
	}

	const requiresConfirmation = Boolean(metadata.highRisk || metadata.requiresPermission);
	if (!requiresConfirmation || context.yoloMode || context.confirmationPolicy === "allow") {
		return {
			disposition: "allow",
			allowed: true,
			mode,
			yoloMode: context.yoloMode,
			riskClass: metadata.riskClass,
			permissionScope: metadata.permissionScope,
			requiresPermission: requiresConfirmation,
		};
	}

	if (context.confirmationPolicy === "deny" || mode === "subagent") {
		const reason = mode === "subagent"
			? "subagent cannot request interactive permission"
			: "permission confirmation is unavailable";
		return {
			disposition: "deny",
			allowed: false,
			reason,
			policyReason: reason,
			mode,
			yoloMode: context.yoloMode,
			riskClass: metadata.riskClass,
			permissionScope: metadata.permissionScope,
			requiresPermission: true,
		};
	}

	return {
		disposition: "confirm",
		allowed: false,
		reason: "permission confirmation required",
		policyReason: "permission confirmation required",
		mode,
		yoloMode: context.yoloMode,
		riskClass: metadata.riskClass,
		permissionScope: metadata.permissionScope,
		requiresPermission: true,
	};
}

function blockedResult(toolName: string, decision: ToolPermissionDecision) {
	return {
		content: [
			{
				type: "text" as const,
				text: `Blocked ${toolName}: ${decision.reason ?? decision.policyReason ?? "permission denied"}`,
			},
		],
		details: { permissionDecision: decision },
		isError: true,
	};
}

function mergePermissionDetails(details: unknown, decision: ToolPermissionDecision): unknown {
	if (details && typeof details === "object" && !Array.isArray(details)) {
		const record = details as Record<string, unknown>;
		if (record.permissionDecision) {
			return { ...record, capabilityPolicyDecision: decision };
		}
		return { ...record, permissionDecision: decision };
	}
	return { permissionDecision: decision };
}

export function createPolicyEnforcedTool<T extends AgentTool>(
	tool: T,
	options: {
		getContext?: () => CapabilityPolicyContext;
		permissionProvider?: ToolPermissionProvider;
	} = {},
): T {
	if ((tool as PolicyEnforcedTool)[POLICY_ENFORCED]) return tool;
	const wrapped = {
		...tool,
		execute: async (toolCallId: string, args: unknown, signal?: AbortSignal, onUpdate?: (update: unknown) => void) => {
			let decision = evaluateToolPermission(tool, options.getContext?.());
			if (decision.disposition === "confirm") {
				const approved = await options.permissionProvider
					?.confirm({ toolName: tool.name, args, decision })
					.catch(() => false);
				if (!approved) {
					return blockedResult(tool.name, {
						...decision,
						disposition: "deny",
						reason: "permission denied by user",
						policyReason: "permission denied by user",
					});
				}
				decision = {
					...decision,
					disposition: "allow",
					allowed: true,
					reason: undefined,
					policyReason: undefined,
				};
			}
			if (!decision.allowed) return blockedResult(tool.name, decision);
			const result = await tool.execute(toolCallId, args, signal, onUpdate);
			return {
				...result,
				details: mergePermissionDetails(result.details, decision),
			};
		},
	} as T & PolicyEnforcedTool;
	wrapped[POLICY_ENFORCED] = true;
	return wrapped as T;
}

export function createPolicyEnforcedTools<T extends readonly AgentTool[]>(
	tools: T,
	options: {
		getContext?: () => CapabilityPolicyContext;
		permissionProvider?: ToolPermissionProvider;
	} = {},
): AgentTool[] {
	return tools.map((tool) => createPolicyEnforcedTool(tool, options));
}

export function formatCapabilityPolicySummary(tools: readonly AgentTool[], context: CapabilityPolicyContext = {}): string {
	const lines = [
		"Pie permissions and safety model",
		"",
		`Mode: ${context.mode ?? "normal"}${context.yoloMode ? " (YOLO)" : ""}`,
		"",
	];
	for (const tool of tools) {
		const decision = evaluateToolPermission(tool, context);
		lines.push(
			`- ${tool.name}: ${decision.disposition}${decision.permissionScope ? `, scope=${decision.permissionScope}` : ""}${decision.riskClass ? `, risk=${decision.riskClass}` : ""}${decision.reason ? `, reason=${decision.reason}` : ""}`,
		);
	}
	return lines.join("\n");
}
