import type { AgentTool } from "@pie/agent-core";
import {
  ManageTodoListParamsSchema,
  buildExecutionReminder,
  createExecutionStateFromTodos,
  createTodoStore,
  executeManageTodoList,
  type ExecutionState,
  type ManageTodoListParams,
  type TodoItem,
} from "@pie/shared-headless-capabilities";
import { Value } from "@sinclair/typebox/value";

const TOOL_DESCRIPTION = `Manage a session-local todo list. Use when the user explicitly asks to use the todo tool, create/manage todos, track tasks, follow a todo list, show tasks, or mark a task done.
NEVER use for: internal planning, tracking your own progress, remembering subtasks, or creating checklists for yourself.
Use action=create with items to create a list; provide todo titles and optional descriptions only. The tool assigns ids and starts item 1 automatically.
Use action=complete_current after finishing the current item; the tool advances to the next item or clears the list after the final item.
When a todo list exists, keep executing from the current in-progress item until it is cleared. If the work cannot continue, explain the failure and use action=clear with a reason.
Actions: create, read, complete_current, clear.`;

export function createManageTodoListTool() {
  const store = createTodoStore();
  let executionState: ExecutionState | null = null;

  const tool: AgentTool = {
    name: "manage_todo_list",
    label: "manage_todo_list",
    description: TOOL_DESCRIPTION,
    parameters: ManageTodoListParamsSchema,
    execute: async (_toolCallId, args: unknown) => {
      if (!Value.Check(ManageTodoListParamsSchema, args)) {
        const firstError = Array.from(Value.Errors(ManageTodoListParamsSchema, args))[0];
        const path = firstError?.path || "/";
        const message = firstError ? `Invalid todo arguments at ${path}: ${firstError.message}` : "Invalid todo arguments.";
        return {
          content: [{ type: "text" as const, text: `Todo action failed: ${message}` }],
          details: { action: "read" as const, todos: store.read(), error: message },
          isError: true,
        };
      }

      const execution = executeManageTodoList(args as ManageTodoListParams, store.read());
      store.restore(execution.nextTodos);
      executionState = createExecutionStateFromTodos(execution.nextTodos, "todo", "user_todo");
      return execution.result;
    },
  };

  return {
    tool,
    getState() {
      return store.read();
    },
    getExecutionState() {
      return executionState;
    },
    getReminder() {
      return executionState ? buildExecutionReminder(executionState) : null;
    },
    restore(state: TodoItem[] | undefined) {
      store.restore(state);
      executionState = createExecutionStateFromTodos(store.read(), "todo", "user_todo");
    },
    reset() {
      store.clear();
      executionState = null;
    },
  };
}
