import type { AgentTool } from "@pie/agent-core";
import { Type } from "@sinclair/typebox";

interface UnitySceneObject { name: string }
interface UnityScene {
  name: string;
  path: string;
  IsValid(): boolean;
  GetRootGameObjects(): UnitySceneObject[];
}
declare const CS: {
  System: {
    IO: {
      Path: { Combine(...parts: string[]): string };
      File: { Exists(path: string): boolean; ReadAllText(path: string): string };
    };
  };
  UnityEngine: {
    Rendering: { GraphicsSettings: { renderPipelineAsset?: { GetType(): { FullName: string } } | null } };
    QualitySettings: {
      renderPipeline?: { GetType(): { FullName: string } } | null;
      activeColorSpace: unknown;
    };
    SceneManagement: { SceneManager: { GetActiveScene(): UnityScene } };
    Application: { productName: string; unityVersion: string };
  };
  UnityEditor?: { Selection?: { activeGameObject?: { name: string } | null } };
};

export interface UnityContextSnapshot {
  projectRoot: string;
  isEditor: boolean;
  sceneName: string;
  scenePath: string;
  selectedObject: string;
  colorSpace: string;
  productName: string;
  unityVersion: string;
  agentsPath: string;
  hasAgentsFile: boolean;
  renderPipeline: string;
  renderPipelineAssetType: string;
  packageHints: string[];
  rootObjectCount: number;
  rootObjects: string[];
}

function getRenderPipelineInfo() {
  const graphicsSettings = CS.UnityEngine.Rendering.GraphicsSettings;
  const qualitySettings = CS.UnityEngine.QualitySettings;

  const globalAsset = graphicsSettings.renderPipelineAsset;
  const qualityAsset = qualitySettings.renderPipeline;
  const activeAsset = qualityAsset || globalAsset;

  const assetName = activeAsset ? activeAsset.GetType().FullName : "";
  let pipeline = "Built-in Render Pipeline";

  if (assetName.indexOf("Universal") >= 0) {
    pipeline = "Universal Render Pipeline";
  } else if (assetName.indexOf("HDRender") >= 0 || assetName.indexOf("HighDefinition") >= 0) {
    pipeline = "High Definition Render Pipeline";
  }

  return {
    pipeline,
    assetType: assetName || "None",
    hasRenderPipelineAsset: !!activeAsset,
  };
}

function detectPackageHints(projectRoot: string): string[] {
  const manifestPath = CS.System.IO.Path.Combine(projectRoot, "Packages", "manifest.json");
  if (!CS.System.IO.File.Exists(manifestPath)) return [];

  try {
    const content = String(CS.System.IO.File.ReadAllText(manifestPath));
    const hints: string[] = [];
    if (content.indexOf("com.unity.render-pipelines.universal") >= 0) hints.push("URP package");
    if (content.indexOf("com.unity.render-pipelines.high-definition") >= 0) hints.push("HDRP package");
    if (content.indexOf("com.unity.render-pipelines.core") >= 0) hints.push("SRP core package");
    return hints;
  } catch {
    return [];
  }
}

export function getUnityContextSnapshot(projectRoot: string, isEditor: boolean): UnityContextSnapshot {
  const pipelineInfo = getRenderPipelineInfo();
  const sceneManager = CS.UnityEngine.SceneManagement.SceneManager;
  const activeScene = sceneManager.GetActiveScene();
  const selection = isEditor && CS.UnityEditor && CS.UnityEditor.Selection
    ? CS.UnityEditor.Selection.activeGameObject
    : null;
  const agentsPath = CS.System.IO.Path.Combine(projectRoot, "AGENTS.md");
  const roots = activeScene && activeScene.IsValid() ? activeScene.GetRootGameObjects() : [];
  const rootObjects: string[] = [];
  for (let i = 0; i < roots.length; i++) {
    rootObjects.push(String(roots[i].name));
  }

  return {
    projectRoot,
    isEditor,
    sceneName: activeScene ? activeScene.name : "",
    scenePath: activeScene ? activeScene.path : "",
    selectedObject: selection ? selection.name : "",
    colorSpace: String(CS.UnityEngine.QualitySettings.activeColorSpace),
    productName: CS.UnityEngine.Application.productName,
    unityVersion: CS.UnityEngine.Application.unityVersion,
    agentsPath,
    hasAgentsFile: CS.System.IO.File.Exists(agentsPath),
    renderPipeline: pipelineInfo.pipeline,
    renderPipelineAssetType: pipelineInfo.assetType,
    packageHints: detectPackageHints(projectRoot),
    rootObjectCount: rootObjects.length,
    rootObjects: rootObjects.slice(0, 12),
  };
}

export function createInspectUnityContextTool(projectRoot: string, isEditor: boolean): AgentTool {
  return {
    name: "unity_project_inspect",
    label: "unity_project_inspect",
    description: "Inspect the current Unity environment, including render pipeline, scene, selection, and AGENTS.md status.",
    parameters: Type.Object({}),
    execute: async () => {
      const payload = getUnityContextSnapshot(projectRoot, isEditor);

      return {
        content: [{ type: "text" as const, text: JSON.stringify(payload, null, 2) }],
        details: payload,
      };
    },
  };
}
