/**
 * Headless controller that binds Agent runtime lifecycle to SessionManager.
 *
 * This stays UI-free so hosts can reuse the same persistence and queue semantics
 * while keeping prompt building, tool assembly, and rendering in product layers.
 */

import type {
	Agent,
	AgentEvent,
	AgentMessage,
	AgentTool,
	HostSemanticEvent,
} from "@pie/agent-core";
import type { UserContentBlock } from "@pie/ai";
import type { SessionManager } from "./manager.js";
import type { SessionMetadata } from "./types.js";

export type AgentSessionStreamingBehavior = "steer" | "followUp";
export type AgentSessionCompactionReason = "threshold" | "overflow";
export type AgentSessionPromptInput = string | AgentMessage | AgentMessage[] | UserContentBlock[];
export type AgentSessionQueuedInputVisibility = "user" | "internal";

export interface AgentSessionPromptOptions {
	streamingBehavior?: AgentSessionStreamingBehavior;
	source?: string;
	displayText?: string;
	dedupeKey?: string;
	clearEditor?: boolean;
	visibility?: AgentSessionQueuedInputVisibility;
}

export interface AgentSessionCompactionContext {
	reason: AgentSessionCompactionReason;
	willRetry: boolean;
	agent: Agent;
	sessionManager: SessionManager;
	messages: AgentMessage[];
	cwd: string;
}

export interface AgentSessionCompactionResult {
	summary?: string;
	firstKeptEntryId?: string;
	tokensBefore?: number;
	messages?: AgentMessage[];
	aborted?: boolean;
}

export interface AgentSessionCompactionHandler {
	compact: (context: AgentSessionCompactionContext) => Promise<AgentSessionCompactionResult | undefined>;
}

export interface AgentSessionPrepareTurnContext {
	source?: string;
	streamingBehavior?: AgentSessionStreamingBehavior;
	messages: AgentMessage[];
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	baseSystemPrompt?: string;
}

export interface AgentSessionPrepareTurnResult {
	handled?: boolean;
	messages?: AgentMessage[];
	systemPrompt?: string;
}

export interface AgentSessionQueuedInput {
	id: string;
	mode: AgentSessionStreamingBehavior;
	source?: string;
	displayText: string;
	dedupeKey?: string;
	clearEditor: boolean;
	visibility: AgentSessionQueuedInputVisibility;
	deliveredToAgent: boolean;
	messages: AgentMessage[];
	createdAt: number;
}

export interface AgentSessionAgentEndContext {
	messages: AgentMessage[];
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	hasQueuedMessages: boolean;
}

export interface AgentSessionQueuedTurnContext {
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	queuedInput: AgentSessionQueuedInput;
}

export interface AgentSessionDispatchDecision {
	allowed: boolean;
	reason?: string;
	retryAfterMs?: number;
}

export interface AgentSessionAutoCompactContext {
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	message?: AgentMessage;
	messages: AgentMessage[];
}

export interface AgentSessionAutoCompactDecision {
	reason: AgentSessionCompactionReason;
	willRetry: boolean;
}

export interface AgentSessionAutoContinueContext {
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	messages: AgentMessage[];
	hasQueuedMessages: boolean;
}

export interface AgentSessionAutoContinueResult {
	message?: AgentMessage;
	reason?: string;
}

export interface AgentSessionRetryPolicy {
	isRetryableError: (errorMessage: string) => boolean;
	maxRetries?: number;
	baseDelayMs?: number;
	setTimeout?: (callback: () => void, delayMs: number) => unknown;
	clearTimeout?: (handle: unknown) => void;
}

export interface AgentSessionRuntimeContext {
	systemPrompt?: string;
	tools?: AgentTool<any>[];
}

export type AgentSessionControllerEvent =
	| { type: "agent_event"; event: AgentEvent }
	| { type: "semantic_event"; event: HostSemanticEvent }
	| { type: "session_synced"; addedMessages: AgentMessage[]; totalMessages: number }
	| { type: "prepare_turn"; source?: string; messageCount: number }
	| { type: "agent_end_hook_start"; hasQueuedMessages: boolean }
	| { type: "agent_end_hook_end"; errorMessage?: string }
	| { type: "streaming_changed"; isStreaming: boolean }
	| { type: "queue_changed"; queuedInputs: AgentSessionQueuedInput[] }
	| { type: "queued_turn_dispatched"; queuedInput: AgentSessionQueuedInput }
	| { type: "queued_turn_blocked"; queuedInput: AgentSessionQueuedInput; reason?: string }
	| { type: "retry_scheduled"; errorMessage: string; attempt: number; maxRetries: number; delayMs: number }
	| { type: "retry_start"; attempt: number; maxRetries: number }
	| { type: "retry_succeeded"; attempts: number }
	| { type: "retry_exhausted"; errorMessage: string; maxRetries: number }
	| { type: "runtime_guard_triggered"; toolName: string; repeatCount: number; reason: string }
	| { type: "auto_continue_scheduled"; reason?: string }
	| { type: "auto_continue_skipped"; reason: string }
	| { type: "auto_compaction_start"; reason: AgentSessionCompactionReason; willRetry: boolean }
	| {
			type: "auto_compaction_end";
			reason: AgentSessionCompactionReason;
			willRetry: boolean;
			result?: AgentSessionCompactionResult;
			errorMessage?: string;
	  };

export interface AgentSessionControllerOptions {
	agent: Agent;
	sessionManager: SessionManager;
	cwd: string;
	compaction?: AgentSessionCompactionHandler;
	baseSystemPrompt?: string;
	prepareTurn?: (context: AgentSessionPrepareTurnContext) => Promise<AgentSessionPrepareTurnResult | void> | AgentSessionPrepareTurnResult | void;
	afterAgentEnd?: (context: AgentSessionAgentEndContext) => Promise<void> | void;
	canDispatchQueuedTurn?: (context: AgentSessionQueuedTurnContext) => Promise<AgentSessionDispatchDecision | boolean | void> | AgentSessionDispatchDecision | boolean | void;
	getAutoCompactDecision?: (context: AgentSessionAutoCompactContext) => AgentSessionAutoCompactDecision | undefined | void;
	getAutoContinueMessage?: (context: AgentSessionAutoContinueContext) => Promise<AgentSessionAutoContinueResult | AgentMessage | undefined | void> | AgentSessionAutoContinueResult | AgentMessage | undefined | void;
	retry?: AgentSessionRetryPolicy;
	onEvent?: (event: AgentSessionControllerEvent) => void;
}

export interface AgentSessionReplaceMessagesOptions {
	updateSession?: boolean;
}

function isAgentMessage(value: unknown): value is AgentMessage {
	return !!value && typeof value === "object" && "role" in value;
}

function isUserContentBlock(value: unknown): value is UserContentBlock {
	if (!value || typeof value !== "object" || !("type" in value)) {
		return false;
	}
	const type = (value as { type?: unknown }).type;
	return type === "text" || type === "image" || type === "audio" || type === "video" || type === "fileRef";
}

function normalizePromptInput(input: string | AgentMessage | AgentMessage[] | UserContentBlock[]): AgentMessage[] {
	if (typeof input === "string") {
		return [{ role: "user", content: input, timestamp: Date.now() }];
	}
	if (Array.isArray(input)) {
		if (input.every(isAgentMessage)) {
			return input;
		}
		if (input.every(isUserContentBlock)) {
			return [{ role: "user", content: input, timestamp: Date.now() }];
		}
		throw new Error("Invalid prompt array: expected user content blocks or agent messages.");
	}
	if (isAgentMessage(input)) {
		return [input];
	}
	throw new Error("Invalid prompt input.");
}

function textFromMessage(message: AgentMessage): string {
	const content = (message as { content?: unknown }).content;
	if (typeof content === "string") {
		return content;
	}
	if (Array.isArray(content)) {
		return content
			.filter((block): block is { type: string; text?: string } => !!block && typeof block === "object" && "type" in block)
			.filter((block) => block.type === "text")
			.map((block) => block.text || "")
			.join("");
	}
	return "";
}

function stableStringify(value: unknown): string {
	if (value === null || typeof value !== "object") {
		return JSON.stringify(value) ?? String(value);
	}
	if (Array.isArray(value)) {
		return `[${value.map(stableStringify).join(",")}]`;
	}
	const record = value as Record<string, unknown>;
	return `{${Object.keys(record).sort().map((key) => `${JSON.stringify(key)}:${stableStringify(record[key])}`).join(",")}}`;
}

function summarizeToolResultForGuard(result: unknown): string {
	if (!result || typeof result !== "object") {
		return String(result ?? "");
	}
	const content = Array.isArray((result as { content?: unknown }).content)
		? (result as { content: unknown[] }).content
		: [];
	const text = content
		.filter((block): block is { type: string; text?: string } => !!block && typeof block === "object" && "type" in block)
		.filter((block) => block.type === "text")
		.map((block) => block.text || "")
		.join("\n")
		.trim();
	return text || stableStringify(result);
}

const RUNAWAY_TOOLCALL_WHITESPACE_DELTA_CHARS = 16_384;
const RUNAWAY_TOOLCALL_WHITESPACE_DELTA_EVENTS = 40;

interface StreamGuardState {
	whitespaceToolCallDeltaChars: number;
	whitespaceToolCallDeltaEvents: number;
}

function cloneQueuedInput(input: AgentSessionQueuedInput): AgentSessionQueuedInput {
	return {
		...input,
		messages: input.messages.slice(),
	};
}

export class AgentSessionController {
	readonly agent: Agent;
	readonly sessionManager: SessionManager;
	readonly cwd: string;

	private compaction?: AgentSessionCompactionHandler;
	private listeners = new Set<(event: AgentSessionControllerEvent) => void>();
	private unsubscribeAgent?: () => void;
	private unsubscribeSemantic?: () => void;
	private queuedInputs: AgentSessionQueuedInput[] = [];
	private lastSyncedMessageCount = 0;
	private disposed = false;
	private baseSystemPrompt?: string;
	private prepareTurn?: AgentSessionControllerOptions["prepareTurn"];
	private afterAgentEnd?: AgentSessionControllerOptions["afterAgentEnd"];
	private canDispatchQueuedTurn?: AgentSessionControllerOptions["canDispatchQueuedTurn"];
	private getAutoCompactDecision?: AgentSessionControllerOptions["getAutoCompactDecision"];
	private getAutoContinueMessage?: AgentSessionControllerOptions["getAutoContinueMessage"];
	private retry?: AgentSessionRetryPolicy;
	private retryAttempt = 0;
	private retryTimer: unknown;
	private dispatchTimer: unknown;
	private autoCompactTimer: unknown;
	private autoContinueTimer: unknown;
	private pendingAutoCompact?: AgentSessionAutoCompactDecision;
	private queueIdCounter = 0;
	private repeatedToolFailures = new Map<string, number>();
	private streamGuard: StreamGuardState = {
		whitespaceToolCallDeltaChars: 0,
		whitespaceToolCallDeltaEvents: 0,
	};
	private runtimeGuardTriggered = false;

	constructor(options: AgentSessionControllerOptions) {
		this.agent = options.agent;
		this.sessionManager = options.sessionManager;
		this.cwd = options.cwd;
		this.compaction = options.compaction;
		this.baseSystemPrompt = options.baseSystemPrompt ?? this.agent.state.systemPrompt;
		this.prepareTurn = options.prepareTurn;
		this.afterAgentEnd = options.afterAgentEnd;
		this.canDispatchQueuedTurn = options.canDispatchQueuedTurn;
		this.getAutoCompactDecision = options.getAutoCompactDecision;
		this.getAutoContinueMessage = options.getAutoContinueMessage;
		this.retry = options.retry;
		if (options.onEvent) {
			this.listeners.add(options.onEvent);
		}

		this.syncFromActiveSession();
		this.unsubscribeAgent = this.agent.subscribe((event) => {
			this.emit({ type: "agent_event", event });
			if (event.type === "agent_start") {
				this.resetRuntimeGuardState();
				this.emit({ type: "streaming_changed", isStreaming: true });
			}
			if (event.type === "message_update") {
				this.recordMessageUpdateForGuard(event);
			}
			if (event.type === "tool_execution_end") {
				this.recordToolExecutionEndForGuard(event);
			}
			if (event.type === "message_end") {
				this.markQueuedMessageDelivered(event.message);
			}
			if (event.type === "turn_end") {
				void this.syncNewAgentMessages();
				void this.handleTurnEndRuntimePolicies(event.message);
			}
			if (event.type === "agent_end") {
				void this.handleAgentEndHook(event.messages);
				this.emit({ type: "streaming_changed", isStreaming: false });
			}
		});
		this.unsubscribeSemantic = this.agent.subscribeSemantic((event) => {
			this.emit({ type: "semantic_event", event });
		});
	}

	get isStreaming(): boolean {
		return this.agent.state.isStreaming;
	}

	get hasQueuedMessages(): boolean {
		return this.queuedInputs.length > 0 || this.agent.hasQueuedMessages();
	}

	get pendingMessageCount(): number {
		return this.queuedInputs.length;
	}

	get queuedInputsSnapshot(): AgentSessionQueuedInput[] {
		return this.queuedInputs.map(cloneQueuedInput);
	}

	get activeSessionMetadata(): Readonly<SessionMetadata> | undefined {
		const metadata = this.sessionManager.getActiveSession()?.metadata;
		return metadata ? { ...metadata } : undefined;
	}

	get syncedMessageCount(): number {
		return this.lastSyncedMessageCount;
	}

	get runtimeContext(): Readonly<AgentSessionRuntimeContext> {
		return {
			systemPrompt: this.agent.state.systemPrompt,
			tools: this.agent.state.tools.slice(),
		};
	}

	getRuntimeSnapshot(): {
		isStreaming: boolean;
		hasQueuedMessages: boolean;
		pendingMessageCount: number;
		queuedInputs: AgentSessionQueuedInput[];
		activeSessionMetadata: Readonly<SessionMetadata> | undefined;
		syncedMessageCount: number;
	} {
		return {
			isStreaming: this.isStreaming,
			hasQueuedMessages: this.hasQueuedMessages,
			pendingMessageCount: this.pendingMessageCount,
			queuedInputs: this.queuedInputsSnapshot,
			activeSessionMetadata: this.activeSessionMetadata,
			syncedMessageCount: this.syncedMessageCount,
		};
	}

	subscribe(listener: (event: AgentSessionControllerEvent) => void): () => void {
		this.listeners.add(listener);
		return () => this.listeners.delete(listener);
	}

	syncFromActiveSession(messages?: AgentMessage[]): void {
		const activeSession = this.sessionManager.getActiveSession();
		this.agent.sessionId = activeSession?.id;
		const sessionMessages = messages ?? this.sessionManager.getMessages();
		const conversationMessages = sessionMessages.filter(
			(message) => message.role === "user" || message.role === "assistant" || message.role === "toolResult",
		);
		this.agent.replaceMessages(conversationMessages);
		this.lastSyncedMessageCount = conversationMessages.length;
		this.clearQueuedInputs();
	}

	markSyncedToAgentState(): void {
		this.lastSyncedMessageCount = this.agent.state.messages.length;
	}

	replaceMessagesAndMarkSynced(
		messages: AgentMessage[],
		options?: AgentSessionReplaceMessagesOptions,
	): void {
		this.agent.replaceMessages(messages);
		if (options?.updateSession) {
			this.sessionManager.updateMessages(messages);
		}
		this.markSyncedToAgentState();
	}

	updateRuntimeContext(context: AgentSessionRuntimeContext): void {
		if (context.systemPrompt !== undefined) {
			this.baseSystemPrompt = context.systemPrompt;
			this.agent.setSystemPrompt(context.systemPrompt);
		}
		if (context.tools !== undefined) {
			this.agent.setTools(context.tools);
		}
	}

	async prompt(
		input: AgentSessionPromptInput,
		options?: AgentSessionPromptOptions,
	): Promise<void> {
		const messages = normalizePromptInput(input);
		if (options?.streamingBehavior) {
			this.enqueueMessages(messages, options.streamingBehavior, options);
			if (!this.isStreaming) {
				this.scheduleQueueDispatch();
			}
			return;
		}
		if (this.isStreaming) {
			throw new Error("Agent is already processing. Specify streamingBehavior ('steer' or 'followUp') to queue the message.");
		}

		const prepared = await this.preparePromptMessages(messages, options);
		if (prepared.handled) {
			return;
		}
		if (prepared.systemPrompt !== undefined) {
			this.agent.setSystemPrompt(prepared.systemPrompt);
		}
		await this.agent.prompt(prepared.messages);
		await this.syncNewAgentMessages();
	}

	async continue(): Promise<void> {
		if (this.isStreaming) {
			throw new Error("Agent is already processing. Wait for completion before continuing.");
		}
		await this.agent.continue();
		await this.syncNewAgentMessages();
	}

	abort(): void {
		this.cancelRetry();
		this.cancelAutoCompactTimerOnly();
		this.cancelDispatchTimerOnly();
		this.cancelAutoContinueTimerOnly();
		this.agent.abort();
	}

	waitForIdle(): Promise<void> {
		return this.agent.waitForIdle();
	}

	async runAutoCompact(
		reason: AgentSessionCompactionReason,
		willRetry = false,
	): Promise<AgentSessionCompactionResult | undefined> {
		if (!this.compaction) {
			throw new Error("No compaction handler configured");
		}

		this.emit({ type: "auto_compaction_start", reason, willRetry });
		try {
			if (reason === "overflow") {
				this.removeTrailingAssistantError();
			}

			const result = await this.compaction.compact({
				reason,
				willRetry,
				agent: this.agent,
				sessionManager: this.sessionManager,
				messages: this.agent.state.messages.slice(),
				cwd: this.cwd,
			});

			if (result?.summary && result.firstKeptEntryId) {
				this.sessionManager.appendCompaction(result.summary, result.firstKeptEntryId, result.tokensBefore);
				this.replaceMessagesAndMarkSynced(this.sessionManager.getMessages());
			} else if (result?.messages) {
				this.replaceMessagesAndMarkSynced(result.messages, { updateSession: true });
			}

			this.markSyncedToAgentState();
			await this.sessionManager.save();

			if (willRetry && !result?.aborted) {
				await this.continue();
			}

			this.emit({ type: "auto_compaction_end", reason, willRetry, result });
			return result;
		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.emit({ type: "auto_compaction_end", reason, willRetry, errorMessage });
			throw error;
		}
	}

	dispose(): void {
		if (this.disposed) return;
		this.disposed = true;
		this.cancelRetry();
		this.cancelAutoCompactTimerOnly();
		this.cancelDispatchTimerOnly();
		this.cancelAutoContinueTimerOnly();
		this.unsubscribeAgent?.();
		this.unsubscribeSemantic?.();
		this.listeners.clear();
		this.queuedInputs = [];
	}

	drainQueuedInputsForEditor(): AgentSessionQueuedInput[] {
		const drained = this.queuedInputs.map(cloneQueuedInput);
		this.queuedInputs = [];
		this.agent.clearAllQueues();
		this.emitQueueChanged();
		return drained;
	}

	replaceQueuedInputText(search: string, replacement: string): void {
		if (!search || this.queuedInputs.length === 0) {
			return;
		}
		let changed = false;
		for (const input of this.queuedInputs) {
			if (input.displayText.includes(search)) {
				input.displayText = input.displayText.split(search).join(replacement);
				changed = true;
			}
			for (const message of input.messages) {
				if (message.role !== "user") {
					continue;
				}
				const content = (message as { content?: unknown }).content;
				if (typeof content === "string" && content.includes(search)) {
					(message as { content: unknown }).content = content.split(search).join(replacement);
					changed = true;
				} else if (Array.isArray(content)) {
					for (const block of content) {
						if (
							block &&
							typeof block === "object" &&
							"type" in block &&
							block.type === "text" &&
							typeof (block as { text?: unknown }).text === "string" &&
							(block as { text: string }).text.includes(search)
						) {
							(block as { text: string }).text = (block as { text: string }).text.split(search).join(replacement);
							changed = true;
						}
					}
				}
			}
		}
		if (changed) {
			this.emitQueueChanged();
		}
	}

	requestQueueDispatch(): void {
		if (this.queuedInputs.length > 0) {
			this.scheduleQueueDispatch();
		}
	}

	private async preparePromptMessages(
		messages: AgentMessage[],
		options?: AgentSessionPromptOptions,
	): Promise<{ handled: boolean; messages: AgentMessage[]; systemPrompt?: string }> {
		if (this.baseSystemPrompt !== undefined) {
			this.agent.setSystemPrompt(this.baseSystemPrompt);
		}
		if (!this.prepareTurn) {
			return { handled: false, messages };
		}

		this.emit({ type: "prepare_turn", source: options?.source, messageCount: messages.length });
		const result = await this.prepareTurn({
			source: options?.source,
			streamingBehavior: options?.streamingBehavior,
			messages,
			agent: this.agent,
			sessionManager: this.sessionManager,
			cwd: this.cwd,
			baseSystemPrompt: this.baseSystemPrompt,
		});

		return {
			handled: result?.handled === true,
			messages: result?.messages ?? messages,
			systemPrompt: result?.systemPrompt,
		};
	}

	private async syncNewAgentMessages(): Promise<void> {
		const activeSession = this.sessionManager.getActiveSession();
		if (!activeSession) {
			this.lastSyncedMessageCount = this.agent.state.messages.length;
			return;
		}

		const currentAgentCount = this.agent.state.messages.length;
		if (currentAgentCount <= this.lastSyncedMessageCount) {
			return;
		}

		const addedMessages = this.agent.state.messages.slice(this.lastSyncedMessageCount);
		for (const message of addedMessages) {
			this.sessionManager.addMessage(message);
		}
		this.lastSyncedMessageCount = currentAgentCount;

		this.emit({ type: "session_synced", addedMessages, totalMessages: currentAgentCount });
		await this.sessionManager.save();
	}

	private enqueueMessages(
		messages: AgentMessage[],
		mode: AgentSessionStreamingBehavior,
		options: AgentSessionPromptOptions,
	): void {
		if (options.dedupeKey && this.queuedInputs.some((input) => input.dedupeKey === options.dedupeKey)) {
			return;
		}
		for (const message of messages) {
			const queuedInput: AgentSessionQueuedInput = {
				id: `queued-${++this.queueIdCounter}`,
				mode,
				source: options.source,
				displayText: options.displayText ?? textFromMessage(message),
				dedupeKey: options.dedupeKey,
				clearEditor: options.clearEditor ?? true,
				visibility: options.visibility ?? "user",
				deliveredToAgent: false,
				messages: [message],
				createdAt: Date.now(),
			};
			this.queuedInputs.push(queuedInput);
			if (this.isStreaming) {
				this.deliverQueuedInputToAgent(queuedInput);
			}
		}
		this.emitQueueChanged();
	}

	private deliverQueuedInputToAgent(queuedInput: AgentSessionQueuedInput): void {
		if (queuedInput.deliveredToAgent) {
			return;
		}
		for (const message of queuedInput.messages) {
			if (queuedInput.mode === "steer") {
				this.agent.steer(message);
			} else {
				this.agent.followUp(message);
			}
		}
		queuedInput.deliveredToAgent = true;
	}

	private markQueuedMessageDelivered(message: AgentMessage): void {
		if (this.queuedInputs.length === 0 || message.role !== "user") {
			return;
		}
		const index = this.queuedInputs.findIndex((queued) => queued.messages.includes(message));
		if (index >= 0) {
			const [delivered] = this.queuedInputs.splice(index, 1);
			if (delivered) {
				this.emit({ type: "queued_turn_dispatched", queuedInput: cloneQueuedInput(delivered) });
			}
			this.emitQueueChanged();
			return;
		}
		const delivered = this.queuedInputs.shift();
		if (delivered) {
			this.emit({ type: "queued_turn_dispatched", queuedInput: cloneQueuedInput(delivered) });
		}
		this.emitQueueChanged();
	}

	private clearQueuedInputs(): void {
		if (this.queuedInputs.length === 0 && !this.agent.hasQueuedMessages()) {
			return;
		}
		this.queuedInputs = [];
		this.agent.clearAllQueues();
		this.emitQueueChanged();
	}

	private removeTrailingAssistantError(): void {
		const messages = this.agent.state.messages;
		const lastMessage = messages[messages.length - 1] as AgentMessage | undefined;
		if (
			lastMessage?.role === "assistant" &&
			(lastMessage.stopReason === "error" || Boolean(lastMessage.errorMessage))
		) {
			const nextMessages = messages.slice(0, -1);
			this.replaceMessagesAndMarkSynced(nextMessages, { updateSession: true });
		}
	}

	private async handleTurnEndRuntimePolicies(message: AgentMessage | undefined): Promise<void> {
		if (this.disposed) {
			return;
		}
		if (this.runtimeGuardTriggered) {
			return;
		}
		const compactDecision = this.getAutoCompactDecision?.({
			agent: this.agent,
			sessionManager: this.sessionManager,
			cwd: this.cwd,
			message,
			messages: this.agent.state.messages.slice(),
		});
		if (compactDecision) {
			this.scheduleAutoCompact(compactDecision);
			return;
		}
		await this.handleTurnEndForRetry(message);
	}

	private async handleTurnEndForRetry(message: AgentMessage | undefined): Promise<void> {
		if (!this.retry || !message || message.role !== "assistant") {
			return;
		}
		const errorMessage = message.stopReason === "error" ? message.errorMessage : undefined;
		if (!errorMessage) {
			if (this.retryAttempt > 0) {
				this.emit({ type: "retry_succeeded", attempts: this.retryAttempt });
				this.retryAttempt = 0;
			}
			return;
		}
		if (!this.retry.isRetryableError(errorMessage)) {
			return;
		}

		const maxRetries = this.retry.maxRetries ?? 3;
		this.retryAttempt += 1;
		if (this.retryAttempt > maxRetries) {
			this.emit({ type: "retry_exhausted", errorMessage, maxRetries });
			this.retryAttempt = 0;
			return;
		}

		const attempt = this.retryAttempt;
		const delayMs = (this.retry.baseDelayMs ?? 2000) * 2 ** (attempt - 1);
		this.emit({ type: "retry_scheduled", errorMessage, attempt, maxRetries, delayMs });
		this.cancelRetryTimerOnly();
		const setTimer = this.retry.setTimeout ?? ((callback: () => void, delay: number) => setTimeout(callback, delay));
		this.retryTimer = setTimer(() => {
			this.retryTimer = undefined;
			this.emit({ type: "retry_start", attempt, maxRetries });
			this.removeTrailingAssistantError();
			void this.continue().catch(() => {});
		}, delayMs);
	}

	private async handleAgentEndHook(messages: AgentMessage[]): Promise<void> {
		if (this.disposed) {
			return;
		}
		if (this.runtimeGuardTriggered) {
			return;
		}
		if (this.afterAgentEnd) {
			this.emit({ type: "agent_end_hook_start", hasQueuedMessages: this.hasQueuedMessages });
			try {
				await this.afterAgentEnd({
					messages,
					agent: this.agent,
					sessionManager: this.sessionManager,
					cwd: this.cwd,
					hasQueuedMessages: this.hasQueuedMessages,
				});
				this.emit({ type: "agent_end_hook_end" });
			} catch (error) {
				this.emit({
					type: "agent_end_hook_end",
					errorMessage: error instanceof Error ? error.message : String(error),
				});
			}
		}
		if (this.queuedInputs.length > 0) {
			this.scheduleQueueDispatch();
		}
		this.scheduleAutoContinueCheck(messages);
	}

	private cancelRetryTimerOnly(): void {
		if (this.retryTimer === undefined) {
			return;
		}
		const clearTimer = this.retry?.clearTimeout ?? ((handle: unknown) => clearTimeout(handle as ReturnType<typeof setTimeout>));
		clearTimer(this.retryTimer);
		this.retryTimer = undefined;
	}

	private cancelRetry(): void {
		this.cancelRetryTimerOnly();
		this.retryAttempt = 0;
	}

	private scheduleQueueDispatch(delayMs = 0): void {
		if (this.disposed || this.runtimeGuardTriggered || this.dispatchTimer !== undefined) {
			return;
		}
		const setTimer = this.retry?.setTimeout ?? ((callback: () => void, delay: number) => setTimeout(callback, delay));
		this.dispatchTimer = setTimer(() => {
			this.dispatchTimer = undefined;
			void this.dispatchNextQueuedInput();
		}, delayMs);
	}

	private async dispatchNextQueuedInput(): Promise<boolean> {
		if (this.disposed || this.isStreaming || this.retryTimer !== undefined || this.autoCompactTimer !== undefined) {
			return false;
		}
		const queuedInput = this.queuedInputs[0];
		if (!queuedInput) {
			return false;
		}

		const decision = await this.canDispatchQueuedTurn?.({
			agent: this.agent,
			sessionManager: this.sessionManager,
			cwd: this.cwd,
			queuedInput: cloneQueuedInput(queuedInput),
		});
		const dispatchDecision = typeof decision === "boolean"
			? { allowed: decision }
			: decision ?? { allowed: true };
		if (!dispatchDecision.allowed) {
			this.emit({ type: "queued_turn_blocked", queuedInput: cloneQueuedInput(queuedInput), reason: dispatchDecision.reason });
			if (dispatchDecision.retryAfterMs !== undefined && dispatchDecision.retryAfterMs >= 0) {
				this.scheduleQueueDispatch(dispatchDecision.retryAfterMs);
			}
			return false;
		}

		this.queuedInputs.shift();
		this.emitQueueChanged();
		this.emit({ type: "queued_turn_dispatched", queuedInput: cloneQueuedInput(queuedInput) });

		if (queuedInput.deliveredToAgent || this.agent.state.messages.at(-1)?.role === "assistant") {
			if (!queuedInput.deliveredToAgent) {
				this.deliverQueuedInputToAgent(queuedInput);
			}
			await this.continue();
		} else {
			const prepared = await this.preparePromptMessages(queuedInput.messages, {
				source: queuedInput.source,
				streamingBehavior: queuedInput.mode,
				displayText: queuedInput.displayText,
				dedupeKey: queuedInput.dedupeKey,
				clearEditor: queuedInput.clearEditor,
				visibility: queuedInput.visibility,
			});
			if (!prepared.handled) {
				if (prepared.systemPrompt !== undefined) {
					this.agent.setSystemPrompt(prepared.systemPrompt);
				}
				await this.agent.prompt(prepared.messages);
				await this.syncNewAgentMessages();
			}
		}
		return true;
	}

	private scheduleAutoContinueCheck(messages: AgentMessage[]): void {
		if (!this.getAutoContinueMessage || this.disposed || this.autoContinueTimer !== undefined) {
			return;
		}
		const setTimer = this.retry?.setTimeout ?? ((callback: () => void, delay: number) => setTimeout(callback, delay));
		const snapshot = messages.slice();
		this.autoContinueTimer = setTimer(() => {
			this.autoContinueTimer = undefined;
			void this.maybeScheduleAutoContinue(snapshot);
		}, 0);
	}

	private async maybeScheduleAutoContinue(messages: AgentMessage[]): Promise<void> {
		if (!this.getAutoContinueMessage || this.disposed || this.runtimeGuardTriggered || this.hasQueuedMessages || this.isStreaming) {
			if (this.hasQueuedMessages) {
				this.emit({ type: "auto_continue_skipped", reason: "queued_messages" });
			}
			return;
		}
		const lastMessage = messages[messages.length - 1];
		if (lastMessage?.role === "assistant" && (lastMessage.stopReason === "error" || lastMessage.stopReason === "aborted")) {
			this.emit({ type: "auto_continue_skipped", reason: "last_turn_failed" });
			return;
		}
		const result = await this.getAutoContinueMessage({
			agent: this.agent,
			sessionManager: this.sessionManager,
			cwd: this.cwd,
			messages,
			hasQueuedMessages: this.hasQueuedMessages,
		});
		const message = result && "role" in result ? result : result?.message;
		const reason = result && "role" in result ? undefined : result?.reason;
		if (!message) {
			this.emit({ type: "auto_continue_skipped", reason: reason ?? "no_message" });
			return;
		}
		if (this.hasQueuedMessages || this.isStreaming) {
			this.emit({ type: "auto_continue_skipped", reason: "runtime_busy" });
			return;
		}
		this.emit({ type: "auto_continue_scheduled", reason });
		this.agent.followUp(message);
		const setTimer = this.retry?.setTimeout ?? ((callback: () => void, delay: number) => setTimeout(callback, delay));
		this.autoContinueTimer = setTimer(() => {
			this.autoContinueTimer = undefined;
			if (this.disposed) {
				return;
			}
			void this.continue().catch(() => {});
		}, 0);
	}

	private scheduleAutoCompact(decision: AgentSessionAutoCompactDecision, delayMs = 0): void {
		if (this.runtimeGuardTriggered) {
			return;
		}
		this.pendingAutoCompact = decision;
		if (this.autoCompactTimer !== undefined) {
			return;
		}
		const setTimer = this.retry?.setTimeout ?? ((callback: () => void, delay: number) => setTimeout(callback, delay));
		this.autoCompactTimer = setTimer(() => {
			this.autoCompactTimer = undefined;
			const pending = this.pendingAutoCompact;
			this.pendingAutoCompact = undefined;
			if (!pending || this.disposed) {
				return;
			}
			if (this.isStreaming) {
				this.pendingAutoCompact = pending;
				this.scheduleAutoCompact(pending, 100);
				return;
			}
			void this.runAutoCompact(pending.reason, pending.willRetry);
		}, delayMs);
	}

	private cancelDispatchTimerOnly(): void {
		if (this.dispatchTimer === undefined) {
			return;
		}
		const clearTimer = this.retry?.clearTimeout ?? ((handle: unknown) => clearTimeout(handle as ReturnType<typeof setTimeout>));
		clearTimer(this.dispatchTimer);
		this.dispatchTimer = undefined;
	}

	private cancelAutoCompactTimerOnly(): void {
		if (this.autoCompactTimer === undefined) {
			return;
		}
		const clearTimer = this.retry?.clearTimeout ?? ((handle: unknown) => clearTimeout(handle as ReturnType<typeof setTimeout>));
		clearTimer(this.autoCompactTimer);
		this.autoCompactTimer = undefined;
		this.pendingAutoCompact = undefined;
	}

	private cancelAutoContinueTimerOnly(): void {
		if (this.autoContinueTimer === undefined) {
			return;
		}
		const clearTimer = this.retry?.clearTimeout ?? ((handle: unknown) => clearTimeout(handle as ReturnType<typeof setTimeout>));
		clearTimer(this.autoContinueTimer);
		this.autoContinueTimer = undefined;
	}

	private emitQueueChanged(): void {
		this.emit({ type: "queue_changed", queuedInputs: this.queuedInputsSnapshot });
	}

	private resetRuntimeGuardState(): void {
		this.repeatedToolFailures.clear();
		this.streamGuard = {
			whitespaceToolCallDeltaChars: 0,
			whitespaceToolCallDeltaEvents: 0,
		};
		this.runtimeGuardTriggered = false;
	}

	private triggerRuntimeGuard(toolName: string, repeatCount: number, reason: string): void {
		if (this.runtimeGuardTriggered) {
			return;
		}
		this.runtimeGuardTriggered = true;
		this.cancelRetry();
		this.cancelAutoCompactTimerOnly();
		this.cancelDispatchTimerOnly();
		this.cancelAutoContinueTimerOnly();
		this.emit({ type: "runtime_guard_triggered", toolName, repeatCount, reason });
		this.agent.abort();
	}

	private recordMessageUpdateForGuard(event: Extract<AgentEvent, { type: "message_update" }>): void {
		if (this.runtimeGuardTriggered) {
			return;
		}
		const assistantEvent = event.assistantMessageEvent;
		if (assistantEvent.type !== "toolcall_delta") {
			this.streamGuard.whitespaceToolCallDeltaChars = 0;
			this.streamGuard.whitespaceToolCallDeltaEvents = 0;
			return;
		}
		if (assistantEvent.delta.trim().length > 0) {
			this.streamGuard.whitespaceToolCallDeltaChars = 0;
			this.streamGuard.whitespaceToolCallDeltaEvents = 0;
			return;
		}
		this.streamGuard.whitespaceToolCallDeltaChars += assistantEvent.delta.length;
		this.streamGuard.whitespaceToolCallDeltaEvents += 1;
		const content = event.message.role === "assistant" && Array.isArray(event.message.content)
			? event.message.content[assistantEvent.contentIndex] as { partialArgs?: unknown } | undefined
			: undefined;
		const partialArgs = typeof content?.partialArgs === "string" ? content.partialArgs : "";
		const sparsePartialArgs = partialArgs.length >= RUNAWAY_TOOLCALL_WHITESPACE_DELTA_CHARS
			&& partialArgs.replace(/\s/g, "").length / partialArgs.length < 0.05;
		if (
			sparsePartialArgs ||
			(
				this.streamGuard.whitespaceToolCallDeltaChars >= RUNAWAY_TOOLCALL_WHITESPACE_DELTA_CHARS &&
				this.streamGuard.whitespaceToolCallDeltaEvents >= RUNAWAY_TOOLCALL_WHITESPACE_DELTA_EVENTS
			)
		) {
			this.triggerRuntimeGuard(
				"assistant_stream",
				this.streamGuard.whitespaceToolCallDeltaEvents,
				"runaway_tool_call_arguments",
			);
		}
	}

	private recordToolExecutionEndForGuard(event: Extract<AgentEvent, { type: "tool_execution_end" }>): void {
		if (!event.isError) {
			const prefix = `${event.toolName}:`;
			for (const key of this.repeatedToolFailures.keys()) {
				if (key.startsWith(prefix)) {
					this.repeatedToolFailures.delete(key);
				}
			}
			return;
		}
		const resultSummary = summarizeToolResultForGuard(event.result).slice(0, 500);
		const key = `${event.toolName}:${stableStringify(event.args)}:${resultSummary}`;
		const repeatCount = (this.repeatedToolFailures.get(key) ?? 0) + 1;
		this.repeatedToolFailures.set(key, repeatCount);
		if (repeatCount < 3 || this.runtimeGuardTriggered) {
			return;
		}
		this.triggerRuntimeGuard(event.toolName, repeatCount, "repeated_tool_error");
	}

	private emit(event: AgentSessionControllerEvent): void {
		for (const listener of this.listeners) {
			listener(event);
		}
	}
}

export function createAgentSessionController(options: AgentSessionControllerOptions): AgentSessionController {
	return new AgentSessionController(options);
}
