/**
 * Session store implementations (v2 - tree structure)
 */

import { FileSystemGateway, getPlatformConfig, detectPlatform } from "@pie/platform";
import type { SessionStore, SessionData, SessionMetadata, SessionEntry } from "./types.js";
import type { AgentMessage } from "@pie/agent-core";
import { flattenTreeToMessages, generateEntryId } from "./types.js";
import {
	deleteDurableFile,
	durableFileExists,
	loadDurableFile,
	writeDurableFile,
	type DurableFileParsed,
} from "./durable-file.js";

/** Current data version */
const SESSION_VERSION = 2;

function isSessionEntry(value: unknown): value is SessionEntry {
	return !!value && typeof value === "object" && "id" in value && "type" in value;
}

function normalizeEntriesInput(entriesOrMessages: SessionEntry[] | AgentMessage[]): SessionEntry[] {
	if (entriesOrMessages.every(isSessionEntry)) {
		return entriesOrMessages;
	}

	const entries: SessionEntry[] = [];
	let parentId: string | null = null;
	for (const message of entriesOrMessages as AgentMessage[]) {
		const entry: SessionEntry = {
			id: generateEntryId(),
			parentId,
			type: "message",
			timestamp: Date.now(),
			message,
		};
		entries.push(entry);
		parentId = entry.id;
	}
	return entries;
}

/** Legacy version */
const LEGACY_VERSION = 1;

/**
 * Get the default sessions directory path
 * Uses platform-specific path from PlatformConfig
 */
export function getDefaultSessionsDir(): string {
	return getPlatformConfig().sessionsPath;
}

/**
 * Migrate v1 (linear messages) to v2 (tree entries)
 */
function migrateV1ToV2(data: SessionData): SessionData {
	console.log(`[SessionStore] Migrating session ${data.metadata.id} from v1 to v2`);

	const messages = data.messages ?? [];
	const entries: SessionEntry[] = [];

	// Convert linear messages to tree entries
	let parentId: string | null = null;
	for (const message of messages) {
		const entry: SessionEntry = {
			id: generateEntryId(),
			parentId,
			type: "message",
			timestamp: Date.now(),
			message,
		};
		entries.push(entry);
		parentId = entry.id;
	}

	// Get the last entry as active
	const activeEntryId = entries.length > 0 ? entries[entries.length - 1].id : null;
	const rootEntryId = entries.length > 0 ? entries[0].id : null;

	return {
		version: SESSION_VERSION,
		metadata: {
			...data.metadata,
			entryCount: entries.length,
			messageCount: messages.length,
			activeEntryId,
			rootEntryId,
		},
		entries,
		messages, // Keep for backward compatibility
	};
}

/**
 * File-based session store (v2 - tree structure)
 */
export class FileSessionStore implements SessionStore {
	private sessionsDir: string;
	private gateway: FileSystemGateway;

	constructor(sessionsDir?: string) {
		this.sessionsDir = sessionsDir || getDefaultSessionsDir();
		this.gateway = new FileSystemGateway({
			allowedRoots: [this.sessionsDir, getPlatformConfig().dataPath],
		});
		this.ensureDirectory();
	}

	/**
	 * Ensure the sessions directory exists
	 */
	private ensureDirectory(): void {
		try {
			if (!this.gateway.exists(this.sessionsDir)) {
				this.gateway.mkdir(this.sessionsDir, { recursive: true });
			}
		} catch (e) {
			console.warn(`[FileSessionStore] Could not create sessions directory: ${e}`);
		}
	}

	/**
	 * Get the full path for a session file
	 */
	private getSessionPath(sessionId: string): string {
		// Sanitize session ID for filesystem
		const safeId = sessionId.replace(/[^a-zA-Z0-9_-]/g, "_");
		return this.gateway.join(this.sessionsDir, `${safeId}.json`);
	}

	private normalizeLoadedData(data: SessionData): { data: SessionData; shouldPersist: boolean } {
		if (data.version === LEGACY_VERSION || !data.version) {
			return { data: migrateV1ToV2(data), shouldPersist: true };
		}

		if (data.version !== SESSION_VERSION) {
			console.warn(
				`[SessionStore] Session version mismatch: ${data.version} vs ${SESSION_VERSION}`,
			);
		}

		if (!data.entries) {
			data.entries = [];
		}

		return { data, shouldPersist: false };
	}

	private parseSessionContent(content: string, filePath: string): DurableFileParsed<SessionData> {
		if (!content || content.trim().length === 0) {
			throw new Error("empty session file");
		}
		const parsed = JSON.parse(content) as SessionData;
		const normalized = this.normalizeLoadedData(parsed);
		const persistedContent = normalized.shouldPersist ? JSON.stringify(normalized.data, null, 2) : content;
		return {
			data: normalized.data,
			content: persistedContent,
			updatedAt: normalized.data.metadata?.updatedAt ?? 0,
		};
	}

	/**
	 * Save a session to disk (v2 format)
	 */
	async save(
		sessionId: string,
		entries: SessionEntry[] | AgentMessage[],
		metadata?: Partial<SessionMetadata>,
	): Promise<void> {
		const normalizedEntries = normalizeEntriesInput(entries);
		const now = Date.now();
		const existing = await this.load(sessionId);

		// Count messages
		const messageCount = normalizedEntries.filter((e) => e.type === "message" && e.message).length;

		// Find root and active entry
		const rootEntry = normalizedEntries.find((e) => e.parentId === null);
		const activeEntryId =
			metadata?.activeEntryId ??
			existing?.metadata.activeEntryId ??
			normalizedEntries[normalizedEntries.length - 1]?.id ??
			null;

		const sessionData: SessionData = {
			version: SESSION_VERSION,
			metadata: {
				id: sessionId,
				name:
					metadata?.name ??
					existing?.metadata.name ??
					`Session ${sessionId.slice(0, 8)}`,
				createdAt: existing?.metadata.createdAt ?? now,
				updatedAt: now,
				entryCount: normalizedEntries.length,
				messageCount,
				activeEntryId: activeEntryId ?? rootEntry?.id ?? null,
				rootEntryId: rootEntry?.id ?? null,
				tags: metadata?.tags ?? existing?.metadata.tags,
				...metadata,
			},
			entries: normalizedEntries,
			messages: flattenTreeToMessages(normalizedEntries, activeEntryId ?? null),
		};

		const json = JSON.stringify(sessionData, null, 2);
		const filePath = this.getSessionPath(sessionId);

		await writeDurableFile({
			gateway: this.gateway,
			filePath,
			parse: (content, path) => this.parseSessionContent(content, path),
		}, json);
	}

	/**
	 * Legacy save method for backward compatibility
	 * @deprecated Use save() with entries instead
	 */
	async saveLegacy(
		sessionId: string,
		messages: AgentMessage[],
		metadata?: Partial<SessionMetadata>,
	): Promise<void> {
		console.warn("[FileSessionStore] Using deprecated saveLegacy() - consider migrating to v2");

		// Convert messages to entries
		const entries: SessionEntry[] = [];
		let parentId: string | null = null;
		for (const message of messages) {
			const entry: SessionEntry = {
				id: generateEntryId(),
				parentId,
				type: "message",
				timestamp: Date.now(),
				message,
			};
			entries.push(entry);
			parentId = entry.id;
		}

		await this.save(sessionId, entries, metadata);
	}

	/**
	 * Load a session from disk
	 */
	async load(sessionId: string): Promise<SessionData | null> {
		const filePath = this.getSessionPath(sessionId);

		try {
			const loaded = await loadDurableFile({
				gateway: this.gateway,
				filePath,
				parse: (content, path) => this.parseSessionContent(content, path),
			});
			if (!loaded) {
				return null;
			}
			if (loaded.restoredMain || loaded.refreshedBackup) {
				console.warn(
					`[SessionStore] Repaired session ${sessionId} from ${loaded.source}` +
					(loaded.repairError ? ` with repair warning: ${loaded.repairError}` : ""),
				);
			} else if (loaded.repairError) {
				console.warn(`[SessionStore] Loaded session ${sessionId} but sidecar refresh failed: ${loaded.repairError}`);
			}
			return loaded.data;
		} catch (e) {
			console.error(`[SessionStore] Failed to load session: ${sessionId}`, e);
			return null;
		}
	}

	/**
	 * Delete a session
	 */
	async delete(sessionId: string): Promise<boolean> {
		const filePath = this.getSessionPath(sessionId);
		try {
			return deleteDurableFile(this.gateway, filePath);
		} catch (e) {
			console.error(`[SessionStore] Failed to delete session: ${sessionId}`, e);
			return false;
		}
	}

	/**
	 * Check if a session exists
	 */
	async exists(sessionId: string): Promise<boolean> {
		const filePath = this.getSessionPath(sessionId);
		return durableFileExists(this.gateway, filePath);
	}

	/**
	 * List all session IDs
	 */
	async list(): Promise<string[]> {
		if (!this.gateway.exists(this.sessionsDir)) {
			return [];
		}

		const files = this.gateway.readdir(this.sessionsDir);
		const sessionIds = new Set<string>();
		for (const file of files) {
			if (file.endsWith("-files.json") || file.endsWith("-files.json.bak") || file.endsWith("-files.json.prev")) {
				continue;
			}
			if (file.endsWith(".json")) {
				sessionIds.add(file.replace(/\.json$/i, ""));
			} else if (file.endsWith(".json.bak")) {
				sessionIds.add(file.replace(/\.json\.bak$/i, ""));
			} else if (file.endsWith(".json.prev")) {
				sessionIds.add(file.replace(/\.json\.prev$/i, ""));
			}
		}
		return [...sessionIds];
	}

	/**
	 * List all session metadata
	 */
	async listMetadata(): Promise<SessionMetadata[]> {
		const sessionIds = await this.list();
		const metadata: SessionMetadata[] = [];

		for (const id of sessionIds) {
			const meta = await this.getMetadata(id);
			if (meta) {
				metadata.push(meta);
			}
		}

		// Sort by updatedAt descending (most recent first)
		return metadata.sort((a, b) => b.updatedAt - a.updatedAt);
	}

	/**
	 * Get session metadata without loading full entries
	 */
	async getMetadata(sessionId: string): Promise<SessionMetadata | null> {
		const data = await this.load(sessionId);
		return data?.metadata ?? null;
	}
}

/**
 * In-memory session store for testing
 */
export class MemorySessionStore implements SessionStore {
	private sessions = new Map<string, SessionData>();

	async save(
		sessionId: string,
		entries: SessionEntry[] | AgentMessage[],
		metadata?: Partial<SessionMetadata>,
	): Promise<void> {
		const normalizedEntries = normalizeEntriesInput(entries);
		const now = Date.now();
		const existing = this.sessions.get(sessionId);

		// Count messages
		const messageCount = normalizedEntries.filter((e) => e.type === "message" && e.message).length;

		// Find root and active entry
		const rootEntry = normalizedEntries.find((e) => e.parentId === null);
		const activeEntryId =
			metadata?.activeEntryId ??
			existing?.metadata.activeEntryId ??
			normalizedEntries[normalizedEntries.length - 1]?.id ??
			null;

		// Strip ephemeral API fields before persisting
		const sessionData: SessionData = {
			version: SESSION_VERSION,
			metadata: {
				id: sessionId,
				name:
					metadata?.name ??
					existing?.metadata.name ??
					`Session ${sessionId.slice(0, 8)}`,
				createdAt: existing?.metadata.createdAt ?? now,
				updatedAt: now,
				entryCount: normalizedEntries.length,
				messageCount,
				activeEntryId: activeEntryId ?? rootEntry?.id ?? null,
				rootEntryId: rootEntry?.id ?? null,
				tags: metadata?.tags ?? existing?.metadata.tags,
				...metadata,
			},
			entries: normalizedEntries,
			messages: flattenTreeToMessages(normalizedEntries, activeEntryId ?? null),
		};

		this.sessions.set(sessionId, sessionData);
	}

	async saveLegacy(
		sessionId: string,
		messages: AgentMessage[],
		metadata?: Partial<SessionMetadata>,
	): Promise<void> {
		// Convert messages to entries
		const entries: SessionEntry[] = [];
		let parentId: string | null = null;
		for (const message of messages) {
			const entry: SessionEntry = {
				id: generateEntryId(),
				parentId,
				type: "message",
				timestamp: Date.now(),
				message,
			};
			entries.push(entry);
			parentId = entry.id;
		}
		await this.save(sessionId, entries, metadata);
	}

	async load(sessionId: string): Promise<SessionData | null> {
		return this.sessions.get(sessionId) ?? null;
	}

	async delete(sessionId: string): Promise<boolean> {
		return this.sessions.delete(sessionId);
	}

	async exists(sessionId: string): Promise<boolean> {
		return this.sessions.has(sessionId);
	}

	async list(): Promise<string[]> {
		return Array.from(this.sessions.keys());
	}

	async listMetadata(): Promise<SessionMetadata[]> {
		return Array.from(this.sessions.values())
			.map((s) => s.metadata)
			.sort((a, b) => b.updatedAt - a.updatedAt);
	}

	async getMetadata(sessionId: string): Promise<SessionMetadata | null> {
		return this.sessions.get(sessionId)?.metadata ?? null;
	}
}

/**
 * Create a file-based session store
 */
export function createFileSessionStore(sessionsDir?: string): SessionStore {
	return new FileSessionStore(sessionsDir);
}

/**
 * Create a memory-based session store (for testing)
 */
export function createMemorySessionStore(): SessionStore {
	return new MemorySessionStore();
}

/**
 * Create the appropriate session store for the current platform
 */
export function createSessionStore(sessionsDir?: string): SessionStore {
	const platform = detectPlatform();

	if (platform === "node") {
		return new FileSessionStore(sessionsDir);
	} else {
		// In PuerTS, we can still use FileSessionStore if we have file system access
		// But MemorySessionStore is safer for WebGL builds
		try {
			return new FileSessionStore(sessionsDir);
		} catch {
			console.warn("[createSessionStore] Falling back to MemorySessionStore");
			return new MemorySessionStore();
		}
	}
}
