/**
 * API key resolution from environment
 */

export function getProviderEnvVar(provider: string): string {
	return `${provider.toUpperCase().replace(/[^A-Z0-9]+/gi, "_")}_API_KEY`;
}

/**
 * Get API key for a provider from environment variables
 */
export function getEnvApiKey(provider: string, explicitEnvVar?: string): string | undefined {
	void provider;
	// Guard: process may not be available in V8-only environments (e.g. PuerTS)
	const env: Record<string, string | undefined> =
		typeof process !== "undefined" ? process.env : {};

	// Strict mode: only explicit model/profile env mappings are honored.
	const explicitEnv = explicitEnvVar;
	if (explicitEnv) {
		const value = env[explicitEnv];
		if (value) return value;
	}

	return undefined;
}
